window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["nicet-water-based"] = window.COURSE_LANG["nicet-water-based"] || {};
window.COURSE_LANG["nicet-water-based"]["es"] = [
  {id:1, q:"En los planos de taller de rociadores contra incendios, ¿qué representa típicamente un círculo con el deflector mostrado apuntando hacia abajo?", opts:["Un rociador montante (upright)","Un rociador colgante (pendent)","Un interruptor de flujo","Una válvula de retención"], re:"Un rociador colgante descarga hacia abajo y cuelga por debajo del ramal, por lo que su símbolo muestra el deflector orientado hacia abajo. Ref.: símbolos de protección contra incendios NFPA 170; definiciones de orientación de rociadores NFPA 13."},
  {id:2, q:"¿Qué norma establece los símbolos gráficos normalizados utilizados en los planos de seguridad y protección contra incendios en los Estados Unidos?", opts:["NFPA 25","NFPA 170","NFPA 72","NFPA 20"], re:"NFPA 170, Norma para símbolos de seguridad humana y emergencias, define los símbolos normalizados utilizados en los planos de protección contra incendios. Ref.: NFPA 170."},
  {id:3, q:"Un rociador montante (upright) se instala de modo que el agua se rocía:", opts:["Hacia abajo desde debajo del ramal","Hacia arriba y es desviada de nuevo hacia abajo por el deflector","Solo horizontalmente","Directamente contra una pared"], re:"Un rociador montante se sitúa por encima del ramal; el agua sale hacia arriba y el deflector la redirige hacia abajo y hacia afuera en un patrón hemisférico. Ref.: NFPA 13, definiciones de tipos de rociador."},
  {id:4, q:"En un plano de rociadores, la abreviatura 'FDC' marca ¿qué componente?", opts:["Conexión del cuerpo de bomberos (fire department connection)","Acoplamiento flexible de bajada","Registro de limpieza del desagüe de piso","Controlador fijo de diluvio"], re:"FDC significa fire department connection (conexión del cuerpo de bomberos), la entrada exterior por la que los bomberos bombean agua al sistema. Ref.: NFPA 13; abreviaturas NFPA 170."},
  {id:5, q:"Se selecciona un rociador de pared (sidewall) en un plano principalmente cuando:", opts:["El techo tiene más de 30 ft de altura","El montaje en el techo es poco práctico y el rociador debe proyectar agua desde una pared","El área es un congelador","Solo se dispone de cabezas montantes"], re:"Los rociadores de pared se montan en una pared y proyectan agua a través de una sala; se usan donde la tubería en el techo es poco práctica, como salas pequeñas y pasillos. Ref.: NFPA 13, uso de rociador de pared."},
  {id:6, q:"En los planos de taller, una línea cruzada por una pequeña marca perpendicular con un círculo denota comúnmente:", opts:["Un cambio de diámetro de tubería","Una válvula de control","Únicamente una cabeza de rociador","Una penetración de pared"], re:"Los símbolos de válvula se colocan en línea sobre el tramo de tubería en los planos de taller; la leyenda define cada tipo de válvula. Ref.: leyenda de símbolos NFPA 170; leyenda del plano del proyecto."},
  {id:7, q:"Todo juego de planos de taller de rociadores debe incluir ¿qué elemento para definir el significado de cada símbolo utilizado?", opts:["Una leyenda de símbolos","Un informe de suelos","Una matriz de alarma contra incendios","Un registro de OSHA"], re:"Una leyenda (lista de símbolos) en los planos identifica qué significa cada símbolo y abreviatura para que revisores e instaladores interpreten el plano de manera coherente. Ref.: requisitos de planos de trabajo NFPA 13."},
  {id:8, q:"Una línea discontinua (oculta) en un plano de rociadores indica más comúnmente:", opts:["Un objeto por encima o por debajo del plano del dibujo / oculto a la vista","Un circuito eléctrico","Una línea de propiedad","Una nota obligatoria"], re:"Las líneas ocultas/discontinuas representan bordes o tuberías no visibles directamente en la vista actual, como elementos por encima del techo o por debajo del piso. Ref.: convención estándar de dibujo; convenciones de línea ASME/arquitectónicas."},
  {id:9, q:"En un plano, 'ITC' o 'prueba del inspector' identifica la conexión utilizada para:", opts:["Rellenar el sistema con anticongelante","Simular el flujo de un rociador para probar la alarma de flujo de agua","Conectar la red municipal","Ventilar automáticamente el aire atrapado"], re:"La conexión de prueba del inspector tiene un orificio que coincide con un rociador y se usa para verificar el funcionamiento de la alarma de flujo de agua. Ref.: NFPA 13; pruebas NFPA 25."},
  {id:10, q:"Un rociador oculto (concealed) se muestra en los planos con una anotación que indica que está:", opts:["Instalado por encima del techo y oculto por una placa de cubierta","Siempre con un orificio extra grande","Solo para uso exterior","Pintado de rojo"], re:"Los rociadores ocultos se sitúan empotrados por encima de la línea del techo detrás de una placa de cubierta a ras que se desprende en un incendio. Ref.: NFPA 13, definición de rociador oculto."},
  {id:11, q:"En los planos de rociadores, el término 'columna ascendente' (riser) se refiere a:", opts:["La tubería de suministro vertical con sus válvulas asociadas que sirve al sistema","Un arriostramiento diagonal","El ramal más cercano a la pared","El desagüe del techo"], re:"La columna ascendente es la tubería vertical (con válvula de control, manómetros, dispositivo de alarma y desagüe principal) que suministra al sistema desde la fuente. Ref.: NFPA 13, definición de columna ascendente del sistema."},
  {id:12, q:"Se coloca una flecha de norte en un plano de planta de rociadores principalmente para:", opts:["Indicar la densidad de diseño del sistema","Establecer la orientación del dibujo respecto al edificio","Mostrar la dirección de la pendiente de la tubería","Marcar la ubicación de la FDC"], re:"La flecha de norte orienta el plano para que el lector pueda relacionar el dibujo con el edificio real y con otras hojas. Ref.: convención estándar de dibujo/planos de trabajo."},
  {id:13, q:"En un plano, los diámetros de tubería se indican más comúnmente mediante:", opts:["Solo color","Una llamada numérica junto a la tubería (p. ej., 2\")","Únicamente el grosor de la línea","Una flecha de norte"], re:"Los diámetros de tubería se rotulan con llamadas numéricas a lo largo de cada tramo para que el instalador conozca el tamaño de cada segmento. Ref.: planos de trabajo NFPA 13; convenciones de dibujo."},
  {id:14, q:"El símbolo de una válvula de retención (check valve) en un plano de rociadores representa un dispositivo que:", opts:["Permite el flujo en una sola dirección","Reduce la presión","Mide la temperatura","Desagua el sistema"], re:"Una válvula de retención permite que el agua fluya en una dirección y evita el flujo inverso, protegiendo el suministro de la contaminación. Ref.: requisitos de válvulas NFPA 13; NFPA 170."},
  {id:15, q:"En los planos hidráulicos, una pequeña banderita o número de nodo de referencia en un accesorio se usa para:", opts:["Identificar un punto de referencia de cálculo a lo largo de la trayectoria del flujo","Marcar la clasificación de temperatura de un rociador","Indicar el color de pintura","Mostrar el límite de la propiedad"], re:"Los puntos de referencia hidráulica (nodos) se numeran para que cada unión pueda vincularse a la hoja de cálculo hidráulico. Ref.: procedimientos de cálculo hidráulico NFPA 13."},
  {id:16, q:"Un 'sprig' (montante corto) mostrado en un plano o detalle de columna es:", opts:["Una tubería vertical corta que sube hasta un rociador montante por encima de una tubería principal","Una tubería principal transversal horizontal","Un tipo de soporte","Un accesorio de desagüe"], re:"Un sprig-up es un niple de tubería corto que sube desde un ramal para alimentar un rociador montante situado por encima. Ref.: NFPA 13, definición de sprig."},
  {id:17, q:"Cuando un plano de rociadores muestra el símbolo de un 'interruptor de manipulación' (tamper switch) en una válvula, este monitorea:", opts:["La temperatura del agua","Si la válvula está abierta o cerrada (supervisión)","El espesor de la pared de la tubería","La concentración de anticongelante"], re:"Un interruptor de manipulación (supervisión) de válvula señala si una válvula de control se mueve de su posición normal abierta. Ref.: NFPA 13; señalización de supervisión NFPA 72."},
  {id:18, q:"Una vista en planta de un edificio se describe mejor como una vista:", opts:["Que mira directamente hacia abajo desde arriba sobre un corte horizontal","Que mira horizontalmente una cara exterior","Cortada verticalmente a través del edificio","Desde un ángulo de 45 grados"], re:"Un plano es una vista de corte horizontal vista desde arriba, que muestra la disposición de muros, salas y tuberías en un nivel. Ref.: convenciones de dibujo arquitectónico."},
  {id:19, q:"Una vista de alzado muestra:", opts:["Una disposición vista desde arriba","Una vista plana de una cara vertical del edificio","Un corte que atraviesa el interior","Un esquema sin escala"], re:"Un alzado es una vista frontal de un lado vertical (fachada o superficie interior), dibujada a escala. Ref.: convenciones de dibujo arquitectónico."},
  {id:20, q:"Una vista de sección se crea:", opts:["Mirando hacia abajo desde el techo","Cortando a través del edificio en un plano vertical y observando el corte","Fotografiando el exterior","Rotando el plano 90 grados"], re:"Un dibujo de sección corta verticalmente la estructura para revelar relaciones interiores como alturas de techo y trazado de tuberías. Ref.: convenciones de dibujo arquitectónico."},
  {id:21, q:"En una escala de arquitecto, '1/8\" = 1'-0\"' significa que cada 1/8 de pulgada en el papel equivale a:", opts:["1 pulgada en el edificio","1 pie en el edificio","8 pies en el edificio","1 yarda en el edificio"], re:"A 1/8\" = 1'-0\", un octavo de pulgada en el dibujo representa un pie de longitud real (una relación 1:96). Ref.: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:22, q:"La escala de arquitecto usa un sistema fraccionario, mientras que la escala de ingeniero usa:", opts:["Un sistema decimal (p. ej., 1\" = 20')","Solo unidades métricas","Ninguna relación definida","Las mismas fracciones que la escala de arquitecto"], re:"Las escalas de ingeniero son decimales (1\" = 10', 20', 30', etc.); las escalas de arquitecto usan fracciones de pulgada por pie. Ref.: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:23, q:"A una escala de 1/4\" = 1'-0\", una pared dibujada de 3 pulgadas de largo en el papel representa una longitud real de:", opts:["3 pies","6 pies","12 pies","48 pies"], re:"A 1/4\" = 1', cada pulgada equivale a 4 pies; 3 pulgadas x 4 ft = 12 pies. Ref.: conversión de escala de arquitecto (USFA/FEMA)."},
  {id:24, q:"¿Por qué un diseñador debe evitar medir dimensiones directamente sobre una hoja impresa cuando se proporciona una dimensión escrita?", opts:["La impresión/reproducción puede distorsionar la escala; las dimensiones escritas prevalecen","Las escalas son ilegales de usar","El papel siempre es exacto","Las dimensiones escritas son solo sugerencias"], re:"La reproducción y el trazado pueden estirar un dibujo, por lo que las dimensiones anotadas (escritas) tienen prioridad sobre las mediciones a escala. Ref.: práctica estándar de dibujo."},
  {id:25, q:"Un plano de techo reflejado (RCP) es más útil para un diseñador de rociadores para:", opts:["Ubicar elementos del techo como placas, luminarias y difusores que afectan la ubicación de las cabezas","Dimensionar la red subterránea","Determinar la capacidad portante del suelo","Seleccionar la bomba contra incendios"], re:"Un RCP muestra el techo como si estuviera reflejado en el piso, ayudando a coordinar las ubicaciones de los rociadores con luminarias, rejillas y difusores. Ref.: práctica de coordinación arquitectónica/MEP."},
  {id:26, q:"En un dibujo, la abreviatura 'AFF' típicamente significa:", opts:["Sobre el piso terminado (above finished floor)","Caudal de incendio aprobado","Accesorio de flujo automático","Formulario anual de incendios"], re:"AFF (above finished floor, sobre el piso terminado) hace referencia a una altura medida hacia arriba desde la superficie del piso terminado, usada para alturas de techo y cabezas. Ref.: abreviaturas estándar de dibujo."},
  {id:27, q:"Se proporciona un dibujo de 'detalle' a mayor escala (p. ej., un detalle de columna) para:", opts:["Ocultar información a la AHJ","Mostrar un área pequeña con mayor tamaño y claridad que el plano general","Reemplazar la hoja de portada","Reducir el número de diámetros de tubería"], re:"Los detalles amplían un ensamblaje específico para que se muestren con claridad las conexiones y componentes que serían demasiado pequeños en el plano principal. Ref.: práctica de dibujo/planos de trabajo."},
  {id:28, q:"En un plano de rociadores, la altura del techo afecta más directamente ¿qué parámetro de diseño?", opts:["El color del borde del dibujo","La distancia del rociador al deflector y las reglas de obstrucción/cobertura","La fuente del cuadro de rótulos","La dirección de la flecha de norte"], re:"La altura y la construcción del techo gobiernan la distancia del deflector por debajo del techo y las reglas de obstrucción que determinan el espaciamiento. Ref.: reglas de obstrucción y distancia NFPA 13."},
  {id:29, q:"Una escala gráfica (de barra) impresa en un dibujo es útil porque:", opts:["Permanece proporcionalmente correcta incluso si la hoja se amplía o reduce","Indica la densidad de diseño","Muestra la línea legal de propiedad","Reemplaza por completo la necesidad de dimensiones"], re:"Una escala de barra/gráfica se escala junto con el dibujo, por lo que permanece exacta tras la reproducción aun cuando la relación numérica no lo haría. Ref.: práctica de dibujo (guía de escalas USFA/FEMA)."},
  {id:30, q:"Cuando una nota del plano dice 'NTS', significa que el detalle está:", opts:["Sin escala (not to scale)","Cerca de la escalera sur","Sistema de tanque nuevo","Norma técnica anotada"], re:"NTS (not to scale, sin escala) indica al lector que la figura es esquemática y no debe medirse para obtener dimensiones. Ref.: abreviaturas estándar de dibujo."},
  {id:31, q:"Para hallar la altura de un techo para la distancia del rociador, un diseñador consulta de manera más fiable:", opts:["Solo la hoja de portada","Las vistas de sección del edificio o de muro","El cuadro de rótulos","La leyenda de símbolos"], re:"Las vistas de sección revelan dimensiones verticales como la altura de piso a techo y de piso a estructura, necesarias para la distancia de las cabezas. Ref.: dibujos de sección arquitectónicos."},
  {id:32, q:"En un plano de sitio (civil), la ubicación de la red subterránea del servicio contra incendios y la FDC se coordinan usando ¿qué tipo de escala?", opts:["Escala de arquitecto (fraccionaria)","Escala de ingeniero (decimal)","Sin escala","Solo métrica"], re:"Los dibujos de sitio/civiles suelen dibujarse en escalas de ingeniero (decimales) como 1\" = 20'. Ref.: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:33, q:"La 'cota del piso terminado' en un dibujo la usa el diseñador de rociadores principalmente para:", opts:["Establecer una cota de referencia para las alturas de tuberías, techos y cabezas","Elegir el color del rociador","Fijar la densidad del sistema","Determinar la clase de mercancía"], re:"La cota del piso proporciona el datum base desde el cual se miden las alturas de techo y de las cabezas para el trazado y la hidráulica. Ref.: práctica de dibujo/coordinación."},
  {id:34, q:"Coordinar el trazado de rociadores con los ductos de HVAC mostrados en los planos es importante porque:", opts:["Los ductos son más anchos de 4 ft y pueden obstruir la descarga del rociador","Los ductos cambian la escala de arquitecto","Los ductos fijan la clase de riesgo","Los ductos nunca se muestran en los planos"], re:"Los ductos anchos (y otras obstrucciones) bloquean el rocío y pueden requerir rociadores debajo de ellos o espaciamiento ajustado según las reglas de obstrucción. Ref.: disposiciones de obstrucción NFPA 13."},
  {id:35, q:"El desagüe principal en la columna de un sistema de rociadores se proporciona para:", opts:["Desaguar el sistema y realizar una prueba de desagüe principal (de flujo)","Suministrar la FDC","Añadir anticongelante","Aumentar la presión"], re:"El desagüe principal vacía la columna y apoya la prueba de desagüe principal que verifica la disponibilidad del suministro de agua. Ref.: NFPA 13; prueba de desagüe principal NFPA 25."},
  {id:36, q:"Un interruptor de alarma de flujo de agua (o válvula de alarma) en un sistema de tubería húmeda funciona para:", opts:["Señalar una alarma cuando el agua fluye debido a un rociador en funcionamiento","Reducir la presión municipal","Filtrar sedimentos","Marcar la línea de propiedad"], re:"La detección de flujo de agua inicia la alarma cuando un rociador se abre y el agua circula por la columna. Ref.: NFPA 13; NFPA 72."},
  {id:37, q:"En el plano de un sistema de tubería seca, la válvula de tubería seca retiene el agua usando:", opts:["Aire o nitrógeno presurizado en la tubería por encima de la válvula","Solo un resorte","Únicamente la gravedad","Un elemento calefactor"], re:"En un sistema seco, el aire/nitrógeno presurizado por encima del clapeta mantiene cerrada la válvula de tubería seca hasta que un rociador se abre y el aire escapa. Ref.: sistemas de tubería seca NFPA 13."},
  {id:38, q:"Una conexión del cuerpo de bomberos (FDC) permite a los bomberos:", opts:["Bombear agua/presión suplementaria al sistema de rociadores","Desaguar el sistema","Cerrar el agua municipal","Probar las clasificaciones de temperatura de los rociadores"], re:"La FDC es una entrada para que las autobombas del cuerpo de bomberos aumenten el caudal y la presión del sistema durante un incendio. Ref.: requisitos de FDC NFPA 13."},
  {id:39, q:"La válvula de control del sistema (p. ej., OS&Y o de mariposa) mostrada en la columna se mantiene normalmente:", opts:["Abierta y supervisada","Cerrada","Medio abierta","Retirada durante la operación"], re:"Las válvulas de control deben estar normalmente abiertas y supervisadas para que el agua esté siempre disponible para el sistema. Ref.: NFPA 13; supervisión de válvulas NFPA 25."},
  {id:40, q:"En los planos, una 'tubería principal transversal' (cross main) es la tubería que:", opts:["Alimenta los ramales","Sostiene los rociadores directamente","Se conecta solo a la FDC","Desagua el sistema"], re:"Las tuberías principales transversales distribuyen el agua a los ramales, que a su vez llevan los rociadores. Ref.: definiciones de tuberías NFPA 13."},
  {id:41, q:"Un 'ramal' (branch line) en un plano de rociadores es la tubería que:", opts:["Suministra directamente a los rociadores","Es la columna vertical","Conecta dos edificios","Lleva solo agua de desagüe"], re:"Los ramales son las tuberías a las que los rociadores se conectan directamente. Ref.: definiciones de tuberías NFPA 13."},
  {id:42, q:"Se muestra una bomba contra incendios en los planos cuando:", opts:["La presión/caudal disponible del suministro de agua es insuficiente para la demanda de diseño","Todo edificio tiene una por ley","El sistema es solo húmedo","Se usa anticongelante"], re:"Una bomba contra incendios aumenta la presión/caudal cuando el suministro no puede satisfacer la demanda hidráulica. Ref.: NFPA 13; bombas contra incendios NFPA 20."},
  {id:43, q:"En un detalle de columna, se instalan manómetros para:", opts:["Fijar la escala de arquitecto","Desaguar la columna","Disparar la válvula de tubería seca","Indicar las presiones del sistema y del suministro para monitoreo y pruebas"], re:"Los manómetros muestran las presiones del suministro y del sistema para que el sistema pueda monitorearse y se evalúen las pruebas de desagüe principal. Ref.: NFPA 13; NFPA 25."},
  {id:44, q:"Un conjunto de prevención de reflujo (backflow) puede mostrarse en el suministro entrante principalmente para:", opts:["Calentar el agua","Aumentar la densidad de rociadores","Reemplazar la FDC","Proteger el suministro de agua potable de la contaminación"], re:"Los preventores de reflujo impiden que el agua del sistema posiblemente contaminada regrese al suministro público. Ref.: NFPA 13; código local de plomería/conexiones cruzadas."},
  {id:45, q:"En un sistema de preacción de doble enclavamiento, el agua entra en la tubería solo cuando:", opts:["Se abre el desagüe principal","Un rociador se abre por sí solo","La detección actúa por sí sola","La detección actúa Y un rociador se abre"], re:"La preacción de doble enclavamiento requiere tanto una señal de detección independiente como un rociador abierto antes de admitir el agua, minimizando la descarga accidental. Ref.: sistemas de preacción NFPA 13."},
  {id:46, q:"Un desagüe auxiliar (drum drip) en un sistema seco se proporciona en:", opts:["La succión de la bomba contra incendios","Solo el punto más alto","La FDC","Los puntos bajos/tramos atrapados para eliminar el condensado"], re:"Los desagües auxiliares de punto bajo (drum drips) recogen y eliminan la condensación que se acumula en la tubería del sistema seco. Ref.: drenaje del sistema seco NFPA 13."},
  {id:47, q:"Una válvula de diluvio en un plano se asocia con:", opts:["Lazos de anticongelante","Solo cabezas colgantes cerradas","Una función de reducción de presión","Rociadores/boquillas abiertos que descargan todos cuando la válvula se dispara"], re:"Los sistemas de diluvio usan boquillas abiertas; cuando la válvula de diluvio se dispara por detección, el agua fluye de todas ellas simultáneamente. Ref.: sistemas de diluvio NFPA 13."},
  {id:48, q:"En los planos, los soportes y el arriostramiento sísmico se muestran para:", opts:["Identificar la clase de mercancía","Aumentar la densidad de agua","Marcar la FDC","Soportar y restringir la tubería"], re:"Los soportes sostienen el peso de la tubería y el arriostramiento restringe el movimiento (incluido el sísmico), según las reglas de suspensión y arriostramiento de NFPA 13. Ref.: NFPA 13, capítulo sobre suspensión/arriostramiento."},
  {id:49, q:"Una 'columna de incendio' (standpipe) mostrada junto a la tubería de rociadores está destinada a:", opts:["Suministrar la red municipal","Reemplazar los rociadores","Desaguar el condensado","Proporcionar conexiones de manguera para combate manual de incendios"], re:"Las columnas de incendio entregan agua a las válvulas de manguera en cada piso para chorros de manguera del cuerpo de bomberos o de los ocupantes (NFPA 14). Ref.: NFPA 14; coordinación con NFPA 13."},
  {id:50, q:"Una válvula reductora de presión (PRV) puede aparecer en la columna de un edificio de gran altura para:", opts:["Proporcionar la FDC","Añadir aire al sistema","Aumentar el caudal por encima del suministro","Limitar la presión excesiva a niveles aceptables para los componentes aguas abajo"], re:"Las PRV reducen la alta presión estática (común en los pisos inferiores de edificios altos) para proteger la tubería y los dispositivos. Ref.: límites de presión NFPA 13 / NFPA 14."},
  {id:51, q:"En el plano, el 'punto de conexión' al suministro de agua es importante porque:", opts:["Selecciona la clase de mercancía","Fija el color del rociador","Determina la escala de arquitecto","Define dónde el sistema se conecta a la fuente usada para los cálculos hidráulicos"], re:"El punto de conexión del suministro establece la base de presión/caudal de la fuente para el diseño hidráulico. Ref.: requisitos de suministro de agua y cálculo hidráulico NFPA 13."},
  {id:52, q:"Según NFPA 13, ¿qué ocupación se clasifica como riesgo leve (Light Hazard)?", opts:["Taller de reparación de automóviles","Sala de lectura de biblioteca","Fabricación de papel","Hangar de aeronaves"], re:"El riesgo leve cubre contenidos de baja cantidad/combustibilidad como oficinas, iglesias y salas de lectura de biblioteca. Ref.: clasificación de ocupación NFPA 13 (riesgo leve)."},
  {id:53, q:"Una panadería o lavandería típicamente se clasifica por NFPA 13 como:", opts:["Riesgo leve","Riesgo ordinario grupo 1","Riesgo extra grupo 1","Riesgo extra grupo 2"], re:"Las panaderías y lavanderías son ejemplos de ocupaciones de riesgo ordinario grupo 1 (cantidad moderada, baja combustibilidad). Ref.: clasificación de ocupación NFPA 13 (OH1)."},
  {id:54, q:"¿Cuál de los siguientes es un ejemplo de ocupación de riesgo ordinario grupo 2?", opts:["Santuario de iglesia","Sala de lectura de biblioteca","Taller mecánico / metalmecánica","Oficina"], re:"El riesgo ordinario grupo 2 incluye talleres mecánicos, comercios y ocupaciones similares de combustibilidad moderada a alta. Ref.: clasificación de ocupación NFPA 13 (OH2)."},
  {id:55, q:"Los hangares de aeronaves y operaciones de alta combustibilidad similares generalmente se clasifican como:", opts:["Riesgo leve","Riesgo ordinario grupo 1","Riesgo extra grupo 1","Riesgo leve con excepciones"], re:"El riesgo extra grupo 1 cubre alta combustibilidad con desarrollo rápido del fuego, como hangares de aeronaves y operaciones de imprenta. Ref.: clasificación de ocupación NFPA 13 (EH1)."},
  {id:56, q:"Una cabina de pintura por aspersión de automóviles (cantidad sustancial de líquidos inflamables) se clasifica mejor como:", opts:["Riesgo leve","Riesgo ordinario grupo 1","Riesgo ordinario grupo 2","Riesgo extra grupo 2"], re:"El riesgo extra grupo 2 cubre ocupaciones con cantidades sustanciales de líquidos inflamables/combustibles, como aplicaciones de pintura por aspersión. Ref.: clasificación de ocupación NFPA 13 (EH2)."},
  {id:57, q:"En NFPA 13, la clasificación de riesgo por ocupación se usa principalmente para determinar:", opts:["El color de la pintura de la pared","La densidad de diseño del suministro de agua y los criterios de área","La escala de arquitecto","El cuadro de rótulos del dibujo"], re:"La clasificación de riesgo fija la densidad de diseño y el área de operación usada para dimensionar el sistema. Ref.: enfoques de diseño por clase de riesgo NFPA 13."},
  {id:58, q:"Una mercancía Clase I según NFPA 13 se describe mejor como:", opts:["Neumáticos de caucho","Plástico de alta liberación de calor","Líquido inflamable en tambores","Producto esencialmente incombustible, puede estar sobre tarimas combustibles / en cajas de cartón"], re:"La Clase I es producto esencialmente incombustible, que admite cajas de cartón corrugado ordinario y tarimas de madera. Ref.: clasificación de mercancía NFPA 13 (Clase I)."},
  {id:59, q:"Los plásticos del Grupo A se diferencian de los plásticos de los Grupos B y C porque tienen:", opts:["El menor calor de combustión","Un calor de combustión y una tasa de combustión mucho mayores que los combustibles ordinarios","Ningún efecto sobre el diseño de rociadores","La misma tasa de combustión que la madera"], re:"Los plásticos del Grupo A tienen el mayor calor de combustión y la tasa de combustión más rápida de los tres grupos, lo que impone los criterios de almacenamiento más exigentes. Ref.: clasificación de plásticos NFPA 13."},
  {id:60, q:"¿Qué material es un ejemplo de plástico del Grupo A?", opts:["Nailon","Poliestireno (p. ej., expandido)","Fenólico","PVC rígido (menos del 5% plastificado)"], re:"El poliestireno (expandido/no expandido), el polietileno, el polipropileno, el ABS y el PET son plásticos del Grupo A. Ref.: clasificación de plásticos NFPA 13 (Grupo A)."},
  {id:61, q:"El nailon y el caucho natural no expandido son ejemplos de ¿qué grupo de plásticos?", opts:["Grupo A","Grupo B","Grupo C","No es un plástico"], re:"Los plásticos del Grupo B incluyen el nailon, los celulósicos y el caucho natural no expandido (entre el Grupo A y el C en severidad). Ref.: clasificación de plásticos NFPA 13 (Grupo B)."},
  {id:62, q:"¿Cuál de los siguientes es un plástico del Grupo C?", opts:["Polietileno","Polipropileno","Fenólico (o PTFE)","ABS"], re:"Los plásticos del Grupo C (p. ej., fenólico, melamina, PTFE, PVC rígido) arden de manera similar a los combustibles ordinarios. Ref.: clasificación de plásticos NFPA 13 (Grupo C)."},
  {id:63, q:"NFPA 13 trata el riesgo de incendio de los plásticos del Grupo C como aproximadamente equivalente a ¿qué clase de mercancía?", opts:["Clase I","Clase II","Clase III","Clase IV"], re:"Los plásticos del Grupo C se consideran equivalentes a las mercancías de Clase III (comportamiento similar al de combustibles ordinarios). Ref.: equivalencia mercancía/plásticos NFPA 13."},
  {id:64, q:"Una mercancía Clase IV contiene:", opts:["Ningún plástico en absoluto","Cantidades apreciables de plásticos del Grupo A (dentro de límites definidos) añadidas a un producto de clase inferior","Solo artículos incombustibles","Líquido inflamable puro"], re:"La Clase IV es un producto que contiene una cantidad apreciable pero limitada de plásticos del Grupo A (p. ej., 5-15% en peso). Ref.: clasificación de mercancía NFPA 13 (Clase IV)."},
  {id:65, q:"La clasificación de mercancía (Clase I-IV, plásticos) es el punto de partida para diseñar la protección en:", opts:["Oficinas de riesgo leve","Ocupaciones de almacenamiento / depósito","Solo plataformas de estacionamiento abiertas","Dormitorios residenciales"], re:"Las ocupaciones de almacenamiento se protegen según la clase de mercancía, la altura de almacenamiento y la disposición, en lugar del riesgo básico por ocupación únicamente. Ref.: protección de almacenamiento NFPA 13."},
  {id:66, q:"Las mercancías de Clase III generalmente se describen como:", opts:["Solo productos incombustibles","Madera, papel, fibras naturales o plásticos del Grupo C (con cantidades limitadas del Grupo A/B)","Plásticos puros del Grupo A","Gases inflamables"], re:"La Clase III es madera, papel, tela de fibra natural o plásticos del Grupo C, con solo una pequeña proporción permitida de plásticos del Grupo A/B. Ref.: clasificación de mercancía NFPA 13 (Clase III)."},
  {id:67, q:"Cuando los contenidos combinan múltiples riesgos en un mismo espacio, el diseñador generalmente protege según:", opts:["El menor riesgo presente","Riesgo leve por defecto","El riesgo más exigente (más alto) presente, o diseña por área","Lo que sea más económico"], re:"Las mercancías/ocupaciones mixtas generalmente se protegen según el riesgo más alto presente, a menos que las áreas estén separadas y diseñadas individualmente. Ref.: guía de mercancía/ocupación mixta NFPA 13."},
  {id:68, q:"El encapsulamiento de una mercancía almacenada (p. ej., envoltura plástica sobre la parte superior) importa porque:", opts:["No tiene efecto sobre el comportamiento del fuego","Reduce la clase de mercancía","Puede atrapar el calor/limitar la penetración del agua, aumentando la demanda de protección","Elimina la necesidad de rociadores"], re:"El encapsulamiento puede proteger la mercancía del agua e intensificar el comportamiento del fuego, requiriendo a menudo una mayor protección. Ref.: almacenamiento NFPA 13 (disposiciones de encapsulamiento)."},
  {id:69, q:"Un sistema de rociadores de tubería húmeda es apropiado donde:", opts:["Las temperaturas pueden caer por debajo del punto de congelación","No se puede tolerar agua accidental en absoluto","El área está climatizada y se mantiene por encima de 40 F (4 C)","Solo se usan boquillas abiertas"], re:"Los sistemas húmedos mantienen agua en la tubería y se usan en áreas climatizadas mantenidas a 40 F (4 C) o más. Ref.: uso de sistema de tubería húmeda NFPA 13."},
  {id:70, q:"Un sistema de tubería seca se selecciona principalmente para:", opts:["Espacio de oficina climatizado","Áreas que necesitan la entrega de agua más rápida posible","Áreas sin calefacción/con congelación, como almacenes fríos o estacionamientos","Lugares sin suministro de agua"], re:"Los sistemas secos usan aire presurizado para mantener el agua fuera de la tubería expuesta a la congelación, comunes en espacios sin calefacción. Ref.: uso de sistema de tubería seca NFPA 13."},
  {id:71, q:"Comparado con un sistema húmedo, un sistema de tubería seca tiene:", opts:["Entrega de agua más rápida a un rociador abierto","Ninguna necesidad de válvula de control","Un retardo porque el aire debe ventilarse antes de que el agua llegue al rociador","Ninguna necesidad de suministro de agua"], re:"Los sistemas secos tienen un retardo inherente porque el aire atrapado debe expulsarse antes de que el agua fluya de una cabeza abierta. Ref.: características del sistema seco NFPA 13."},
  {id:72, q:"Un sistema de preacción de enclavamiento simple admite agua en la tubería cuando:", opts:["Un rociador se funde únicamente","Se abre el desagüe principal","Un sistema de detección separado actúa","Se conecta la FDC"], re:"La preacción de enclavamiento simple llena la tubería al recibir una señal de detección; luego el agua fluye cuando un rociador se abre. Ref.: tipos de sistema de preacción NFPA 13."},
  {id:73, q:"Un sistema de preacción comúnmente se elige para proteger:", opts:["Estacionamientos abiertos","Muelles de carga exteriores","Áreas sensibles al agua como centros de datos o archivos","Solo salas de calderas"], re:"Los sistemas de preacción reducen la probabilidad de descarga accidental de agua, lo que los hace adecuados para espacios sensibles al agua como centros de datos y museos. Ref.: aplicaciones de preacción NFPA 13."},
  {id:74, q:"Un sistema de diluvio es más apropiado para:", opts:["Una oficina típica","Almacenamiento en frío sin riesgo","Áreas de alto riesgo que requieren agua simultánea de todas las cabezas (p. ej., hangares de aeronaves)","Una pequeña unidad residencial"], re:"Los sistemas de diluvio usan cabezas abiertas y aplican agua en todas partes a la vez para incendios de alto riesgo de rápida propagación. Ref.: aplicaciones de diluvio NFPA 13."},
  {id:75, q:"Un sistema de preacción de doble enclavamiento es muy adecuado para:", opts:["Un vestíbulo climatizado","Cocheras abiertas","Almacenes congeladores donde el agua accidental es costosa y la congelación es una preocupación","Una oficina rociada estándar"], re:"La preacción de doble enclavamiento impide la entrada de agua a menos que la detección y un rociador actúen, ideal para congeladores. Ref.: preacción de doble enclavamiento NFPA 13."},
  {id:76, q:"¿Por debajo de aproximadamente qué temperatura NFPA 13 generalmente aleja a los diseñadores de los sistemas húmedos hacia los secos o de preacción?", opts:["120 F (49 C)","70 F (21 C)","90 F (32 C)","40 F (4 C)"], re:"Donde las temperaturas pueden caer por debajo de 40 F (4 C), un sistema húmedo corre riesgo de congelación, por lo que se usa un sistema seco/de preacción o protección contra congelación. Ref.: umbral de protección contra congelación NFPA 13."},
  {id:77, q:"Los rociadores abiertos (sin elemento sensible al calor) se usan en ¿qué sistema?", opts:["Tubería húmeda","Tubería seca","Diluvio","Preacción de enclavamiento simple"], re:"Los sistemas de diluvio usan rociadores/boquillas abiertos para que todos descarguen a la vez cuando la válvula de diluvio se dispara. Ref.: definición de sistema de diluvio NFPA 13."},
  {id:78, q:"¿Qué sistema mantiene la tubería seca hasta que la detección actúa Y está destinado a limitar la descarga accidental de agua?", opts:["Tubería húmeda","Diluvio convencional","Preacción","Lazo de anticongelante"], re:"Los sistemas de preacción mantienen la tubería seca hasta que la detección (y, para los tipos de enclavamiento, un rociador) actúa, limitando la descarga involuntaria. Ref.: sistemas de preacción NFPA 13."},
  {id:79, q:"Un sistema de rociadores con anticongelante es una variación típicamente usada para:", opts:["Aumentar la presión","Reemplazar la bomba contra incendios","Proteger pequeñas áreas sin calefacción de un sistema por lo demás húmedo sin una válvula seca separada","Eliminar la columna ascendente"], re:"Los lazos de anticongelante protegen porciones limitadas sin calefacción llenando esa sección con una solución anticongelante aprobada. Ref.: disposiciones de sistema con anticongelante NFPA 13."},
  {id:80, q:"Para un edificio de oficinas climatizado típico, el tipo de sistema más común y económico es:", opts:["Diluvio","Preacción de doble enclavamiento","Tubería húmeda","Tubería seca"], re:"Los sistemas de tubería húmeda son los más comunes y simples para ocupaciones climatizadas, ofreciendo la respuesta más rápida. Ref.: NFPA 13; práctica común de diseño."},
  {id:81, q:"Una desventaja clave de los sistemas de tubería seca en comparación con los húmedos es:", opts:["No pueden usarse en almacenes","No requieren mantenimiento","Mayor complejidad, potencial de corrosión y entrega de agua retardada","No pueden detectar el fuego"], re:"Los sistemas secos añaden equipo de suministro de aire, son propensos a corrosión/condensación interna y retardan la entrega de agua. Ref.: consideraciones de sistema seco NFPA 13."},
  {id:82, q:"Al seleccionar un tipo de sistema, la PRIMERA consideración que el diseñador evalúa suele ser:", opts:["El color de la tubería","La marca del rociador","El entorno/riesgo del edificio (p. ej., congelación, sensibilidad al agua, nivel de riesgo)","La fuente del cuadro de rótulos"], re:"El tipo de sistema se deriva del entorno y el riesgo: climatizado vs con congelación, contenidos sensibles al agua y severidad del riesgo. Ref.: justificación de selección de sistema NFPA 13."},
  {id:83, q:"Un sistema combinado de tubería seca-preacción podría especificarse para:", opts:["Una oficina pequeña","Un dormitorio residencial","Tubería muy larga en áreas frías que necesita los beneficios de ambos enfoques","Un estacionamiento abierto"], re:"Las disposiciones combinadas de tubería seca-preacción atienden sistemas grandes/largos en frío donde se desean tanto la protección contra congelación como la supervisión. Ref.: disposiciones de sistema combinado NFPA 13."},
  {id:84, q:"Para un almacén de congelación donde cualquier agua en la tubería inactiva causa daños por hielo, la opción preferida es:", opts:["Tubería húmeda","Preacción de enclavamiento simple","Preacción de doble enclavamiento","Lazo de anticongelante en todo el sistema"], re:"La preacción de doble enclavamiento mantiene la tubería seca hasta que la detección y la activación del rociador ocurren, lo mejor para congeladores. Ref.: uso de preacción de doble enclavamiento NFPA 13."},
  {id:85, q:"NFPA 13 es la norma para la:", opts:["Instalación de bombas contra incendios","Inspección, prueba y mantenimiento de sistemas a base de agua","Instalación de sistemas de alarma contra incendios","Instalación de sistemas de rociadores"], re:"NFPA 13 es la Norma para la Instalación de Sistemas de Rociadores. Ref.: NFPA 13 (título/alcance)."},
  {id:86, q:"¿Qué documento define la Autoridad Competente (AHJ)?", opts:["Solo el propietario del edificio","El contratista general","El fabricante de rociadores","NFPA, como la oficina/individuo responsable de hacer cumplir un código o aprobar equipos"], re:"NFPA define la AHJ como la organización, oficina o individuo responsable de hacer cumplir un código/norma o de aprobar equipos e instalaciones. Ref.: definiciones NFPA (AHJ)."},
  {id:87, q:"¿Cómo se vuelve NFPA 13 legalmente exigible en una jurisdicción?", opts:["Es automáticamente ley en todas partes","Los fabricantes votan sobre ella","Se adopta por referencia a través de un código de construcción/incendios u ordenanza local","Solo aplica si se imprime en color"], re:"NFPA 13 adquiere fuerza de ley cuando se adopta por referencia en un código de construcción o de incendios aplicable o en una ordenanza. Ref.: proceso de adopción de códigos; NFPA."},
  {id:88, q:"¿Qué norma referencia más comúnmente a NFPA 13 para exigir la instalación de rociadores en los edificios?", opts:["NFPA 25","NFPA 170","El Código Internacional de Construcción (IBC) / Código Internacional de Incendios (IFC)","NFPA 20"], re:"Los códigos modelo como el IBC y el IFC referencian a NFPA 13 para la instalación de sistemas de rociadores requeridos. Ref.: normas referenciadas IBC/IFC."},
  {id:89, q:"NFPA 25 cubre la:", opts:["Instalación de nuevos sistemas de rociadores","Diseño de sistemas de alarma contra incendios","Inspección, prueba y mantenimiento de sistemas de protección contra incendios a base de agua","Fabricación de tuberías"], re:"NFPA 25 es la Norma para la Inspección, Prueba y Mantenimiento de Sistemas de Protección contra Incendios a Base de Agua. Ref.: NFPA 25 (título/alcance)."},
  {id:90, q:"NFPA 20 es la norma para la:", opts:["Sistemas de columna de incendio y manguera","Símbolos en los dibujos","Mantenimiento de rociadores","Instalación de bombas estacionarias contra incendios para protección contra incendios"], re:"NFPA 20 es la Norma para la Instalación de Bombas Estacionarias para Protección contra Incendios. Ref.: NFPA 20 (título/alcance)."},
  {id:91, q:"NFPA 14 es la norma para:", opts:["Instalación de rociadores","ITM a base de agua","Sistemas de alarma contra incendios","Sistemas de columna de incendio y manguera"], re:"NFPA 14 es la Norma para la Instalación de Sistemas de Columna de Incendio y Manguera. Ref.: NFPA 14 (título/alcance)."},
  {id:92, q:"Cuando la AHJ y NFPA 13 difieren, en una jurisdicción que la adopta el diseñador generalmente debe:", opts:["Ignorar a la AHJ","Elegir la que sea más económica","Usar solo el catálogo del fabricante","Cumplir con los requisitos exigibles del código/AHJ, que pueden ser más estrictos"], re:"El código adoptado y la aplicación de la AHJ gobiernan; las enmiendas locales pueden ser más restrictivas que la norma base. Ref.: adopción de códigos/autoridad de la AHJ."},
  {id:93, q:"NFPA 13R está destinada a sistemas de rociadores en:", opts:["Almacenes de alto riesgo","Refinerías","Hangares de aeronaves","Ocupaciones residenciales de baja altura de hasta cuatro pisos (según se define)"], re:"NFPA 13R aborda ocupaciones residenciales de hasta cuatro pisos inclusive dentro de su alcance. Ref.: NFPA 13R (alcance)."},
  {id:94, q:"NFPA 13D aplica a sistemas de rociadores en:", opts:["Oficinas de gran altura","Hospitales","Almacenes de depósito","Viviendas unifamiliares y bifamiliares y casas prefabricadas"], re:"NFPA 13D es la norma para sistemas de rociadores en viviendas unifamiliares y bifamiliares y casas prefabricadas. Ref.: NFPA 13D (alcance)."},
  {id:95, q:"Los planos de trabajo (de taller) se presentan a la AHJ principalmente para:", opts:["Fijar la escala de arquitecto","Vender el edificio","Reemplazar los cálculos hidráulicos","Obtener revisión y aprobación/permiso antes de la instalación"], re:"Los planos de taller se presentan para revisión, aprobación y permiso de la AHJ antes de la instalación. Ref.: requisitos de planos de trabajo/aprobación NFPA 13."},
  {id:96, q:"La edición de NFPA 13 que un diseñador debe seguir está determinada por:", opts:["Siempre la edición más reciente","El fabricante de la tubería","La preferencia personal del diseñador","La edición referenciada/adoptada por el código vigente en esa jurisdicción"], re:"La edición aplicable es la adoptada por el código vigente de la jurisdicción, que puede no ser la más reciente. Ref.: práctica de adopción de códigos."},
  {id:97, q:"Un componente 'listado' (listed) referenciado en NFPA 13 significa que el producto está:", opts:["Pintado de rojo","Exento de inspección","Más barato que las alternativas","Evaluado por un laboratorio de pruebas reconocido y publicado en una lista para su uso previsto"], re:"'Listado' indica equipo evaluado por un laboratorio reconocido (p. ej., UL/FM) y publicado como adecuado para un uso específico. Ref.: definiciones NFPA (listado)."},
  {id:98, q:"NFPA 170 apoya la lectura de planos al proporcionar:", opts:["Métodos de cálculo hidráulico","Clases de mercancía","Curvas de bomba","Símbolos normalizados de seguridad humana y emergencias"], re:"NFPA 170 normaliza los símbolos de seguridad humana/emergencias usados en dibujos y señalización. Ref.: NFPA 170 (alcance)."},
  {id:99, q:"El área máxima de piso protegida por un solo sistema de rociadores para riesgo leve u ordinario se limita tradicionalmente a:", opts:["25,000 sq ft","Sin límite","100,000 sq ft","52,000 sq ft"], re:"NFPA 13 limita tradicionalmente un solo sistema de riesgo leve/ordinario a 52,000 sq ft (riesgo extra/almacenamiento en altura a 40,000 sq ft). Ref.: limitaciones de área de protección del sistema NFPA 13."},
  {id:100, q:"Dentro de la jerarquía de diseño, el papel de NFPA 13 respecto al código de construcción que la adopta es:", opts:["Anular el código de construcción en todos los casos","Definir la carga de ocupantes","Reemplazar a la AHJ","Servir como la norma de instalación referenciada a la que el código apunta para los sistemas de rociadores"], re:"El código de construcción/incendios referencia a NFPA 13 como la norma de instalación; el código y la AHJ siguen siendo la autoridad legal. Ref.: estructura de normas referenciadas del código modelo."},
  {id:101, q:"¿Qué representa el factor K nominal de un rociador en el diseño?", opts:["La sensibilidad térmica (índice de tiempo de respuesta) del elemento operativo","La temperatura a la que se libera el elemento operativo","El área de cobertura máxima que el rociador puede proteger","El coeficiente de descarga que relaciona el caudal con la raíz cuadrada de la presión (Q = K√P)"], re:"El factor K es el coeficiente de descarga en Q = K√P, donde Q es el caudal (gpm) y P es la presión (psi). NFPA 13 especifica el uso del factor K nominal para los cálculos hidráulicos."},
  {id:102, q:"Un rociador de descarga estándar (standard-spray) con factor K nominal de 5.6 que fluye a 7 psi descarga aproximadamente cuántos gpm? (Q = K√P)", opts:["Cerca de 14.8 gpm","Cerca de 5.6 gpm","Cerca de 39 gpm","Cerca de 25 gpm"], re:"Q = K√P = 5.6 × √7 = 5.6 × 2.646 ≈ 14.8 gpm. El factor K multiplicado por la raíz cuadrada de la presión da la descarga."},
  {id:103, q:"El factor K nominal más común usado históricamente para rociadores de descarga estándar de riesgo ligero y ordinario es:", opts:["K-2.8","K-5.6","K-11.2","K-25.2"], re:"K-5.6 (orificio de 1/2 pulg.) es el factor K tradicional de descarga estándar para riesgo ligero y ordinario. NFPA 13 enumera los factores K nominales; K-5.6 es la referencia de larga data."},
  {id:104, q:"En comparación con un rociador K-5.6 a la misma presión, un rociador K-11.2 descarga aproximadamente:", opts:["La mitad del caudal","El mismo caudal","Cuatro veces el caudal","El doble del caudal"], re:"Como el caudal es proporcional a K, duplicar K de 5.6 a 11.2 duplica la descarga a una presión dada (Q = K√P)."},
  {id:105, q:"Cuando un suministro de agua proporciona presión limitada pero volumen adecuado, seleccionar un rociador de factor K mayor es ventajoso porque:", opts:["Permite automáticamente un espaciamiento más amplio de los rociadores","Reduce la densidad de diseño requerida","Entrega el caudal requerido a una presión de operación más baja","Reduce la clasificación de temperatura necesaria"], re:"Un factor K mayor entrega el mismo caudal a menor presión (Q = K√P), por lo que se prefiere donde la presión de suministro es limitada. Los límites de espaciamiento y densidad se establecen de forma independiente."},
  {id:106, q:"Para aplicaciones de almacenamiento, NFPA 13 generalmente exige un factor K nominal mínimo de al menos:", opts:["K-2.8","K-8.0","K-4.2","K-25.2"], re:"La protección de almacenamiento requiere orificios más grandes para entregar densidades más altas; los criterios de almacenamiento de NFPA 13 generalmente exigen rociadores K-8.0 (y mayores). K-2.8 y K-4.2 se limitan a usos de riesgo ligero/residencial."},
  {id:107, q:"Se selecciona un rociador de descarga vertical (upright) en lugar de uno colgante (pendent) principalmente cuando:", opts:["La línea ramal queda expuesta debajo del techo/estructura","Un techo terminado oculta la tubería","Se requiere cobertura de pared lateral desde una pared","Se necesita protección de almacenamiento ESFR"], re:"Los rociadores verticales se usan en líneas ramales expuestas (p. ej., bajo estructura expuesta) para que el deflector arroje el agua hacia abajo/afuera correctamente. Los colgantes descienden por debajo de los techos terminados."},
  {id:108, q:"Un rociador de pared lateral de descarga estándar (standard sidewall spray) es más apropiado donde:", opts:["Debe protegerse almacenamiento apilado en altura","Las áreas de proceso de riesgo extra requieren espaciamiento de 12 ft","Se usa protección ESFR solo de techo","La tubería ramal no puede tenderse por el techo y la cobertura debe provenir de una pared"], re:"Los rociadores de pared lateral descargan un semi-paraboloide desde una pared y se usan donde la tubería superior es poco práctica. NFPA 13 limita los de pared lateral principalmente a salas de riesgo ligero y ordinario (Grupo 1)."},
  {id:109, q:"Los rociadores de pared lateral de descarga estándar generalmente están limitados por NFPA 13 a qué ocupaciones?", opts:["Solo riesgo extra Grupo 2","Solo riesgo ligero y riesgo ordinario (Grupo 1)","Solo almacenamiento apilado en altura","Todas las ocupaciones sin restricción"], re:"NFPA 13 restringe los rociadores de pared lateral de descarga estándar a riesgo ligero y riesgo ordinario Grupo 1; otros riesgos requieren descarga superior o rociadores especiales."},
  {id:110, q:"Un rociador colgante seco (dry-pendent) se selecciona principalmente para:", opts:["Aumentar el factor K de un sistema húmedo","Permitir que un colgante descienda desde un sistema húmedo hacia un espacio sin calefacción/con congelación sin agua atrapada en la cabeza","Proporcionar operación de respuesta rápida","Proteger contra altas temperaturas de techo"], re:"Un colgante seco/pared lateral seco mantiene el agua retenida en la porción calefaccionada del sistema, permitiendo que una sola cabeza se extienda a un congelador o área sin calefacción sin congelarse. No cambia el factor K ni la clase de respuesta."},
  {id:111, q:"Los rociadores colgantes ocultos (concealed pendent) con placa de cubierta se eligen principalmente por:", opts:["Mayor densidad de descarga","Espaciamiento máximo más amplio que los colgantes estándar","Ocupaciones de almacenamiento","Estética en techos terminados, con la placa de cubierta que se desprende a una temperatura establecida"], re:"Los rociadores ocultos esconden la cabeza detrás de una placa de cubierta que se libera a una temperatura clasificada (comúnmente 135 °F) antes de que el rociador opere; son una elección estética para techos terminados y siguen el espaciamiento de descarga estándar."},
  {id:112, q:"Qué tipo de rociador está específicamente listado y destinado a la protección de almacenamiento apilado en altura y en estanterías desde el nivel del techo, eliminando con frecuencia los rociadores dentro de estanterías?", opts:["ESFR (Early Suppression Fast Response)","Pared lateral de descarga estándar","Rociador residencial","Rociador de diluvio abierto"], re:"Los rociadores ESFR están diseñados para suprimir (no solo controlar) incendios de almacenamiento desde el techo, eliminando frecuentemente la necesidad de rociadores dentro de estanterías dentro de sus límites listados."},
  {id:113, q:"Los rociadores residenciales (según las disposiciones residenciales de NFPA 13) están listados principalmente para:", opts:["Maximizar la densidad de control en almacenes","Proteger procesos químicos de riesgo extra","Proporcionar habitabilidad para el escape de los ocupantes en unidades de vivienda usando elementos de respuesta rápida","Reemplazar ESFR en almacenamiento en estanterías"], re:"Los rociadores residenciales usan elementos de respuesta rápida y patrones de mojado de paredes para mejorar la seguridad de la vida/habitabilidad en unidades de vivienda; no son cabezas de control/supresión para almacenamiento industrial."},
  {id:114, q:"Un rociador de aplicación específica en modo de control (CMSA, antes 'gota grande') se caracteriza por:", opts:["Gotas de agua grandes y alto momento para penetrar el penacho del fuego en almacenamiento","Un orificio pequeño y elemento de respuesta rápida para oficinas","Una placa de cubierta para instalación oculta","Descarga solo de pared lateral"], re:"Los rociadores CMSA producen gotas grandes de alto momento que penetran el penacho del fuego para protección de almacenamiento; son una opción de modo de control distinta de los rociadores de supresión ESFR."},
  {id:115, q:"Para un sistema de riesgo ligero calculado hidráulicamente, NFPA 13 generalmente exige rociadores con un factor K nominal de al menos:", opts:["K-1.4","K-2.8","K-5.6","K-14.0"], re:"Los sistemas de riesgo ligero y ordinario calculados hidráulicamente generalmente usan K-5.6 o mayor; los orificios más pequeños (K-2.8/K-4.2) se limitan a usos específicos de riesgo ligero listados."},
  {id:116, q:"Un rociador abierto (sin elemento sensible al calor) se usa en:", opts:["Sistemas de diluvio donde todas las cabezas fluyen simultáneamente al activarse el sistema","Sistemas húmedos estándar de tubería húmeda de riesgo ligero","Salas de riesgo ordinario de respuesta rápida","Techos de almacenamiento ESFR"], re:"Los rociadores abiertos no tienen elemento fusible/de ampolla y se usan en sistemas de diluvio, donde un sistema de detección separado abre la válvula de diluvio y el agua fluye de cada cabeza a la vez."},
  {id:117, q:"Seleccionar un rociador de cobertura extendida (EC) en lugar de uno de descarga estándar permite principalmente al diseñador:", opts:["Reducir la densidad de diseño requerida","Eliminar los cálculos hidráulicos","Reducir la clasificación de temperatura necesaria","Cubrir un área de piso mayor por rociador dentro de su listado específico"], re:"Los rociadores EC están listados para áreas de protección mayores y espaciamientos más amplios que la descarga estándar, reduciendo el número de cabezas. Deben usarse estrictamente dentro de su listado y aún requieren cálculo hidráulico."},
  {id:118, q:"Para rociadores de descarga estándar en riesgo LIGERO (construcción sin obstrucciones), el área de protección máxima por rociador es:", opts:["130 ft²","196 ft²","400 ft²","225 ft²"], re:"Tabla de NFPA 13 para descarga estándar: el área de protección máxima para riesgo ligero es 225 ft² por rociador (p. ej., 15 ft × 15 ft)."},
  {id:119, q:"Para rociadores de descarga estándar en riesgo ORDINARIO (construcción sin obstrucciones), el área de protección máxima por rociador es:", opts:["225 ft²","130 ft²","100 ft²","400 ft²"], re:"NFPA 13: el área de protección máxima para riesgo ordinario en descarga estándar es 130 ft² por rociador."},
  {id:120, q:"Para rociadores de descarga estándar en riesgo LIGERO u ORDINARIO, la distancia máxima entre rociadores en una línea ramal es:", opts:["10 ft","15 ft","12 ft","20 ft"], re:"NFPA 13 establece 15 ft de espaciamiento máximo entre rociadores de descarga estándar tanto para riesgo ligero como ordinario."},
  {id:121, q:"Para rociadores de descarga estándar en riesgo EXTRA, la distancia máxima entre rociadores es:", opts:["15 ft","8 ft","20 ft","12 ft"], re:"NFPA 13 limita el espaciamiento de descarga estándar de riesgo extra a 12 ft (sistemas de cédula de tubería y calculados hidráulicamente a densidades de 0.25 gpm/ft² o mayores)."},
  {id:122, q:"Para rociadores de descarga estándar de riesgo EXTRA, el área de protección máxima por rociador (calculado hidráulicamente, densidad menor a 0.25 gpm/ft²) es:", opts:["400 ft²","100 ft²","225 ft²","130 ft²"], re:"Para riesgo extra, los sistemas calculados hidráulicamente por debajo de 0.25 gpm/ft² pueden usar hasta 130 ft²; a 0.25 gpm/ft² y superior (y cédula de tubería) el máximo es 100 ft²."},
  {id:123, q:"El área de protección por rociador (A_s) se determina mediante qué relación?", opts:["A_s = S − L","A_s = K × √P","A_s = S × L, donde S es la dimensión a lo largo del ramal y L es la dimensión entre ramales","A_s = densidad × presión"], re:"NFPA 13 calcula el área de protección por rociador como A_s = S × L, donde S es la distancia a lo largo de la línea ramal (el mayor entre el doble de la distancia a la pared o el espaciamiento) y L es la distancia entre líneas ramales, ambas tomadas como el mayor valor aplicable."},
  {id:124, q:"Al calcular S (a lo largo de la línea ramal) para un rociador adyacente a una pared, la dimensión usada es:", opts:["Solo la distancia real a la pared","Siempre 15 ft","La mitad de la distancia a la pared","El doble de la distancia a la pared, o el espaciamiento al siguiente rociador — el que sea mayor"], re:"NFPA 13 toma S como el mayor entre: el doble de la distancia a la pared (rociador de extremo) o la distancia al rociador adyacente. Esto asegura que el área no se subestime para las cabezas de extremo."},
  {id:125, q:"La distancia máxima de un rociador de descarga estándar a una pared es:", opts:["Igual al espaciamiento máximo entre rociadores","La mitad de la distancia máxima permitida entre rociadores","Un cuarto del ancho de la sala","Siempre 4 in"], re:"NFPA 13: la distancia a una pared no puede exceder la mitad del espaciamiento permitido entre rociadores (p. ej., 7.5 ft para un trazado de 15 ft)."},
  {id:126, q:"La distancia mínima a la que el deflector de un rociador de descarga estándar puede colocarse de una pared es:", opts:["4 in","12 in","18 in","2 in"], re:"NFPA 13 exige que los rociadores estén al menos a 4 in de una pared para evitar que la pared obstruya el patrón de descarga en desarrollo."},
  {id:127, q:"La distancia mínima permitida entre dos rociadores de descarga estándar (sin deflector/baffle) es:", opts:["4 ft","6 ft","8 ft","10 ft"], re:"NFPA 13 exige al menos 6 ft entre rociadores (medidos a lo largo de la pendiente del techo) para evitar el enfriamiento cruzado (cold-soldering), a menos que se instale un baffle listado entre ellos."},
  {id:128, q:"Dos rociadores pueden espaciarse a menos de 6 ft entre centros solo cuando:", opts:["El techo está inclinado","El riesgo es ligero","Son de respuesta rápida","Se instala un baffle entre ellos para proteger los elementos operativos"], re:"Un baffle listado entre cabezas muy próximas protege cada elemento operativo de la descarga del otro (evitando el enfriamiento cruzado), que es la condición que NFPA 13 permite para espaciamiento menor a 6 ft."},
  {id:129, q:"La 'regla de sala pequeña' de NFPA 13 se aplica a una sala de riesgo ligero que es:", opts:["Cualquier sala con techo inclinado","Cualquier sala menor a 1,500 ft²","Cualquier sala de riesgo ordinario","Sin obstrucciones, de ocupación de riesgo ligero, y de 800 ft² o menos de área"], re:"La regla de sala pequeña se aplica a un compartimento de riesgo ligero sin obstrucciones de 800 ft² o menos, permitiendo un rociador hasta a 9 ft de cualquier pared individual."},
  {id:130, q:"Bajo la regla de sala pequeña, un rociador puede ubicarse a un máximo de qué distancia de cualquier pared individual?", opts:["7.5 ft","12 ft","9 ft","15 ft"], re:"La regla de sala pequeña permite colocar un rociador hasta a 9 ft de cualquier pared individual (en lugar del límite usual de media-distancia a la pared), dentro de una sala de riesgo ligero de 800 ft²."},
  {id:131, q:"Los rociadores de cobertura extendida en riesgo ligero pueden estar listados para un área de protección máxima de hasta:", opts:["225 ft²","130 ft²","400 ft²","100 ft²"], re:"Los rociadores EC pueden estar listados para cobertura de hasta 400 ft² (p. ej., 20 ft × 20 ft) en riesgo ligero, muy por encima del límite de 225 ft² de la descarga estándar, pero solo dentro de su listado específico."},
  {id:132, q:"Los rociadores de cobertura extendida deben instalarse:", opts:["A cualquier espaciamiento que el diseñador elija","Sin cálculo hidráulico","Solo en ocupaciones de riesgo extra","Estrictamente dentro de los límites de área de protección y espaciamiento indicados en su listado individual"], re:"Los límites de espaciamiento/área de los rociadores EC provienen del listado del fabricante en lugar de las tablas genéricas de descarga estándar, por lo que deben aplicarse exactamente como están listados."},
  {id:133, q:"Un rociador está ubicado a 7 ft de una pared y a 6 ft del siguiente rociador a lo largo de la línea ramal. El valor de S usado para el cálculo del área de protección es:", opts:["6 ft","7 ft","13 ft","14 ft"], re:"S es el mayor entre el doble de la distancia a la pared (2 × 7 = 14 ft) o el espaciamiento del rociador (6 ft); por lo tanto S = 14 ft."},
  {id:134, q:"Si los rociadores están a 12 ft de distancia a lo largo del ramal (S = 12 ft) y las líneas ramales están a 10 ft de distancia (L = 10 ft), el área de protección por rociador es:", opts:["120 ft²","22 ft²","144 ft²","100 ft²"], re:"A_s = S × L = 12 ft × 10 ft = 120 ft², que no debe exceder el área de protección máxima permitida del riesgo."},
  {id:135, q:"La 'regla de tres veces' de NFPA 13 para rociadores de descarga estándar exige que un rociador se posicione lejos de una obstrucción una distancia horizontal de al menos:", opts:["Tres veces la dimensión máxima de la obstrucción (p. ej., el ancho de un ducto), hasta un máximo de 24 in","Tres veces el espaciamiento del rociador","Tres pies en todos los casos","La mitad de la altura de la obstrucción"], re:"La regla de tres veces: mantener el rociador al menos a tres veces la dimensión máxima de la obstrucción (máx. 24 in) para que la descarga pueda pasar por ambos lados. (Para rociadores de cobertura extendida aplica una regla de cuatro veces, máx. 36 in.)"},
  {id:136, q:"La regla de tres veces limita la separación horizontal requerida desde una obstrucción a un máximo de:", opts:["12 in","18 in","24 in","36 in"], re:"Incluso para obstrucciones muy grandes, la regla de tres veces para rociadores de descarga estándar limita la distancia horizontal requerida a 24 in."},
  {id:137, q:"Para rociadores de cobertura extendida, la regla de obstrucción análoga es la 'regla de cuatro veces', con una separación máxima de:", opts:["24 in","36 in","48 in","12 in"], re:"Los rociadores EC siguen una regla de cuatro veces (cuatro veces la dimensión de la obstrucción), limitada a 36 in, reflejando su mayor alcance."},
  {id:138, q:"Bajo la 'regla de viga', un deflector de rociador posicionado en o por encima del fondo de una viga/obstrucción debe separarse horizontalmente de esa obstrucción al menos:", opts:["12 in (1 ft)","6 in","24 in","36 in"], re:"La regla de viga exige al menos 1 ft (12 in) de separación horizontal cuando el deflector está a cualquier distancia por encima del fondo de la obstrucción, aumentando a medida que el deflector sube (según la tabla de deflector-por-encima-del-fondo-de-la-obstrucción del estándar)."},
  {id:139, q:"Las obstrucciones continuas más anchas que qué dimensión generalmente requieren que se instalen rociadores debajo de ellas?", opts:["Más de 2 ft","Más de 4 ft","Más de 6 ft","Más de 8 ft"], re:"NFPA 13 generalmente exige rociadores bajo obstrucciones fijas de más de 4 ft de ancho (p. ej., ductos anchos, plataformas, mesas) porque la obstrucción protege el piso de abajo."},
  {id:140, q:"Cuando debe instalarse un rociador debajo de una obstrucción ancha, su deflector debe ubicarse dentro de qué distancia del fondo de la obstrucción?", opts:["Dentro de 18 in","Dentro de 12 in","Dentro de 24 in","Dentro de 36 in"], re:"NFPA 13 exige que el deflector de un rociador bajo una obstrucción ancha no esté a más de 12 in por debajo del fondo de esa obstrucción para que el patrón se desarrolle adecuadamente debajo."},
  {id:141, q:"La separación vertical mínima desde el deflector de un rociador de descarga estándar hasta la PARTE SUPERIOR DEL ALMACENAMIENTO debe ser de al menos:", opts:["12 in","24 in","18 in","36 in"], re:"NFPA 13 exige una separación mínima de 18 in entre el deflector y la parte superior del almacenamiento para que el patrón de descarga pueda desarrollarse plenamente antes de alcanzar la mercancía."},
  {id:142, q:"Para rociadores ESFR, la separación mínima desde el deflector hasta la parte superior del almacenamiento es:", opts:["18 in","24 in","36 in","12 in"], re:"La protección de almacenamiento ESFR requiere una separación mínima de 36 in desde el deflector hasta la parte superior del almacenamiento — mayor que las 18 in usadas para descarga estándar — para permitir que la descarga en modo de supresión se desarrolle."},
  {id:143, q:"Para construcción sin obstrucciones, el deflector de un rociador colgante o vertical de descarga estándar debe posicionarse a qué distancia por debajo del techo?", opts:["Un máximo de 36 in por debajo del techo","Exactamente 6 in por debajo del techo","Un mínimo de 4 in por debajo del techo","Un mínimo de 1 in y un máximo de 12 in por debajo del techo"], re:"NFPA 13: bajo techos sin obstrucciones (lisos), los deflectores colgantes/verticales de descarga estándar se colocan de 1 in a 12 in por debajo del techo para equilibrar la captación de calor con el desarrollo del patrón."},
  {id:144, q:"Para rociadores de pared lateral de descarga estándar, el deflector generalmente se ubica a qué distancia por debajo del techo?", opts:["1 in a 6 in","12 in a 18 in","4 in a 6 in","18 in a 24 in"], re:"NFPA 13 generalmente exige los deflectores de rociadores de pared lateral de 4 in a 6 in por debajo del techo (listados especiales pueden permitir de 6 in a 18 in)."},
  {id:145, q:"El propósito de las reglas de obstrucción en el trazado de rociadores es fundamentalmente:", opts:["Aumentar el factor K del rociador","Reducir la clasificación de temperatura requerida","Asegurar que el patrón de descarga alcance el piso/riesgo sin ser bloqueado o sombreado","Permitir un espaciamiento máximo más amplio"], re:"Las reglas de obstrucción protegen el patrón de distribución de agua desarrollado de ser bloqueado o 'sombreado', lo que dejaría áreas desprotegidas — la razón central de las reglas de tres veces/viga/bajo-obstrucción."},
  {id:146, q:"Un ducto de 24 in de ancho corre debajo del techo. Aplicando la regla de tres veces, el rociador debe ubicarse al menos a qué distancia horizontal del borde cercano del ducto?", opts:["72 in","24 in (limitado por el máximo de 24 in)","12 in","48 in"], re:"Tres veces la dimensión de 24 in es 72 in, pero la regla limita la distancia horizontal requerida a un máximo de 24 in; por lo tanto se requieren 24 in."},
  {id:147, q:"Los rociadores debajo de una rejilla abierta u obstrucción tipo enrejado:", opts:["Nunca se requieren sin importar el tamaño","Pueden no ser requeridos si la obstrucción es lo suficientemente abierta para dejar pasar agua/calor, según las disposiciones del estándar","Siempre requieren cabezas ESFR","Deben espaciarse a un máximo de 4 ft"], re:"El enrejado abierto que permite que pasen calor y agua puede tratarse de forma diferente a las obstrucciones sólidas; NFPA 13 tiene disposiciones específicas para construcción abierta/de rejilla en lugar de requisitos generales de rociadores debajo."},
  {id:148, q:"Cuando los rociadores se espacian a menos de 6 ft, el baffle entre ellos debe:", opts:["Ser combustible para quemarse temprano","Instalarse solo en rociadores de pared lateral","Tener al menos 24 in de alto","Ser sólido y rígido, dimensionado para proteger los elementos operativos, y permanecer en su lugar durante la operación"], re:"NFPA 13 exige un baffle sólido y rígido (aproximadamente 8 in de largo, 6 in de alto, colocado entre los deflectores) que permanezca en su lugar antes y durante la operación para proteger los elementos operativos adyacentes."},
  {id:149, q:"Una luminaria colgante de 10 in de ancho cuelga debajo de un rociador de techo de descarga estándar. Bajo la regla de tres veces, la separación horizontal mínima requerida al rociador es:", opts:["24 in (el límite de la regla, ya que 3 × 10 in = 30 in excede 24 in)","5 in","10 in","30 in"], re:"Tres veces la dimensión de 10 in es 30 in, pero la regla de tres veces limita la separación horizontal requerida a un máximo de 24 in; por lo tanto solo se requieren 24 in, no el valor aritmético de 30 in."},
  {id:150, q:"Para obstrucciones contra una pared (como un dintel/soffit) sobre las que un rociador de pared lateral debe arrojar, el diseñador debe verificar:", opts:["El factor K es de al menos 11.2","La obstrucción no interrumpe el alcance horizontal listado del rociador y el deflector la libra según el estándar","La clasificación de temperatura es alta","El espaciamiento mínimo es de 4 ft"], re:"El trazado de pared lateral debe mantener dinteles, nichos de luz y obstrucciones de pared similares fuera de la trayectoria de descarga listada para que el patrón no se bloquee, en consistencia con las disposiciones de obstrucción de NFPA 13."},
  {id:151, q:"La separación mínima de 18 in al almacenamiento se aumenta a 36 in para qué mercancía almacenada?", opts:["Neumáticos de caucho","Registros de papel","Comida enlatada","Tarimas vacías"], re:"NFPA 13 exige al menos 36 in de separación desde los deflectores de descarga estándar cuando se almacenan neumáticos de caucho, reflejando el grave desafío de incendio del almacenamiento de neumáticos."},
  {id:152, q:"El área de protección máxima por rociador ESFR es:", opts:["130 ft²","144 ft²","225 ft²","100 ft²"], re:"NFPA 13 limita la cobertura del rociador ESFR a un máximo de 100 ft² por rociador."},
  {id:153, q:"La distancia máxima entre rociadores ESFR es:", opts:["12 ft","15 ft","20 ft","8 ft"], re:"Los rociadores ESFR tienen un espaciamiento máximo de 12 ft entre cabezas (con límites adicionales en grandes alturas de techo)."},
  {id:154, q:"El espaciamiento mínimo entre rociadores ESFR es:", opts:["8 ft","6 ft","4 ft","10 ft"], re:"NFPA 13 establece un espaciamiento mínimo de 8 ft entre rociadores ESFR (mayor que el mínimo de 6 ft para descarga estándar) para evitar el enfriamiento cruzado de los elementos de respuesta rápida."},
  {id:155, q:"ESFR significa:", opts:["Extended Spray Fire Resistant","Enhanced Storage Flow Regulator","Extra Spacing Flow Rated","Early Suppression Fast Response"], re:"ESFR = Early Suppression Fast Response, un rociador de respuesta rápida diseñado para suprimir incendios de almacenamiento desde el techo en lugar de meramente controlarlos."},
  {id:156, q:"La diferencia fundamental entre un rociador ESFR de 'modo de supresión' y un rociador de 'modo de control' es que el ESFR busca:", opts:["Pre-mojar solo las mercancías adyacentes","Realmente extinguir/suprimir el fuego entregando un gran volumen rápidamente al foco del fuego","Operar a una temperatura más alta","Reducir el número de niveles dentro de la estantería en uno"], re:"El ESFR entrega una descarga alta y rápida destinada a suprimir (sofocar) el fuego, mientras que los rociadores de modo de control buscan controlar la propagación del fuego y pre-mojar el entorno hasta la extinción manual."},
  {id:157, q:"La protección de techo ESFR se diseña hidráulicamente en base a:", opts:["Una densidad sobre un área","Solo cédula de tubería","Una densidad fija de 0.20 gpm/ft²","Una PRESIÓN de operación mínima para un número especificado de rociadores (p. ej., los 12 más remotos)"], re:"El diseño ESFR se basa en presión: el listado especifica una presión de operación mínima para un conjunto de rociadores de diseño (comúnmente los 12 hidráulicamente más exigentes, cuatro en cada una de tres líneas), no una densidad/área."},
  {id:158, q:"Los factores K nominales típicos para rociadores ESFR incluyen:", opts:["K-2.8 y K-4.2","K-14.0, K-16.8, K-22.4 y K-25.2","Solo K-5.6","K-1.4"], re:"Los rociadores ESFR usan orificios grandes — los factores K nominales comunes son K-14.0, K-16.8, K-22.4 y K-25.2 — para entregar los altos caudales necesarios para la supresión."},
  {id:159, q:"Los sistemas ESFR generalmente NO se permiten en qué tipo de sistema de tubería porque un retraso en la entrega de agua socava la supresión?", opts:["Sistemas de tubería húmeda","Sistemas de tubería seca (excepto donde estén específicamente listados/permitidos)","Sistemas en cuadrícula (gridded)","Sistemas en bucle (looped)"], re:"Como la supresión depende de la entrega inmediata a pleno caudal, el ESFR generalmente se aplica en sistemas de tubería húmeda; los sistemas secos retrasan el agua y se restringen a arreglos específicamente listados."},
  {id:160, q:"Los rociadores dentro de estanterías se añaden a un diseño de almacenamiento principalmente para:", opts:["Reemplazar los rociadores de techo","Reducir el requisito de separación de almacenamiento","Aumentar el espaciamiento de techo","Proporcionar protección dentro de la estantería donde la descarga del techo no puede alcanzar el fuego"], re:"Los rociadores dentro de estanterías protegen dentro del conjunto de almacenamiento donde la descarga del techo está bloqueada por las cargas superiores; complementan (no reemplazan) la protección de techo cuando la opción solo de techo es inadecuada."},
  {id:161, q:"Una ventaja clave de seleccionar protección de techo ESFR para almacenamiento en estanterías es que, dentro de su listado, puede:", opts:["Reducir la separación requerida a 6 in","Eliminar la necesidad de un suministro de agua","Permitir altura de almacenamiento ilimitada","Eliminar la necesidad de rociadores dentro de estanterías"], re:"Un beneficio de diseño principal del ESFR es que, dentro de los límites listados de altura de techo y altura de almacenamiento, puede proteger el almacenamiento en estanterías solo desde el techo, eliminando los rociadores dentro de estanterías."},
  {id:162, q:"La separación desde los deflectores ESFR hasta la parte superior del almacenamiento debe ser de un mínimo de:", opts:["18 in","24 in","36 in","12 in"], re:"El ESFR requiere una separación mínima de 36 in desde el deflector hasta la parte superior del almacenamiento, el doble de las 18 in usadas para descarga estándar, para que la descarga de supresión pueda desarrollarse."},
  {id:163, q:"Los criterios de protección de ocupaciones de almacenamiento dependen más directamente de qué conjunto de variables?", opts:["Solo el área total de piso del edificio","Solo el color del rociador","Clase de mercancía, método/altura de almacenamiento y altura del techo","El número de salidas"], re:"El diseño de almacenamiento (densidades, presiones ESFR, necesidades dentro de estanterías) está impulsado por la clasificación de la mercancía, el arreglo y altura de almacenamiento, y la altura del techo — las variables centrales en los capítulos de almacenamiento de NFPA 13."},
  {id:164, q:"Los rociadores CMSA (aplicación específica en modo de control) difieren del ESFR en que los rociadores CMSA están destinados a:", opts:["Controlar el fuego (limitar el crecimiento y pre-mojar) en lugar de suprimirlo","Suprimir el fuego completamente","Operar solo como cabezas de diluvio abiertas","Proporcionar cobertura de seguridad de vida residencial"], re:"El CMSA es una tecnología de modo de control (gotas grandes, alto momento) destinada a controlar incendios de almacenamiento, mientras que el ESFR es una tecnología de modo de supresión que busca extinguir el fuego."},
  {id:165, q:"Para la protección de almacenamiento, NFPA 13 generalmente exige un factor K nominal de rociador de al menos:", opts:["K-8.0","K-4.2","K-2.8","K-1.4"], re:"Las densidades de almacenamiento requieren orificios más grandes; los criterios de almacenamiento de NFPA 13 generalmente exigen K-8.0 o mayor (CMSA y ESFR usan factores K aún más grandes)."},
  {id:166, q:"Cuando no puede usarse ESFR (por ejemplo porque la altura de almacenamiento o de techo excede su listado), un enfoque común de diseño alternativo de techo para almacenamiento es:", opts:["Rociadores residenciales","Diluvio abierto sin detección","Protección de densidad/área CMSA o de modo de control, posiblemente con rociadores dentro de estanterías","Solo rociadores de pared lateral"], re:"Donde se exceden los límites del ESFR, los diseñadores recurren a protección de techo de modo de control (CMSA o densidad/área de modo de control estándar), a menudo combinada con rociadores dentro de estanterías."},
  {id:167, q:"Una razón principal por la que pueden requerirse rociadores dentro de estanterías incluso con rociadores de techo de modo de control es que:", opts:["Los rociadores de techo están demasiado fríos","Los rociadores dentro de estanterías reemplazan la bomba contra incendios","Los rociadores de techo no pueden alcanzar un fuego profundo dentro de estanterías altas","La mercancía es no combustible"], re:"El almacenamiento en estanterías altas y densas bloquea la descarga del techo de alcanzar los fuegos de niveles inferiores; los rociadores dentro de estanterías colocan agua dentro del conjunto para abordar este sombreado."},
  {id:168, q:"La efectividad de la protección ESFR es más sensible a las obstrucciones porque:", opts:["Las obstrucciones pueden desviar la descarga de alto momento y evitar que alcance el foco del fuego","Sus gotas son muy pequeñas y se bloquean fácilmente","Usa una presión de operación baja","Opera como una cabeza de modo de control"], re:"El ESFR depende de un chorro de alto momento que penetra el penacho hasta el fuego; las obstrucciones cerca de las cabezas pueden desviar esa descarga, por lo que el ESFR tiene reglas estrictas de obstrucción (y separación)."},
  {id:169, q:"El rango de clasificación de temperatura para un rociador de temperatura ORDINARIA es:", opts:["135–170°F","100–134°F","175–225°F","250–300°F"], re:"NFPA 13: los rociadores de temperatura ordinaria llevan una clasificación de temperatura de 135–170°F (comúnmente 135°F o 155°F)."},
  {id:170, q:"El rango de clasificación de temperatura para un rociador de temperatura INTERMEDIA es:", opts:["135–170°F","250–300°F","175–225°F","325–375°F"], re:"NFPA 13: los rociadores de temperatura intermedia están clasificados a 175–225°F (p. ej., 200°F)."},
  {id:171, q:"El rango de clasificación de temperatura para un rociador de temperatura ALTA es:", opts:["250–300°F","175–225°F","135–170°F","100–134°F"], re:"NFPA 13: los rociadores de temperatura alta están clasificados a 250–300°F, usados donde se esperan temperaturas ambientales elevadas."},
  {id:172, q:"Los rociadores cerca de un calefactor de unidad, claraboya u otra fuente de calor generalmente requieren:", opts:["Una clasificación de temperatura más baja (ordinaria)","Solo respuesta rápida","Una clasificación de temperatura más alta para evitar operación prematura/molesta","Un factor K mayor"], re:"NFPA 13 exige rociadores de temperatura intermedia o alta cerca de fuentes de calor (calefactores de unidad, claraboyas, equipos mecánicos) para que el calor ambiental normal no cause operación no intencionada."},
  {id:173, q:"El color estandarizado del líquido de la ampolla de vidrio para un rociador de temperatura ORDINARIA (135°F) es:", opts:["Naranja (o rojo para 155°F)","Verde","Azul","Malva"], re:"Códigos de color de la ampolla de vidrio: 135°F es naranja y 155°F es rojo (ambos clase ordinaria). El color indica la temperatura de operación, independiente de la velocidad de respuesta."},
  {id:174, q:"Para un rociador de ampolla de vidrio, una ampolla AMARILLA o VERDE indica qué clase de temperatura?", opts:["Intermedia","Ordinaria","Alta","Extra alta"], re:"Las ampollas de vidrio amarilla (175°F) y verde (200°F) denotan la clase de temperatura intermedia según el código de color de NFPA 13."},
  {id:175, q:"La temperatura ambiente máxima esperada en el techo impulsa la selección del/de la:", opts:["Factor K","Estilo del deflector","Clase de respuesta (QR/SR)","Clasificación de temperatura"], re:"La clasificación de temperatura se selecciona para que el rociador no opere por el calor ambiental normal; NFPA 13 vincula la clasificación a la temperatura ambiente máxima esperada en el techo."},
  {id:176, q:"Un rociador de respuesta rápida (QR) se define por un índice de tiempo de respuesta (RTI) de:", opts:["80 (m·s)^1/2 o más","50 (m·s)^1/2 o menos","Exactamente 100 (m·s)^1/2","Mayor a 350 (m·s)^1/2"], re:"Los elementos de respuesta rápida tienen un RTI de 50 (m·s)^1/2 o menos; los elementos de respuesta estándar tienen un RTI de 80 (m·s)^1/2 o más."},
  {id:177, q:"Un rociador de respuesta estándar (SR) tiene un índice de tiempo de respuesta (RTI) de aproximadamente:", opts:["50 o menos","Siempre 250","Siempre 100","80 o más"], re:"Los rociadores de respuesta estándar tienen un RTI de aproximadamente 80 (m·s)^1/2 o mayor, lo que significa un elemento térmico más grueso que responde más lentamente que la respuesta rápida (RTI ≤ 50)."},
  {id:178, q:"En una ocupación de riesgo LIGERO de tubería húmeda, NFPA 13 generalmente exige qué clase de respuesta?", opts:["Respuesta estándar","Respuesta rápida","Solo alta temperatura","Rociadores abiertos"], re:"NFPA 13 generalmente exige rociadores de respuesta rápida en todas las ocupaciones de riesgo ligero de tubería húmeda para mejorar la seguridad de la vida, con excepciones limitadas."},
  {id:179, q:"Los rociadores de respuesta rápida y de respuesta estándar dentro del mismo compartimento:", opts:["Pueden mezclarse libremente","Solo deben usar el mismo factor K","Ambos deben ser de alta temperatura","No deben mezclarse en el mismo compartimento"], re:"NFPA 13 prohíbe mezclar rociadores QR y SR en el mismo compartimento porque el diseño hidráulico/operativo asume un comportamiento de respuesta consistente en toda el área de diseño."},
  {id:180, q:"La clase de respuesta (QR vs SR) está gobernada por el/la:", opts:["Tamaño del orificio (factor K)","Sensibilidad térmica / RTI del elemento operativo","Solo la clasificación de temperatura","Orientación del deflector"], re:"La clase de respuesta es función de la sensibilidad térmica del elemento operativo, expresada como RTI; es independiente de la clasificación de temperatura y del factor K."},
  {id:181, q:"El elemento de respuesta rápida de un rociador residencial se selecciona principalmente para:", opts:["Operar más pronto para mejorar la habitabilidad y el tiempo de escape de los ocupantes","Aumentar la densidad de descarga","Elevar la clasificación de temperatura","Permitir un espaciamiento más amplio en almacenes"], re:"Los rociadores residenciales usan elementos de respuesta rápida para que se activen temprano, manteniendo condiciones habitables para que los ocupantes escapen — la base de seguridad de vida del listado residencial."},
  {id:182, q:"Dos rociadores del mismo factor K y clasificación de temperatura aún pueden diferir en rendimiento porque pueden tener diferentes:", opts:["Clases de respuesta (RTI), es decir, respuesta rápida vs estándar","Tamaños de rosca de tubería","Solo colores de pintura","Agencias de listado"], re:"La clasificación de temperatura establece la temperatura de operación, pero el RTI (clase de respuesta) establece qué tan rápido el elemento la alcanza; dos rociadores por lo demás idénticos pueden ser QR o SR."},
  {id:183, q:"Para un rociador de estilo de marco (sin ampolla), la clase de temperatura se identifica por:", opts:["El tamaño de la rosca","Un color aplicado a los brazos del marco (o el color del enlace)","El tamaño del deflector","La forma de la placa de cubierta"], re:"NFPA 13 especifica un código de color en los brazos del marco para rociadores tipo soldadura (p. ej., sin color/negro = ordinario, blanco = intermedio, azul = alto) para indicar la clase de temperatura."},
  {id:184, q:"Los rociadores ESFR son inherentemente de qué clase de respuesta?", opts:["Respuesta estándar","Variable","Respuesta rápida (RTI ≤ 50)","Solo alta temperatura"], re:"ESFR significa Early Suppression FAST Response; el elemento es de respuesta rápida (RTI ≤ 50) para que el rociador se abra lo suficientemente temprano para suprimir el incendio de almacenamiento."},
  {id:185, q:"Donde un rociador de ampolla de vidrio muestra una ampolla AZUL, la clase de temperatura es:", opts:["Ordinaria","Alta (286°F)","Intermedia","Residencial"], re:"Una ampolla de vidrio azul corresponde a 286°F, que cae en la clase de temperatura alta según el código de color de ampollas de NFPA 13."},
  {id:186, q:"En el método de densidad/área, la 'densidad' se expresa en unidades de:", opts:["gpm por rociador","gpm/ft² (galones por minuto por pie cuadrado)","psi por ft²","ft² por rociador"], re:"La densidad de diseño es la descarga por unidad de área de piso, gpm/ft², aplicada sobre el área de diseño para establecer la demanda hidráulica."},
  {id:187, q:"Una densidad de diseño típica de riesgo LIGERO usada con el método de densidad/área es aproximadamente:", opts:["0.05 gpm/ft²","0.30 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²"], re:"El riesgo ligero se diseña comúnmente en torno a 0.10 gpm/ft² sobre el área de diseño (p. ej., 1,500 ft² para el método de curva)."},
  {id:188, q:"Un punto de diseño representativo de riesgo ORDINARIO Grupo 2 es:", opts:["0.10 gpm/ft² sobre 1,500 ft²","0.20 gpm/ft² sobre 1,500 ft²","0.05 gpm/ft² sobre 3,000 ft²","0.60 gpm/ft² sobre 2,500 ft²"], re:"El riesgo ordinario Grupo 2 es comúnmente 0.20 gpm/ft² aplicado sobre un área de diseño de 1,500 ft² en el método de densidad/área."},
  {id:189, q:"La descarga mínima requerida de un solo rociador es igual a:", opts:["La densidad de diseño dividida por el área","El factor K multiplicado por el área","La densidad de diseño multiplicada por el área de protección del rociador (A_s)","La presión multiplicada por el factor K"], re:"El caudal mínimo de un rociador = densidad (gpm/ft²) × área de protección A_s (ft²). Esto establece la presión mínima mediante Q = K√P."},
  {id:190, q:"Un rociador que protege 130 ft² a una densidad de riesgo ordinario de 0.20 gpm/ft² debe descargar al menos:", opts:["13 gpm","26 gpm","6.5 gpm","65 gpm"], re:"Caudal requerido = densidad × área = 0.20 gpm/ft² × 130 ft² = 26 gpm mínimo de ese rociador."},
  {id:191, q:"En el enfoque de densidad/área, aumentar el ÁREA de diseño asumida generalmente:", opts:["Eleva la densidad requerida a lo largo de la curva (más área a una densidad ligeramente menor, o viceversa) según la curva de diseño","Reduce la densidad requerida","No tiene efecto sobre la demanda","Elimina el cálculo hidráulico"], re:"Las curvas clásicas de densidad/área intercambian densidad por área: seleccionar un área mayor cambia la densidad según la curva. (La edición 2022 de NFPA 13 limitó y la edición 2025 eliminó estas curvas a favor de un único punto de diseño.)"},
  {id:192, q:"La clasificación de riesgo de una ocupación se selecciona principalmente en base a:", opts:["La cantidad y combustibilidad de los contenidos y el desafío de incendio esperado","Solo la altura del edificio","El color del rociador","El número de pisos"], re:"NFPA 13 clasifica las ocupaciones (ligero, ordinario 1/2, extra 1/2) por la combustibilidad y cantidad de los contenidos y la tasa de liberación de calor esperada — la base para la selección de densidad y área."},
  {id:193, q:"Qué ejemplo de ocupación se clasifica típicamente como riesgo LIGERO?", opts:["Taller de reparación de autos","Operación de pintura por aspersión","Oficina, iglesia o aula escolar","Almacén de líquidos inflamables"], re:"Las oficinas, iglesias y escuelas son ocupaciones clásicas de riesgo ligero (baja carga combustible). Los talleres de reparación son ordinarios; la aspersión y el almacenamiento de líquidos inflamables son de riesgo extra."},
  {id:194, q:"Qué ejemplo se clasifica típicamente como riesgo ORDINARIO (Grupo 2)?", opts:["Una oficina privada","Una sala de lectura de biblioteca","Un taller mecánico o área de reparación de autos","Una habitación residencial"], re:"Los talleres mecánicos y de reparación son ocupaciones representativas de riesgo ordinario Grupo 2, con contenido combustible y tasa de liberación de calor de moderados a altos."},
  {id:195, q:"Qué ejemplo se clasifica típicamente como riesgo EXTRA?", opts:["Un aula","Un área de venta minorista de mercería seca","Una habitación de huéspedes de hotel","Un área de proceso de aspersión de líquido inflamable o de fluido hidráulico"], re:"La aspersión de líquidos inflamables y los procesos de fluido hidráulico combustible son ocupaciones de riesgo extra, que requieren las densidades más altas y el espaciamiento más cerrado."},
  {id:196, q:"Las ocupaciones de riesgo extra requieren mayor densidad Y espaciamiento más cerrado principalmente porque:", opts:["Los techos son siempre más altos","Los rociadores deben ser de un color específico","Los incendios se desarrollan y propagan más rápido y liberan más calor, exigiendo más agua antes sobre el área","Los edificios son más grandes"], re:"El riesgo extra implica un crecimiento rápido del fuego y altas tasas de liberación de calor, por lo que NFPA 13 exige mayores densidades y espaciamiento más cerrado (12 ft / ≤130 ft²) para aplicar más agua rápidamente sobre el área de diseño."},
  {id:197, q:"Para ocupaciones de almacenamiento, la demanda de diseño de techo se expresa más comúnmente como:", opts:["Solo presión, sin caudal","Un solo caudal fijo sin importar la mercancía","Una densidad (gpm/ft²) sobre un área de diseño, o como una presión de operación ESFR para un número fijo de cabezas","Solo el factor K"], re:"La protección de techo de almacenamiento se especifica ya sea como una densidad/área (modo de control) o, para ESFR, como una presión de operación mínima para un número definido de rociadores de diseño."},
  {id:198, q:"El 'área de diseño' (o área remota) en el método de densidad/área representa:", opts:["El área hidráulicamente más exigente que se asume está operando en un incendio","Toda el área de piso del edificio","Solo el área directamente debajo del montante (riser)","El área cubierta por un rociador"], re:"El área de diseño/remota es la porción hidráulicamente más exigente del sistema que se asume opera; la densidad se aplica a través de ella para dimensionar la demanda en la base del montante."},
  {id:199, q:"Cuando un sistema usa rociadores de respuesta rápida en un sistema de tubería húmeda de riesgo ligero u ordinario, NFPA 13 históricamente permitió un área de diseño:", opts:["Aumento del 30%","Duplicación","Reducción (hasta 40% bajo condiciones establecidas), reflejando la operación más temprana de menos cabezas","Eliminación de la asignación de manguera"], re:"NFPA 13 históricamente permitió una reducción del área de diseño (hasta 40% bajo condiciones específicas de techo/pendiente) para rociadores de respuesta rápida en sistemas húmedos de riesgo ligero/ordinario, porque la operación más rápida limita el número de rociadores que se espera se abran."},
  {id:200, q:"Seleccionar la clasificación de riesgo correcta es el paso de diseño fundamental porque determina:", opts:["Solo el color de pintura de la tubería","El permiso de ocupación del edificio","La densidad, el área de diseño, el espaciamiento máximo y el área de protección máxima usados para todo el trazado","El tiempo de respuesta del cuerpo de bomberos"], re:"La clasificación de riesgo establece la densidad, el área de diseño/remota, el espaciamiento máximo y el área de protección máxima por rociador — toda decisión de trazado e hidráulica posterior deriva de ella (capítulos de ocupación y diseño de NFPA 13)."},
  {id:201, q:"En el método de diseño densidad/área, ¿qué expresa la 'densidad' de diseño?", opts:["El número de rociadores por cada 100 ft² de piso","La pérdida por fricción por pie de ramal","El peso del agua almacenada por pie cúbico de espacio","La descarga mínima por unidad de superficie de piso, en gpm por pie cuadrado"], re:"La densidad es la tasa de aplicación mínima requerida sobre el área de diseño, expresada en gpm/ft² (NFPA 13, método de diseño densidad/área)."},
  {id:202, q:"Para una ocupación de Riesgo Ligero, la densidad de diseño comúnmente especificada es la más cercana a cuál valor?", opts:["0.05 gpm/ft²","0.40 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²"], re:"El Riesgo Ligero se diseña típicamente con cerca de 0.10 gpm/ft² sobre el área de diseño más remota (curvas densidad/área de NFPA 13, Riesgo Ligero)."},
  {id:203, q:"El Riesgo Ordinario Grupo 1 se diseña más comúnmente con cuál densidad sobre 1,500 ft²?", opts:["0.15 gpm/ft²","0.12 gpm/ft²","0.10 gpm/ft²","0.30 gpm/ft²"], re:"El diseño de punto único del Riesgo Ordinario Grupo 1 es de 0.15 gpm/ft² sobre 1,500 ft² (diseño densidad/área de NFPA 13)."},
  {id:204, q:"El Riesgo Ordinario Grupo 2 se diseña más comúnmente con cuál densidad sobre 1,500 ft²?", opts:["0.40 gpm/ft²","0.15 gpm/ft²","0.10 gpm/ft²","0.20 gpm/ft²"], re:"El diseño de punto único del Riesgo Ordinario Grupo 2 es de 0.20 gpm/ft² sobre 1,500 ft² (diseño densidad/área de NFPA 13)."},
  {id:205, q:"En las curvas densidad/área de NFPA 13, a medida que el ÁREA DE DISEÑO seleccionada aumenta para un riesgo dado, la densidad requerida generalmente qué hace?", opts:["Aumenta","Disminuye","Permanece exactamente igual","Se duplica"], re:"Las curvas tienen pendiente de modo que un área remota mayor se combina con una densidad menor (y un área menor con una densidad mayor) para el mismo riesgo (concepto de curva densidad/área de NFPA 13)."},
  {id:206, q:"Un diseñador elige una densidad de 0.15 gpm/ft² sobre un área de diseño de 1,500 ft². La descarga mínima teórica de los ROCIADORES exigida sobre esa área suma cuánto (antes de manguera, fricción y sobredescarga)?", opts:["150 gpm","1,500 gpm","300 gpm","225 gpm"], re:"Densidad × área = 0.15 × 1,500 = 225 gpm es la descarga mínima de rociadores sobre el área de diseño (método densidad/área de NFPA 13)."},
  {id:207, q:"Para un diseño de Riesgo Extra Grupo 2 con 0.40 gpm/ft² sobre 2,500 ft², la descarga mínima de rociadores sobre el área de diseño es:", opts:["250 gpm","1,000 gpm","625 gpm","2,500 gpm"], re:"0.40 gpm/ft² × 2,500 ft² = 1,000 gpm de descarga mínima de rociadores sobre el área (método densidad/área de NFPA 13, Riesgo Extra)."},
  {id:208, q:"Dentro del método densidad/área, la descarga mínima requerida de un SOLO rociador es igual a:", opts:["El factor K multiplicado por el área de diseño","La densidad multiplicada por la superficie de piso que ese rociador protege","La asignación de manguera dividida por el número de cabezas","La presión estática multiplicada por 0.433"], re:"El caudal mínimo por rociador = densidad × el área de cobertura asignada a ese rociador (diseño densidad/área de NFPA 13)."},
  {id:209, q:"Un rociador cubre 130 ft² en un espacio diseñado a 0.15 gpm/ft². Su descarga mínima requerida es:", opts:["13.0 gpm","15.0 gpm","19.5 gpm","26.0 gpm"], re:"0.15 gpm/ft² × 130 ft² = 19.5 gpm de descarga mínima para ese rociador (método densidad/área de NFPA 13)."},
  {id:210, q:"Un rociador de Riesgo Ligero cubre 200 ft² con una densidad de diseño de 0.10 gpm/ft². Su descarga mínima requerida es:", opts:["10 gpm","20 gpm","30 gpm","200 gpm"], re:"0.10 gpm/ft² × 200 ft² = 20 gpm de descarga mínima para esa cabeza (método densidad/área de NFPA 13)."},
  {id:211, q:"En el método densidad/área, el área de diseño pretende representar cuál porción del sistema?", opts:["El área más cercana al montante","Todo el piso del edificio","El área hidráulicamente más remota/exigente","Solo los rociadores del pasillo"], re:"El área de diseño modela el grupo de rociadores hidráulicamente más remoto (exigente); si se satisface, las áreas más cercanas también lo están (método densidad/área de NFPA 13)."},
  {id:212, q:"¿Qué par de variables define un punto en una curva densidad/área de NFPA 13?", opts:["Presión y velocidad","Densidad y área de diseño","Factor K y elevación","Valor C y diámetro de tubería"], re:"Cada curva se traza con la densidad (gpm/ft²) en un eje y el área de diseño (ft²) en el otro (curvas densidad/área de NFPA 13)."},
  {id:213, q:"Si la descarga real de cada rociador en el área de diseño excede el mínimo requerido por la densidad, el diseñador debe usar:", opts:["Solo el caudal de densidad mínima","La mitad del caudal calculado","El caudal real (mayor) calculado en cada cabeza","El caudal del chorro de manguera"], re:"Los rociadores más cercanos a la fuente operan a mayor presión y descargan MÁS que el mínimo; el cálculo debe usar el caudal real de cada cabeza, nunca menos que el mínimo de densidad (cálculo hidráulico de NFPA 13)."},
  {id:214, q:"El método densidad/área asegura agua adecuada al garantizar un mínimo de:", opts:["Tasa de aplicación sobre un área de operación definida","Espesor de pared de tubería","Clasificación de temperatura del rociador","Número de válvulas de control de zona"], re:"Garantiza una densidad de aplicación mínima entregada sobre el área de diseño (de operación) elegida (método densidad/área de NFPA 13)."},
  {id:215, q:"Para ocupaciones de Riesgo Extra, el área de diseño máxima en las curvas es generalmente:", opts:["1,500 ft²","2,500 ft²","5,000 ft²","10,000 ft²"], re:"Las áreas de diseño de Riesgo Extra llegan hasta cerca de 2,500 ft² en las curvas densidad/área (densidad/área de NFPA 13, Riesgo Extra)."},
  {id:216, q:"Comparada con el Riesgo Ligero, una ocupación de Riesgo Extra requiere:", opts:["Menor densidad y área más pequeña","Mayor densidad y una mayor demanda de agua","La misma densidad pero menor presión","Ningún cálculo hidráulico"], re:"El Riesgo Extra usa densidades mucho mayores (0.30–0.40 gpm/ft²) y una demanda total mayor que el Riesgo Ligero (~0.10) (clasificaciones de riesgo de NFPA 13)."},
  {id:217, q:"La densidad de operación mínima elegida para un diseño debe ser al menos el valor requerido para la:", opts:["Color del edificio","Clasificación del riesgo de la ocupación","Logotipo del fabricante del rociador","Tarifa local de la factura de agua"], re:"La densidad requerida se establece por la clasificación del riesgo de la ocupación (Ligero, Ordinario, Extra) (método densidad/área de NFPA 13)."},
  {id:218, q:"La ecuación básica de descarga del rociador es:", opts:["Q = K × P","Q = K ÷ P","Q = K × √P","Q = P × √K"], re:"El caudal del rociador Q (gpm) = K√P, donde P es la presión en el orificio en psi (cálculo hidráulico de NFPA 13; fórmula del factor K)."},
  {id:219, q:"En Q = K√P, las unidades de Q y P son normalmente:", opts:["Q en cfm y P en pulgadas de agua","Q en psi y P en gpm","Q en gpm y P en psi","Q en litros y P en bar"], re:"En la práctica estadounidense de rociadores, Q está en galones por minuto (gpm) y P en libras por pulgada cuadrada (psi) (cálculo hidráulico de NFPA 13)."},
  {id:220, q:"Un rociador de pulverización de orificio estándar (1/2 pulg.) tiene un factor K nominal más cercano a:", opts:["2.8","5.6","11.2","25.2"], re:"El rociador de pulverización de orificio estándar de 1/2 pulg. tiene un K nominal de 5.6 (NFPA 13; factor K del rociador de pulverización estándar)."},
  {id:221, q:"Un rociador K=5.6 opera a 25 psi. Su descarga es:", opts:["28.0 gpm","14.0 gpm","56.0 gpm","140 gpm"], re:"Q = 5.6×√25 = 5.6×5 = 28.0 gpm (Q=K√P, NFPA 13)."},
  {id:222, q:"Un rociador K=8.0 opera a 25 psi. Su descarga es:", opts:["40.0 gpm","32.0 gpm","20.0 gpm","64.0 gpm"], re:"Q = 8.0×√25 = 8.0×5 = 40.0 gpm (Q=K√P, NFPA 13)."},
  {id:223, q:"Un rociador K=11.2 opera a 25 psi. Su descarga es:", opts:["44.8 gpm","50.0 gpm","112 gpm","56.0 gpm"], re:"Q = 11.2×√25 = 11.2×5 = 56.0 gpm (Q=K√P, NFPA 13)."},
  {id:224, q:"Para hallar la presión cuando se conocen el caudal y K, se reordena a:", opts:["P = (Q/K)²","P = Q×K","P = K/Q²","P = √(Q×K)"], re:"Resolviendo Q=K√P para P se obtiene P = (Q/K)² (cálculo hidráulico de NFPA 13)."},
  {id:225, q:"Una cabeza K=5.6 debe descargar 28 gpm. La presión requerida es:", opts:["5 psi","25 psi","20 psi","50 psi"], re:"P = (Q/K)² = (28/5.6)² = 5² = 25 psi (cálculo hidráulico de NFPA 13)."},
  {id:226, q:"Una cabeza K=8.0 debe descargar 40 gpm. La presión requerida es:", opts:["16 psi","20 psi","40 psi","25 psi"], re:"P = (Q/K)² = (40/8.0)² = 5² = 25 psi (cálculo hidráulico de NFPA 13)."},
  {id:227, q:"NFPA 13 establece una presión de operación mínima para la mayoría de los rociadores de pulverización estándar de:", opts:["7 psi","3 psi","15 psi","20 psi"], re:"La presión de operación mínima para los rociadores de pulverización estándar es de 7 psi (presión de operación mínima de NFPA 13)."},
  {id:228, q:"Un rociador K=5.6 a la presión mínima de NFPA 13 de 7 psi descarga aproximadamente:", opts:["11.2 gpm","28.0 gpm","19.6 gpm","14.8 gpm"], re:"Q = 5.6×√7 = 5.6×2.646 ≈ 14.8 gpm (Q=K√P, NFPA 13)."},
  {id:229, q:"Si sabe que un rociador da un caudal de 30 gpm a 25 psi, su factor K es:", opts:["6.0","1.2","7.5","30"], re:"K = Q/√P = 30/√25 = 30/5 = 6.0 (cálculo hidráulico de NFPA 13)."},
  {id:230, q:"El factor K de un rociador depende principalmente de su:", opts:["Tamaño y geometría del orificio de descarga","Color del bastidor","Solo la clasificación de temperatura","Distancia desde el montante"], re:"K queda fijado por la geometría del orificio/boquilla y es una constante para ese modelo de rociador (NFPA 13; listado del fabricante)."},
  {id:231, q:"Duplicar la presión en un rociador cambia su caudal por un factor de aproximadamente:", opts:["2.0","1.41","4.0","0.5"], re:"Como Q∝√P, duplicar P multiplica el caudal por √2 ≈ 1.41, no por 2 (relación Q=K√P)."},
  {id:232, q:"Para DUPLICAR la descarga de un rociador, la presión debe aumentarse por un factor de:", opts:["2","√2","4","8"], re:"Q∝√P, por lo que duplicar Q requiere 2² = 4 veces la presión (relación Q=K√P)."},
  {id:233, q:"Un rociador de orificio grande tipo ESFR K=25.2 a 50 psi descarga aproximadamente:", opts:["126 gpm","1,260 gpm","252 gpm","178 gpm"], re:"Q = 25.2×√50 = 25.2×7.071 ≈ 178 gpm (Q=K√P; listado K=25.2)."},
  {id:234, q:"Dos rociadores idénticos en el mismo ramal descargan caudales diferentes porque tienen diferentes:", opts:["Presiones de operación","Factores K","Clasificaciones de temperatura","Tamaños de rosca"], re:"Las cabezas idénticas comparten el mismo K, por lo que un caudal diferente resulta de una presión de operación diferente a lo largo de la tubería (Q=K√P, cálculo hidráulico de NFPA 13)."},
  {id:235, q:"¿Qué ecuación especifica NFPA 13 para la pérdida por fricción en tubería en los cálculos de sistemas a base de agua?", opts:["Darcy-Weisbach","Bernoulli","Hazen-Williams","Manning"], re:"NFPA 13 obliga a usar la fórmula de Hazen-Williams para la pérdida por fricción en los cálculos hidráulicos de rociadores contra incendios (cálculo hidráulico de NFPA 13)."},
  {id:236, q:"La fórmula de pérdida por fricción de Hazen-Williams de NFPA 13 es p = 4.52×Q^1.85 / (C^1.85 × d^4.87). El término 'C' representa:", opts:["La circunferencia de la tubería","El coeficiente de rugosidad/fricción interior de la tubería","El costo por pie","El contenido de cloro"], re:"C es el coeficiente de pérdida por fricción de Hazen-Williams que describe la lisura interior de la tubería (fórmula de Hazen-Williams de NFPA 13)."},
  {id:237, q:"En la fórmula de Hazen-Williams p = 4.52 Q^1.85/(C^1.85 d^4.87), 'p' es:", opts:["La presión total de la bomba","La velocidad en ft/s","La pérdida por fricción por pie de tubería (psi/ft)","La carga de elevación"], re:"p es la resistencia por fricción por pie de tubería, en psi por pie (fórmula de Hazen-Williams de NFPA 13)."},
  {id:238, q:"En la fórmula de Hazen-Williams, el diámetro 'd' a usar es el de la tubería:", opts:["El diámetro nominal","El diámetro exterior","El diámetro de la rosca","El diámetro interno real"], re:"d es el diámetro interno real de la tubería en pulgadas, no el tamaño nominal (fórmula de Hazen-Williams de NFPA 13)."},
  {id:239, q:"El valor C de Hazen-Williams usado típicamente para tubería de ACERO negro o galvanizado nueva (sin revestimiento) en sistemas secos/de preacción de NFPA 13 y como base de la tabla es:", opts:["100","150","140","120"], re:"C = 120 es el valor de Hazen-Williams comúnmente asignado a la tubería de acero y es la base de la tabla de longitud equivalente de NFPA 13 (tabla de valores C de NFPA 13)."},
  {id:240, q:"El valor C de Hazen-Williams asignado al tubo de COBRE y a la tubería de CPVC/plástico es:", opts:["100","120","150","130"], re:"Al tubo de cobre y a la tubería de CPVC/plástico se les asigna C = 150 (interior más liso) (tabla de valores C de NFPA 13)."},
  {id:241, q:"Un valor C de Hazen-Williams más alto indica una tubería que produce:", opts:["Mayor pérdida por fricción","Menor pérdida por fricción","Ningún caudal","Mayor pérdida por elevación"], re:"Un C más alto significa un interior más liso y, por tanto, MENOR pérdida por fricción para el mismo caudal (relación de Hazen-Williams)."},
  {id:242, q:"En la fórmula de Hazen-Williams, la pérdida por fricción aumenta con el caudal Q elevado a la potencia:", opts:["1.0","4.87","2.0","1.85"], re:"La pérdida por fricción varía con Q^1.85 en la ecuación de Hazen-Williams (fórmula de Hazen-Williams de NFPA 13)."},
  {id:243, q:"En la fórmula de Hazen-Williams, la pérdida por fricción es extremadamente sensible al diámetro, variando inversamente con d elevado a cerca de:", opts:["1.85","2.63","0.54","4.87"], re:"La pérdida por fricción varía como 1/d^4.87, por lo que pequeños cambios de diámetro tienen un gran efecto (fórmula de Hazen-Williams de NFPA 13)."},
  {id:244, q:"¿Qué opción, por sí sola, reduciría MÁS la pérdida por fricción para un caudal dado?", opts:["Usar una tubería con un diámetro interno ligeramente mayor","Agregar más accesorios","Bajar el valor C","Aumentar la longitud de la tubería"], re:"Como la pérdida ∝ 1/d^4.87, aumentar el diámetro tiene el efecto más fuerte de reducción de pérdida (fórmula de Hazen-Williams)."},
  {id:245, q:"La pérdida por fricción total en una longitud de tubería es igual a:", opts:["p multiplicado por el valor C","p dividido por la longitud de la tubería","p (psi/ft) multiplicado por la longitud de la tubería en pies","p multiplicado por el factor K"], re:"Pérdida por fricción total = p (psi/ft) × longitud (ft), donde la longitud incluye la longitud equivalente de los accesorios (cálculo hidráulico de NFPA 13)."},
  {id:246, q:"Para 100 gpm en acero Schedule 40 de 1 pulg. (d = 1.049 pulg., C = 120), la pérdida por fricción es la más cercana a:", opts:["0.26 psi/ft","25 psi/ft","9.1 psi/ft","2.56 psi/ft"], re:"p = 4.52×100^1.85/(120^1.85×1.049^4.87) ≈ 2.56 psi/ft (fórmula de Hazen-Williams de NFPA 13, recalculada)."},
  {id:247, q:"Mover los MISMOS 100 gpm de acero Schedule 40 de 1 pulg. a 2 pulg. (d ≈ 2.067 pulg.) cambia la pérdida por fricción de cerca de 2.56 psi/ft a aproximadamente:", opts:["5.0 psi/ft","1.3 psi/ft","2.5 psi/ft","0.09 psi/ft"], re:"p = 4.52×100^1.85/(120^1.85×2.067^4.87) ≈ 0.09 psi/ft — una gran caída por el aumento de diámetro (Hazen-Williams de NFPA 13, recalculada)."},
  {id:248, q:"Reducir a la mitad el caudal Q en una tubería cambia la pérdida por fricción de Hazen-Williams a aproximadamente:", opts:["La mitad de la original","Un cuarto de la original","Cerca del 28% de la original","La misma que la original"], re:"(1/2)^1.85 ≈ 0.277, por lo que la pérdida cae a aproximadamente el 28% de la original cuando el caudal se reduce a la mitad (término Q^1.85 de Hazen-Williams)."},
  {id:249, q:"A la tubería de hierro fundido/dúctil con revestimiento de cemento generalmente se le asigna un valor C de Hazen-Williams de:", opts:["140","120","100","180"], re:"Al hierro fundido o dúctil con revestimiento de cemento se le asigna comúnmente C = 140 (tabla de valores C de NFPA 13)."},
  {id:250, q:"Al hierro fundido sin revestimiento y a la tubería más antigua/rugosa se les puede asignar un valor C de Hazen-Williams tan bajo como:", opts:["150","130","100","180"], re:"A la tubería ferrosa sin revestimiento/envejecida se le asigna un C más bajo como 100, reflejando mayor fricción (tabla de valores C de NFPA 13)."},
  {id:251, q:"En la fórmula de Hazen-Williams, si el valor C usado es demasiado ALTO (la tubería se asume más lisa que en la realidad), la pérdida por fricción calculada será:", opts:["Demasiado baja (no conservadora)","Demasiado alta (conservadora)","Sin afectar","Exactamente correcta"], re:"Un valor C más alto que el real subestima la pérdida por fricción, dando un resultado no conservador (optimista) (término C de Hazen-Williams)."},
  {id:252, q:"En un cálculo hidráulico nodo por nodo, un 'nodo' es:", opts:["Solo la base del montante","Cualquier tramo recto de tubería","Un punto donde el tamaño, el caudal o la dirección de la tubería cambia (p. ej., un accesorio o un rociador)","Solo la bomba"], re:"Los nodos son puntos de referencia —rociadores, accesorios, tes, cambios de tamaño— entre los cuales se calcula la pérdida por fricción (procedimiento de cálculo hidráulico de NFPA 13)."},
  {id:253, q:"Los cálculos hidráulicos normalmente se realizan comenzando desde:", opts:["El suministro de agua hacia el rociador más remoto","El rociador más remoto de vuelta hacia el suministro","El centro del sistema hacia afuera","Solo la descarga de la bomba"], re:"Los cálculos comienzan en el rociador más remoto (hidráulicamente menos favorable) y proceden de vuelta hacia la fuente, acumulando caudal y presión (cálculo hidráulico de NFPA 13)."},
  {id:254, q:"A medida que avanza desde el rociador del extremo de vuelta hacia el montante, el caudal acumulado en la tubería:", opts:["Disminuye","Permanece constante","Aumenta a medida que cada rociador agrega su caudal","Cae a cero en cada te"], re:"Cada rociador aguas abajo agrega su descarga, por lo que el caudal total crece hacia el suministro (cálculo hidráulico de NFPA 13)."},
  {id:255, q:"Cuando dos trayectorias de flujo se encuentran en un nodo de unión común a presiones calculadas diferentes, la regla correcta es:", opts:["Promediar las dos presiones","Sumar las dos presiones","Usar la presión menor e ignorar la otra","Usar la mayor de las dos presiones y reequilibrar el caudal de la trayectoria de menor presión"], re:"La presión de unión más alta gobierna; el ramal de menor presión debe recalcularse hasta esa presión para equilibrar el nodo (cálculo hidráulico de NFPA 13; equilibrio de uniones)."},
  {id:256, q:"Para elevar el caudal de un ramal desde su valor calculado Q a la presión P_low hasta una presión de unión mayor P_high, el caudal equilibrado es:", opts:["Q × (P_high/P_low)","Q × √(P_high/P_low)","Q × (P_low/P_high)","Q ÷ √(P_high/P_low)"], re:"Como Q∝√P para esa trayectoria, el caudal ajustado = Q×√(P_high/P_low) (equilibrio de uniones de NFPA 13)."},
  {id:257, q:"Se calcula que un ramal entrega 25 gpm a 16 psi, pero la unión que encuentra está a 25 psi. El caudal equilibrado del ramal se vuelve:", opts:["20.0 gpm","25.0 gpm","31.25 gpm","40.0 gpm"], re:"Q_adj = 25×√(25/16) = 25×1.25 = 31.25 gpm (equilibrio de uniones, Q∝√P)."},
  {id:258, q:"Equilibrar los caudales en una unión hace cumplir cuál principio físico?", opts:["Solo la conservación de la energía","La conservación de la masa/caudal — el caudal que entra es igual al que sale","Velocidad constante en todas partes","Igual longitud de tubería en todas las trayectorias"], re:"En cada nodo el caudal total que entra debe ser igual al total que sale (continuidad / conservación de la masa) (análisis de redes hidráulicas)."},
  {id:259, q:"En cualquier nodo individual, todas las tuberías conectadas a ese nodo comparten la misma:", opts:["Tasa de caudal","Valor C","Diámetro","Presión"], re:"Un nodo tiene una presión; cada trayectoria que se encuentra allí debe reconciliarse con esa presión común (concepto de nodo hidráulico)."},
  {id:260, q:"La presión total requerida en un nodo de referencia es igual a la suma de:", opts:["Pérdida por fricción, cambio de elevación y la presión inicial (aguas abajo)","Solo la pérdida por fricción","Solo el factor K","Velocidad por área"], re:"P en un nodo = presión aguas abajo + pérdida por fricción + cambio de elevación entre los nodos (cálculo hidráulico de NFPA 13)."},
  {id:261, q:"El cambio de elevación entre dos nodos se convierte a presión a una tasa de aproximadamente:", opts:["1.0 psi por pie","0.433 psi por pie de elevación","2.31 psi por pie","0.052 psi por pie"], re:"Cada pie de columna de agua ≈ 0.433 psi; la tubería ascendente agrega esto, la descendente lo recupera (presión de elevación de NFPA 13)."},
  {id:262, q:"Un nodo está 10 ft más alto que el que está debajo. La presión de elevación a agregar es:", opts:["1.0 psi","4.33 psi","10 psi","23.1 psi"], re:"0.433 psi/ft × 10 ft = 4.33 psi agregados por el ascenso (presión de elevación de NFPA 13)."},
  {id:263, q:"En un sistema reticulado (grid), el agua puede llegar a un rociador por múltiples trayectorias, lo que generalmente:", opts:["Aumenta la pérdida por fricción total","No requiere análisis de nodos","Hace innecesario el equilibrio","Reduce la pérdida por fricción frente a un sistema en árbol de la misma demanda"], re:"Las trayectorias paralelas en una rejilla dividen el caudal, reduciendo la velocidad y la pérdida por fricción en comparación con una sola trayectoria en árbol (sistemas reticulados de NFPA 13)."},
  {id:264, q:"La presión de velocidad (Pv) en la hidráulica de NFPA 13 se calcula como:", opts:["Pv = 0.001123 × Q² / d⁴","Pv = 0.433 × Q","Pv = 4.52 × Q^1.85","Pv = K×√P"], re:"NFPA 13 da la presión de velocidad Pv = 0.001123×Q²/d⁴ (psi), con Q en gpm y d en pulgadas (fórmula de presión de velocidad de NFPA 13)."},
  {id:265, q:"En la hidráulica de NFPA 13, la presión normal (Pn), la presión total (Pt) y la presión de velocidad (Pv) se relacionan por:", opts:["Pn = Pt + Pv","Pn = Pt − Pv","Pn = Pt × Pv","Pn = Pv − Pt"], re:"Presión normal Pn = Pt − Pv; la presión de velocidad se resta de la presión total (método de presión de velocidad de NFPA 13)."},
  {id:266, q:"Cuando se usa el método de presión de velocidad, el caudal de un rociador o ramal en un nodo se basa en la:", opts:["Presión total","Presión de elevación","Solo la presión de velocidad","Presión normal (Pt menos Pv)"], re:"La descarga es impulsada por la presión normal Pn (Pt − Pv); la presión de velocidad no produce caudal en el orificio (método de presión de velocidad de NFPA 13)."},
  {id:267, q:"A la mayoría de los cálculos hidráulicos de rociadores se les permite ignorar la presión de velocidad porque:", opts:["Solo se aplica a tuberías verticales (standpipes)","Siempre es mayor que la presión total","NFPA 13 prohíbe incluirla","Suele ser pequeña y su omisión es conservadora"], re:"La presión de velocidad es típicamente menor y despreciarla es conservador, por lo que NFPA 13 permite omitirla (la presión de velocidad de NFPA 13 es opcional)."},
  {id:268, q:"Después de equilibrar cada unión, la presión acumulada llevada de vuelta a la fuente representa la:", opts:["Presión estática de la red municipal","Presión de demanda del sistema en la fuente","Clasificación de temperatura del rociador","Espesor de pared de la tubería"], re:"La presión acumulada y equilibrada en la base del montante/fuente es la presión de demanda total del sistema que debe igualar el suministro (cálculo hidráulico de NFPA 13)."},
  {id:269, q:"Un gráfico de suministro de agua para el diseño de rociadores se traza en papel especial escalado de modo que la curva de suministro aparezca como:", opts:["Una línea recta (eje de caudal elevado a la potencia 1.85)","Una línea vertical","Un círculo perfecto","Una línea horizontal"], re:"El papel gráfico N^1.85 escala el eje de caudal a la potencia 1.85 de modo que la curva de suministro de Hazen-Williams se traza como una línea recta (gráfico hidráulico de NFPA 13; papel N1.85)."},
  {id:270, q:"En el gráfico hidráulico, la curva de SUMINISTRO DE AGUA muestra que, a medida que el caudal aumenta, la presión disponible:", opts:["Disminuye","Aumenta","Permanece constante","Se vuelve negativa de inmediato"], re:"Más caudal hace bajar el suministro: la presión residual cae a medida que el caudal sube, por lo que la curva de suministro desciende (curva de suministro basada en prueba de caudal)."},
  {id:271, q:"El sistema es adecuado cuando el punto de demanda cae:", opts:["Sobre o por debajo (dentro de) la curva de suministro","Por encima (fuera) de la curva de suministro","Exactamente en caudal cero","Solo en la presión estática"], re:"La demanda debe quedar sobre o por debajo de la curva de suministro disponible, lo que significa que el suministro puede entregar el caudal requerido a la presión requerida (demanda vs. suministro de NFPA 13)."},
  {id:272, q:"La brecha vertical entre la curva de suministro disponible y el punto de demanda al caudal de diseño se denomina:", opts:["Pérdida por fricción","Carga de elevación","Margen de seguridad (colchón)","Presión de velocidad"], re:"Esa diferencia de presión es el margen de seguridad o 'colchón' entre el suministro y la demanda (gráfico hidráulico de NFPA 13; margen de seguridad)."},
  {id:273, q:"Un margen de seguridad MÁS GRANDE entre el suministro y la demanda generalmente indica:", opts:["Un suministro de agua apenas adecuado","Mayor capacidad de reserva y tolerancia a la fluctuación del suministro","Una red de agua subdimensionada","Un cálculo fallido"], re:"Un colchón mayor significa que el suministro supera cómodamente la demanda, dando reserva ante el deterioro o la fluctuación (concepto de margen de seguridad de NFPA 13)."},
  {id:274, q:"En una prueba de caudal, la presión 'estática' es la presión medida en:", opts:["Caudal máximo","Régimen muerto de la bomba (churn)","20 psi residual","Caudal cero (ningún hidrante fluyendo)"], re:"La presión estática se lee sin agua fluyendo (caudal cero) (terminología de NFPA 291 / prueba de caudal)."},
  {id:275, q:"En una prueba de caudal, la presión 'residual' es la presión medida:", opts:["Sin caudal","Después de que termina la prueba","Mientras fluye una cantidad conocida de agua","Solo en la bomba"], re:"La presión residual es la presión que queda en el sistema mientras se descarga un caudal medido (terminología de prueba de caudal)."},
  {id:276, q:"Trazar la curva de suministro en papel N1.85 es útil porque le permite al diseñador:", opts:["Leer el caudal disponible a cualquier presión como una interpolación en línea recta","Evitar medir la presión","Eliminar la asignación de manguera","Ignorar la pérdida por fricción"], re:"Una curva de suministro en línea recta permite la interpolación gráfica simple del caudal disponible a cualquier presión (método gráfico N1.85)."},
  {id:277, q:"La DEMANDA total del sistema trazada en el gráfico debe incluir:", opts:["Solo el caudal de los rociadores","Solo la presión estática","Solo la asignación de manguera","El caudal de los rociadores más la asignación requerida de chorro de manguera"], re:"Demanda del sistema = descarga de rociadores sobre el área de diseño MÁS la asignación de chorro de manguera (cálculo de demanda de NFPA 13)."},
  {id:278, q:"Si el punto de demanda se traza POR ENCIMA de la curva de suministro, el diseñador debe:", opts:["Aumentar el suministro (p. ej., una bomba) o reducir la demanda (tubería más grande) hasta que la demanda quepa bajo la curva","No hacer nada; pasa","Bajar solo la densidad","Eliminar la asignación de manguera"], re:"La demanda por encima del suministro significa que el suministro es inadecuado; o se aumenta el suministro o se reduce la demanda para que el punto caiga dentro de la curva (demanda vs. suministro de NFPA 13)."},
  {id:279, q:"Una razón común por la que una curva de suministro se proyecta hasta 20 psi es que:", opts:["20 psi es la presión máxima permitida","Los códigos comúnmente exigen evaluar el caudal de incendio disponible a 20 psi residual","Los rociadores no pueden fluir por debajo de 20 psi","20 psi es la presión estática"], re:"El caudal de incendio se reporta convencionalmente como el caudal disponible a 20 psi residual, según la práctica del código contra incendios (convención de caudal de incendio de NFPA 291 / código contra incendios)."},
  {id:280, q:"En el gráfico, una curva de suministro con pendiente pronunciada (que cae rápidamente) indica un suministro que es:", opts:["Fuerte con poca pérdida de presión bajo caudal","Independiente del caudal","Débil — la presión cae rápidamente a medida que el caudal aumenta","Siempre adecuado"], re:"Una pendiente descendente pronunciada significa que la presión residual colapsa rápidamente con el caudal, indicando un suministro comparativamente débil (interpretación de la curva de suministro)."},
  {id:281, q:"Si se agrega una bomba contra incendios, en el gráfico hidráulico el efecto es:", opts:["Bajar toda la curva de suministro","Elevar la curva de suministro hacia arriba, agregando presión a un caudal dado","Eliminar la curva de demanda","Aplanar la demanda a cero"], re:"Una bomba agrega carga, desplazando la curva de suministro disponible hacia arriba y aumentando el margen sobre la demanda (concepto de suministro reforzado/bomba)."},
  {id:282, q:"El punto donde la demanda del sistema y el suministro disponible apenas se encuentran (sin colchón restante) significa que el margen de seguridad es:", opts:["Cero","Maximizado","Negativo","Igual a la presión estática"], re:"Si la demanda iguala exactamente al suministro, el colchón/margen de seguridad es cero — la condición mínima aceptable (definición de margen de seguridad)."},
  {id:283, q:"El eje horizontal del gráfico hidráulico estándar de rociadores representa:", opts:["Tiempo (s)","Presión (psi)","Caudal (gpm)","Elevación (ft)"], re:"El caudal en gpm está en el eje horizontal (escalado a la potencia 1.85); la presión está en el eje vertical (gráfico N1.85)."},
  {id:284, q:"El eje vertical del gráfico hidráulico estándar de rociadores representa:", opts:["Caudal (gpm)","Valor C","Presión (psi)","Diámetro de tubería"], re:"La presión en psi se traza en el eje vertical del gráfico hidráulico (gráfico N1.85)."},
  {id:285, q:"Una razón práctica por la que los diseñadores prefieren un margen de seguridad generoso es para tener en cuenta:", opts:["Clasificaciones de temperatura más bajas","Colores de rociador más brillantes","Tramos de tubería más cortos","El futuro engrosamiento por rugosidad de la tubería, la caída estacional del suministro y un error menor en la prueba de caudal"], re:"El margen cubre el deterioro del suministro con el tiempo, la variación de presión estacional/diurna y la inexactitud de la prueba (justificación de ingeniería del margen de seguridad)."},
  {id:286, q:"La DEMANDA total del sistema de rociadores que debe suministrarse es la suma de:", opts:["La descarga de rociadores sobre el área de diseño más la asignación de chorro de manguera","La presión estática más la presión residual","El factor K más el valor C","Solo la elevación más la velocidad"], re:"Demanda = caudal calculado de rociadores sobre el área de diseño + la asignación requerida de chorro de manguera interior/exterior (demanda de agua de NFPA 13)."},
  {id:287, q:"La asignación de chorro de manguera para una ocupación de Riesgo Ligero es típicamente:", opts:["250 gpm","100 gpm","500 gpm","1,000 gpm"], re:"La asignación de chorro de manguera para Riesgo Ligero es de 100 gpm (tabla de chorro de manguera/suministro de agua de NFPA 13)."},
  {id:288, q:"La asignación de chorro de manguera para una ocupación de Riesgo Ordinario es típicamente:", opts:["100 gpm","500 gpm","250 gpm","750 gpm"], re:"La asignación de chorro de manguera para Riesgo Ordinario es de 250 gpm (tabla de chorro de manguera/suministro de agua de NFPA 13)."},
  {id:289, q:"La asignación de chorro de manguera para una ocupación de Riesgo Extra es típicamente:", opts:["100 gpm","500 gpm","250 gpm","2,000 gpm"], re:"La asignación de chorro de manguera para Riesgo Extra es de 500 gpm (tabla de chorro de manguera/suministro de agua de NFPA 13)."},
  {id:290, q:"En la demanda del sistema, la asignación de chorro de manguera generalmente se agrega a la demanda de rociadores en cuál punto?", opts:["En el punto de conexión al suministro (p. ej., base del montante o red municipal)","En cada rociador","Solo en la cabeza más remota","Nunca se agrega"], re:"La asignación de manguera se agrega donde se tomaría —típicamente la base del montante/conexión de suministro— no en los rociadores (aplicación de asignación de manguera de NFPA 13)."},
  {id:291, q:"La DURACIÓN requerida del suministro de agua para una ocupación de Riesgo Ligero es del orden de:", opts:["90 minutos","60 minutos","30 minutos","8 horas"], re:"La duración del suministro de agua para Riesgo Ligero es del orden de 30 minutos (tabla de duración del suministro de agua de NFPA 13)."},
  {id:292, q:"La DURACIÓN requerida del suministro de agua para una ocupación de Riesgo Extra es del orden de:", opts:["90–120 minutos","60 minutos","30 minutos","10 minutos"], re:"La duración del suministro de agua para Riesgo Extra es del orden de 90–120 minutos — más larga que la de riesgos menores (tabla de duración del suministro de agua de NFPA 13)."},
  {id:293, q:"Una prueba de caudal de hidrante contra incendios se usa en el diseño de rociadores principalmente para:", opts:["Determinar la altura del edificio","Establecer la clasificación de temperatura del rociador","Elegir el color de la tubería","Establecer la curva de suministro de agua disponible"], re:"La prueba de caudal define el suministro disponible (estática, residual y pendiente) usado para construir la curva de suministro (propósito de la prueba de caudal)."},
  {id:294, q:"'Caudal de incendio disponible a 20 psi' de una prueba de caudal significa:", opts:["La tubería es de 20 pulg. de diámetro","La presión estática es de 20 psi","El cierre de la bomba es de 20 psi","El caudal cuando la presión residual ha caído a 20 psi"], re:"Es el caudal proyectado que el suministro puede entregar manteniendo aún 20 psi residual (convención de caudal de incendio)."},
  {id:295, q:"Al comparar la demanda del sistema con la curva de suministro de agua, la demanda debe satisfacerse en:", opts:["La tasa de caudal de demanda requerida, no solo en caudal cero","Solo la presión estática (sin caudal)","El doble del caudal de demanda","Solo la presión de régimen muerto de la bomba (churn)"], re:"La adecuación se juzga en el punto de caudal de demanda — el suministro debe proporcionar la presión de demanda AL caudal de demanda (demanda vs. suministro de NFPA 13)."},
  {id:296, q:"Si un suministro de agua proporciona amplia presión estática pero su residual colapsa bajo caudal, el sistema puede aun así fallar porque:", opts:["El factor K cambia","La presión estática es irrelevante","La presión estática por sí sola no garantiza suficiente caudal en el punto de demanda","La elevación aumenta"], re:"Una estática alta con residual deficiente produce una curva pronunciada y débil; la demanda al caudal de diseño puede exceder la presión residual disponible (interpretación de la curva de suministro)."},
  {id:297, q:"Agregar la asignación de chorro de manguera a la demanda desplaza el punto de demanda del sistema en el gráfico:", opts:["Completamente fuera del gráfico","A caudal cero","Hacia abajo hasta la presión estática","A un caudal mayor (y por tanto mayor presión requerida en la curva de suministro)"], re:"El caudal de manguera aumenta el caudal de demanda total, moviendo el punto de demanda a la derecha/arriba a lo largo de la curva de suministro y reduciendo el colchón (acumulación de demanda de NFPA 13)."},
  {id:298, q:"Se necesitan dos puntos de prueba de caudal para definir la curva de suministro porque:", opts:["La ley exige dos hidrantes","Se requieren dos bombas","Un punto da la presión, un segundo establece la pendiente (caída de presión vs. caudal)","Un punto es la temperatura"], re:"La estática fija la presión a caudal cero; el punto de residual-a-caudal establece la pendiente de la curva, definiendo juntos el suministro (construcción de prueba de caudal / curva de suministro)."},
  {id:299, q:"Si el suministro de agua municipal por sí solo no puede satisfacer la demanda del sistema dentro del margen de seguridad, un remedio común es:", opts:["Agregar una bomba contra incendios y/o un tanque de almacenamiento para reforzar el suministro","Bajar la densidad requerida por debajo del código","Eliminar rociadores del área de diseño","Suprimir la asignación de manguera"], re:"Una bomba contra incendios y/o un tanque de almacenamiento de agua refuerza la curva de suministro disponible para satisfacer la demanda con margen (aumento del suministro según NFPA 13 / NFPA 20)."},
  {id:300, q:"La verificación FINAL de un diseño hidráulico de rociadores es que:", opts:["Todos los rociadores tienen presión idéntica","Cada tubería tiene el mismo diámetro","La demanda del sistema (incluida la manguera) cabe dentro del suministro de agua disponible con el margen de seguridad requerido","No se usan accesorios"], re:"La aceptación del diseño requiere que la demanda total más la manguera caiga dentro de la curva de suministro, dejando un margen de seguridad adecuado (verificación final de demanda vs. suministro de NFPA 13)."},
  {id:301, q:"NFPA 13 permite dos métodos básicos para dimensionar la tubería de un sistema de rociadores. Estos son:", opts:["El método de cédula de tubería y el método de cálculo hidráulico","El método de velocidad y el método de área","El método de fricción y el método de densidad","El método de gravedad y el método de presión"], re:"NFPA 13 dimensiona la tubería ya sea por el método de cédula de tubería (usando tablas prescriptivas de rociadores permitidos por tamaño de tubería) o por cálculo hidráulico. Ref: NFPA 13, capítulos de diseño de sistemas sobre sistemas por cédula de tubería y sistemas calculados hidráulicamente."},
  {id:302, q:"Según el método de cédula de tubería para una ocupación de Riesgo Ligero usando acero Schedule 40, una tubería de línea de ramal de 1 in. puede alimentar un máximo de cuántos rociadores?", opts:["1 rociador","2 rociadores","4 rociadores","6 rociadores"], re:"En la cédula de tubería de Riesgo Ligero de NFPA 13, 1 in. = 2 rociadores, 1-1/4 in. = 3, 1-1/2 in. = 5, 2 in. = 10. Ref: tabla de cédula de tubería de Riesgo Ligero de NFPA 13."},
  {id:303, q:"Según la cédula de tubería de Riesgo Ligero (acero Schedule 40), una tubería de 2 in. puede alimentar un máximo de cuántos rociadores?", opts:["5 rociadores","8 rociadores","10 rociadores","30 rociadores"], re:"Cédula de tubería de Riesgo Ligero de NFPA 13: 1-1/2 in. = 5, 2 in. = 10, 2-1/2 in. = 30. Ref: tabla de cédula de tubería de Riesgo Ligero de NFPA 13."},
  {id:304, q:"El método de cédula de tubería NO puede usarse para diseñar un sistema nuevo en cuál de las siguientes situaciones?", opts:["Cualquier sistema donde la demanda calculada esté por debajo del suministro disponible","Un edificio de oficinas de Riesgo Ligero","Cualquier sistema de tubería húmeda","Una ampliación de Riesgo Extra diseñada hidráulicamente o donde NFPA 13 limita su uso a sistemas existentes y ampliaciones pequeñas"], re:"NFPA 13 restringe el diseño por cédula de tubería en gran medida a sistemas existentes por cédula de tubería y ampliaciones limitadas; los sistemas nuevos generalmente deben calcularse hidráulicamente. Ref: limitaciones de los sistemas por cédula de tubería de NFPA 13."},
  {id:305, q:"En un sistema calculado hidráulicamente, la pérdida por fricción en la tubería se determina más comúnmente en NFPA 13 usando cuál fórmula?", opts:["La fórmula de Hazen-Williams","La ecuación de Darcy-Weisbach","La ecuación de energía de Bernoulli","La ecuación de Manning"], re:"Los cálculos hidráulicos de NFPA 13 usan la fórmula de Hazen-Williams para la pérdida por fricción en la tubería. Ref: procedimientos de cálculo hidráulico de NFPA 13 (Hazen-Williams)."},
  {id:306, q:"En la fórmula de Hazen-Williams aplicada por NFPA 13, la variable 'C' representa:", opts:["El área de la sección transversal de la tubería","El coeficiente de pérdida por fricción (rugosidad) de la superficie interior de la tubería","La velocidad del agua","La presión estática en la base del montante"], re:"'C' es el coeficiente de rugosidad de Hazen-Williams que describe la lisura relativa del interior de la tubería; un C menor significa tubería más rugosa y mayor pérdida por fricción. Ref: nomenclatura de la fórmula de Hazen-Williams de NFPA 13."},
  {id:307, q:"Qué valor C de Hazen-Williams asigna NFPA 13 a la tubería de acero negro o galvanizado nueva (sin revestir) para cálculos hidráulicos de rociadores contra incendios?", opts:["100","140","120","150"], re:"NFPA 13 asigna C = 120 a la tubería de acero negro y galvanizado en su tabla de valores C de Hazen-Williams. Ref: tabla de valores C de Hazen-Williams de NFPA 13."},
  {id:308, q:"Qué material de tubería tiene asignado el valor C de Hazen-Williams MÁS ALTO (más liso) en NFPA 13?", opts:["Tubería de acero negro (sistema seco), C = 100","Tubería de acero galvanizado, C = 120","Hierro fundido/dúctil revestido de cemento, C = 140","Plástico (CPVC) / tubo de cobre, C = 150"], re:"NFPA 13 asigna C = 150 al plástico (CPVC listado) y al tubo de cobre, los más lisos de los materiales comunes de rociadores. Ref: tabla de valores C de Hazen-Williams de NFPA 13."},
  {id:309, q:"NFPA 13 asigna un valor C de Hazen-Williams menor a los sistemas de tubería seca y de acción previa (acero negro). Ese valor es:", opts:["100","120","130","140"], re:"A la tubería de acero negro en servicio de tubería seca/acción previa se le asigna C = 100 para tener en cuenta la corrosión interna acelerada por el agua y aire intermitentes. Ref: tabla de valores C de Hazen-Williams de NFPA 13."},
  {id:310, q:"En la relación de pérdida de presión de Hazen-Williams usada por NFPA 13, la pérdida por fricción por unidad de longitud es más sensible a cuál variable?", opts:["Solo la longitud de la tubería","El caudal (Q), que se eleva a una potencia de aproximadamente 1.85","La elevación estática","El color de la tubería"], re:"En Hazen-Williams, la pérdida por fricción varía aproximadamente con Q^1.85 e inversamente con C^1.85 y diámetro^4.87; el caudal impulsa fuertemente la pérdida. Ref: fórmula de Hazen-Williams de NFPA 13."},
  {id:311, q:"Al convertir las pérdidas de accesorios y válvulas a tubería en un cálculo hidráulico, NFPA 13 exige que el diseñador agregue del accesorio su:", opts:["Longitud física real","Diámetro nominal","Longitud equivalente de tubería","Espesor de pared"], re:"La fricción de accesorios y válvulas se contabiliza agregando una longitud equivalente de tubería (de la tabla de longitud equivalente de NFPA 13) a la longitud real de la tubería. Ref: longitudes equivalentes de tubería de accesorios y válvulas de NFPA 13."},
  {id:312, q:"La tabla de longitud equivalente de accesorios de NFPA 13 se basa en tubería de acero Schedule 40 y un valor C de 120. Si la tubería real tiene un valor C diferente, la longitud equivalente tabulada debe:", opts:["Ignorarse por completo","Reemplazarse por el diámetro nominal","Duplicarse en todos los casos","Multiplicarse por un factor de ajuste para el valor C real"], re:"NFPA 13 exige multiplicar la longitud equivalente de la tabla por un ajuste del factor C (la tabla supone C = 120, Schedule 40). Ref: nota a la tabla de longitud equivalente de NFPA 13 sobre el ajuste del valor C."},
  {id:313, q:"Una ventaja fundamental del método de cálculo hidráulico sobre el método de cédula de tubería es que:", opts:["Adapta los tamaños de tubería a la demanda real y al suministro de agua disponible, permitiendo normalmente tubería más pequeña y económica","Elimina la necesidad de cualquier soporte/colgante","Elimina la necesidad de rociadores","Permite suponer cualquier valor C"], re:"El cálculo hidráulico ajusta los tamaños de tubería a la densidad/área requerida y a la curva real de suministro, generalmente produciendo tubería más pequeña y eficiente que las tablas conservadoras de cédula. Ref: base de diseño de sistemas calculados hidráulicamente de NFPA 13."},
  {id:314, q:"En NFPA 13, la velocidad del agua en la tubería afecta principalmente el diseño porque una mayor velocidad:", opts:["Reduce la pérdida por fricción","Aumenta la pérdida por fricción por pie de tubería","No tiene efecto sobre la presión","Aumenta el valor C de la tubería"], re:"Una mayor velocidad de flujo aumenta la pérdida por fricción; aunque NFPA 13 no limita la velocidad, los diseñadores la controlan porque una velocidad excesiva eleva la demanda de presión. Ref: principios de cálculo hidráulico de NFPA 13 (Hazen-Williams)."},
  {id:315, q:"Según la cédula de tubería de Riesgo Ordinario (acero Schedule 40), el número máximo de rociadores permitido en una tubería de línea de ramal de 1-1/4 in. es:", opts:["2","4","3","5"], re:"Cédula de tubería de Riesgo Ordinario de NFPA 13: 1 in. = 2, 1-1/4 in. = 3, 1-1/2 in. = 5, 2 in. = 10. Ref: tabla de cédula de tubería de Riesgo Ordinario de NFPA 13."},
  {id:316, q:"En un cálculo hidráulico de configuración en árbol, la pérdida por fricción se equilibra en puntos de referencia comunes de modo que:", opts:["Cada tubería transporte un caudal idéntico","Se ignore la elevación","Todos los rociadores fluyan exactamente el mínimo","Dos trayectorias que se encuentran en una unión se equilibren a la misma presión antes de sumar los caudales"], re:"En cada unión, las presiones de las trayectorias convergentes deben equilibrarse (igualarse, normalmente al valor mayor) antes de sumar sus caudales. Ref: procedimiento de cálculo hidráulico de NFPA 13 (equilibrio de presiones en las uniones)."},
  {id:317, q:"La presión normal (Pn), la presión de velocidad (Pv) y la presión total (Pt) se relacionan en los cálculos hidráulicos de NFPA 13 por:", opts:["Pt = Pn + Pv","Pt = Pn - Pv","Pn = Pt + Pv","Pv = Pt + Pn"], re:"La presión total es igual a la presión normal (estática) más la presión de velocidad: Pt = Pn + Pv. NFPA 13 permite, pero no exige, incluir la presión de velocidad. Ref: cálculo hidráulico de NFPA 13, disposiciones de presión de velocidad."},
  {id:318, q:"La tubería y el tubo de rociadores sobre el suelo usados según NFPA 13 generalmente deben ser:", opts:["Cualquier tubería disponible en el sitio","De un tipo específicamente permitido por NFPA 13 (p. ej., listado o que cumpla las normas ASTM/ASME referenciadas)","Solo acero inoxidable","Solo cobre"], re:"NFPA 13 limita la tubería/tubo sobre el suelo a materiales que cumplan las especificaciones referenciadas de la norma (como acero ASTM A53/A795, cobre ASTM B) o que estén específicamente listados. Ref: requisitos de tubería y tubo sobre el suelo de NFPA 13."},
  {id:319, q:"La tubería y accesorios de CPVC pueden usarse en un sistema de rociadores contra incendios solo cuando están:", opts:["Schedule 40 PVC de cualquier fabricante","Clasificados solo para agua potable","Listados para servicio de rociadores contra incendios e instalados según su listado","Pintados con pintura intumescente"], re:"Solo el CPVC específicamente listado para uso en rociadores contra incendios puede instalarse, y debe seguir las limitaciones del listado (p. ej., ocultamiento, separación de soportes, cemento solvente). El CPVC ASTM común no está automáticamente listado. Ref: requisitos de tubería no metálica / listado de NFPA 13."},
  {id:320, q:"Cuando la tubería de acero se une con accesorios roscados, NFPA 13 exige un espesor mínimo de pared correspondiente a:", opts:["Schedule 5","Schedule 10","Solo Schedule 80","Schedule 30 (8 in. y mayores) o Schedule 40 (menores de 8 in.)"], re:"El roscado requiere un espesor de pared de al menos Schedule 30 para 8 in. y mayores o Schedule 40 para tubería más pequeña; la pared más ligera (Schedule 10) no puede roscarse. Ref: requisitos de espesor de unión de tubería de acero (roscada) de NFPA 13."},
  {id:321, q:"La tubería de acero de pared delgada (Schedule 10) para rociadores es permitida por NFPA 13 solo cuando se une mediante:", opts:["Métodos listados como conexiones ranuradas por laminación o soldadas (no roscado)","Accesorios roscados","Cemento solvente","Acoplamientos de compresión"], re:"El Schedule 10 carece del espesor de pared para roscas cortadas, por lo que debe unirse mediante ranurado por laminación, soldadura u otros métodos listados. Ref: métodos de unión de tubería de acero y espesor mínimo de pared de NFPA 13."},
  {id:322, q:"La tubería unida mediante acoplamientos mecánicos ranurados debe usar:", opts:["Cualquier empaque a mano","Una combinación listada de accesorios, empaques y ranuras","Solo juntas soldadas","Reductores roscados"], re:"NFPA 13 exige que las juntas ranuradas se hagan con una combinación listada de accesorios, empaques y ranuras para garantizar compatibilidad e integridad. Ref: requisitos de accesorios/acoplamientos ranurados de NFPA 13."},
  {id:323, q:"El tubo de cobre usado en sistemas de rociadores suele unirse por soldadura fuerte (brazing) en lugar de soldadura blanda en muchas aplicaciones porque:", opts:["Las juntas con soldadura blanda no pueden retener agua","El cobre no puede soldarse","Las juntas con soldadura fuerte tienen mayor capacidad de temperatura/resistencia requerida para condiciones de incendio y listados","La soldadura fuerte solo es más rápida"], re:"Las juntas con soldadura fuerte proporcionan mayor resistencia y resistencia al fuego que la soldadura blanda 50/50; NFPA 13 referencia las normas de unión de cobre y los listados para estas juntas. Ref: disposiciones de unión de tubo de cobre de NFPA 13."},
  {id:324, q:"La soldadura de tubería de rociadores según NFPA 13 debe realizarse:", opts:["Por cualquier trabajador con un soplete","Solo en el taller, nunca en campo","Sin ninguna documentación","Usando soldadores/procedimientos calificados con soldaduras de penetración completa y aberturas cortadas por medios listados/aprobados"], re:"NFPA 13 exige procedimientos y soldadores calificados, soldaduras de penetración completa en las salidas de ramal, y que los discos/cupones se recuperen para que no obstruyan la tubería. Ref: disposiciones de tubería y accesorios soldados de NFPA 13."},
  {id:325, q:"Después de soldar una salida de ramal en una tubería principal, NFPA 13 exige que:", opts:["El cupón (disco) cortado se recupere y no se deje dentro de la tubería","El disco se deje dentro para reforzar la junta","La tubería se galvanice posteriormente","La salida se rosque"], re:"El cupón retirado al cortar la salida debe recuperarse; un disco dejado en la tubería podría obstruir el flujo hacia los rociadores. Ref: requisitos de salida soldada de NFPA 13 (recuperación de cupones)."},
  {id:326, q:"Qué norma es comúnmente referenciada por NFPA 13 para tubería de rociadores de acero negro y galvanizado por inmersión en caliente de peso ordinario?", opts:["ASTM D1785","ASTM A53 / ASTM A795","ASME B16.3","AWWA C151"], re:"NFPA 13 referencia ASTM A53 y ASTM A795 (y A135) para tubería de rociadores de acero. ASTM D1785 es para plástico PVC. Ref: especificaciones de tubería de acero referenciadas de NFPA 13."},
  {id:327, q:"Los accesorios usados en sistemas de rociadores deben:", opts:["Ser siempre de hierro fundido","Tener una clasificación de presión mayor a 1000 psi","Coincidir con el material/método de unión de la tubería y cumplir las normas referenciadas de NFPA 13 o estar listados","Fabricarse en campo"], re:"NFPA 13 exige que los accesorios cumplan las normas referenciadas (p. ej., serie ASME B16, listados UL) y sean compatibles con la tubería y el método de unión/presión. Ref: requisitos de accesorios de NFPA 13."},
  {id:328, q:"La clasificación de presión mínima para los componentes del sistema de rociadores (tubería, accesorios, válvulas) según los sistemas estándar de NFPA 13 es generalmente:", opts:["50 psi","100 psi","500 psi","175 psi (donde la presión máxima del sistema no la exceda)"], re:"NFPA 13 generalmente clasifica los componentes del sistema para al menos 175 psi donde la presión máxima de trabajo del sistema no exceda 175 psi; los sistemas de mayor presión requieren componentes clasificados acordemente. Ref: disposiciones de clasificación de presión de componentes de NFPA 13."},
  {id:329, q:"Los listados de tubería no metálica (CPVC) con frecuencia restringen su uso a cuál arreglo a menos que se liste de otra manera?", opts:["Sistemas de tubería húmeda e instalaciones ocultas/protegidas específicas según el listado","Expuesta en cualquier ocupación","Sistemas de tubería seca de Riesgo Extra","Solo subterránea"], re:"Los listados de CPVC comúnmente limitan el uso a sistemas de tubería húmeda y requieren ocultamiento o protección específica (membrana, llena de agua) excepto donde el listado permita uso expuesto. Ref: limitaciones del listado de producto de NFPA 13 / CPVC."},
  {id:330, q:"Cuando se unen metales disímiles como tubo de cobre y tubería de acero, el diseñador debe atender:", opts:["Reducción del valor C a 50","La corrosión galvánica (uso de accesorios dieléctricos/de transición listados)","La soldadura obligatoria","Duplicar la separación de soportes"], re:"Unir cobre a acero puede causar corrosión galvánica; se usan uniones dieléctricas o accesorios de transición listados para mitigarla. Ref: NFPA 13 / buena práctica sobre conexiones de metales disímiles."},
  {id:331, q:"La tubería de acero Schedule 10 ranurada por laminación es permitida por NFPA 13 para presiones de hasta:", opts:["100 psi","175 psi","300 psi","1000 psi"], re:"NFPA 13 permite acero Schedule 10 ranurado por laminación (en los tamaños aplicables) para sistemas con presiones de hasta 300 psi, con un espesor mínimo de pared especificado para tamaños mayores. Ref: disposiciones de espesor de pared/presión de tubería de acero (ranurada por laminación) de NFPA 13."},
  {id:332, q:"La tubería de acero galvanizado a veces se prefiere sobre el acero negro en sistemas secos y de acción previa porque la galvanización:", opts:["Aumenta el valor C a 150","Elimina la necesidad de soportes/colgantes","Permite juntas soldadas con soldadura blanda","Proporciona cierta resistencia adicional a la corrosión interna contra el agua/condensado atrapado"], re:"La galvanización agrega resistencia a la corrosión interna, útil donde el condensado y el agua intermitente aceleran la corrosión en sistemas secos/de acción previa. Ref: disposiciones de material de tubería de NFPA 13 / consideraciones de corrosión."},
  {id:333, q:"Una tubería o componente que está 'listado' según NFPA 13 significa que ha sido:", opts:["Evaluado por un laboratorio de pruebas reconocido y publicado como que cumple las normas apropiadas para su uso previsto","Aprobado solo por el instalador","Fabricado en el extranjero","Usado previamente en otro trabajo"], re:"'Listado' significa que un laboratorio de pruebas reconocido a nivel nacional ha evaluado el producto y lo ha publicado como que cumple la norma pertinente para el uso previsto de protección contra incendios. Ref: definiciones de listado/aprobado de NFPA 13."},
  {id:334, q:"El acero inoxidable y ciertos otros materiales especiales de tubería pueden usarse en sistemas de rociadores cuando:", opts:["Nunca está permitido","Estén listados o específicamente permitidos y unidos por métodos consistentes con NFPA 13 y el listado","Solo para tuberías principales subterráneas","Pintados para parecer acero"], re:"Los materiales especiales (p. ej., acero inoxidable) son aceptables donde cumplen las especificaciones referenciadas o están listados y se unen por métodos listados apropiados. Ref: disposiciones de tubería/tubo sobre el suelo y materiales especiales de NFPA 13."},
  {id:335, q:"En los cálculos hidráulicos de NFPA 13, la longitud equivalente asignada a un accesorio representa:", opts:["La dimensión física cara a cara del accesorio","El tamaño nominal de la tubería","La longitud de tubería recta que produciría la misma pérdida por fricción que el accesorio","La clasificación de presión del accesorio"], re:"La longitud equivalente es la longitud de tubería recta del mismo diámetro que produce la misma pérdida por fricción que el accesorio. Ref: longitud equivalente de tubería de accesorios y válvulas de NFPA 13."},
  {id:336, q:"La tabla de longitud equivalente de NFPA 13 está normalizada a cuál tubería y valor C?", opts:["Acero Schedule 80, C = 100","Cobre, C = 150","Hierro fundido, C = 140","Acero Schedule 40, C = 120"], re:"La tabla de longitud equivalente de accesorios se basa en tubería de acero Schedule 40 y C = 120; se requieren ajustes para otros valores C. Ref: base de la tabla de longitud equivalente de NFPA 13."},
  {id:337, q:"Para un codo estándar de 90 grados de acero Schedule 40 de 2 in., la tabla de NFPA 13 da una longitud equivalente de aproximadamente:", opts:["5 ft","1 ft","12 ft","20 ft"], re:"NFPA 13 lista un codo estándar de 90 grados de 2 in. en aproximadamente 5 ft de longitud equivalente. Ref: tabla de longitud equivalente de tubería de accesorios y válvulas de NFPA 13."},
  {id:338, q:"Comparado con un codo estándar de 90 grados del mismo tamaño, un codo de 90 grados de giro largo (barrido) tiene una longitud equivalente que es:", opts:["Mayor","Menor","Idéntica","Siempre cero"], re:"Un codo de giro largo/barrido produce menos turbulencia, por lo que su longitud equivalente es menor que la de un codo estándar de 90 grados del mismo tamaño. Ref: tabla de longitud equivalente de NFPA 13 (codo estándar vs. de giro largo)."},
  {id:339, q:"Cuando el flujo pasa directamente A TRAVÉS del paso recto de una tee o cruz (sin cambio de dirección), la longitud equivalente que se carga en NFPA 13 es:", opts:["El valor completo del ramal (giro)","Siempre 60 ft","Cero o no contada como un giro (solo a la trayectoria del ramal/giro se le carga el valor de la tee)","La misma que una válvula de compuerta"], re:"El flujo que pasa directamente a través del paso recto de una tee/cruz no se carga con pérdida de accesorio; solo al flujo que gira 90 grados a través del ramal se le asigna la longitud equivalente de la tee. Ref: notas de la tabla de longitud equivalente de NFPA 13 sobre tees y cruces."},
  {id:340, q:"Para una válvula de compuerta de 2 in. completamente abierta, la longitud equivalente de NFPA 13 es aproximadamente:", opts:["6 ft","9 ft","15 ft","1 ft"], re:"Una válvula de compuerta completamente abierta tiene una pérdida muy baja; NFPA 13 lista aproximadamente 1 ft de longitud equivalente para 2 in. Ref: tabla de longitud equivalente de NFPA 13 (válvula de compuerta)."},
  {id:341, q:"Una válvula de mariposa de 2 in. tiene una longitud equivalente en NFPA 13 de aproximadamente:", opts:["6 ft","1 ft","20 ft","40 ft"], re:"Una válvula de mariposa de 2 in. se lista en aproximadamente 6 ft de longitud equivalente porque el disco permanece en la trayectoria del flujo. Ref: tabla de longitud equivalente de NFPA 13 (válvula de mariposa)."},
  {id:342, q:"Una válvula de retención de columpio de 2 in. tiene una longitud equivalente en NFPA 13 de aproximadamente:", opts:["1 ft","9 ft","3 ft","27 ft"], re:"Una válvula de retención de columpio de 2 in. se lista en aproximadamente 9 ft de longitud equivalente. Ref: tabla de longitud equivalente de NFPA 13 (válvula de retención de columpio)."},
  {id:343, q:"Entre los siguientes accesorios/válvulas de 2 in., cuál tiene generalmente la MAYOR longitud equivalente (mayor pérdida por fricción)?", opts:["Válvula de compuerta completamente abierta","Codo estándar de 90 grados","Válvula de retención de columpio","Codo de 45 grados"], re:"De estos, la válvula de retención de columpio (~9 ft para 2 in.) tiene la mayor longitud equivalente; la válvula de compuerta es la menor (~1 ft). Ref: tabla de longitud equivalente de NFPA 13."},
  {id:344, q:"A medida que aumenta el tamaño nominal de la tubería, la longitud equivalente de un tipo de accesorio dado (p. ej., un codo de 90 grados) generalmente:", opts:["Disminuye","Permanece exactamente igual","Se vuelve negativa","Aumenta"], re:"Los accesorios más grandes tienen mayores longitudes equivalentes; p. ej., un codo de 90 grados crece de ~2 ft en 1 in. a ~14 ft en 6 in. Ref: tendencia de la tabla de longitud equivalente de NFPA 13 según los tamaños."},
  {id:345, q:"Un codo de 45 grados tiene una longitud equivalente que, comparada con un codo estándar de 90 grados del mismo tamaño, es:", opts:["Menor","Mayor","Exactamente el doble","Exactamente igual"], re:"Un codo de 45 grados gira el flujo menos y tiene una longitud equivalente menor que el codo de 90 grados del mismo tamaño. Ref: tabla de longitud equivalente de NFPA 13 (codo de 45 vs 90 grados)."},
  {id:346, q:"NFPA 13 generalmente NO exige agregar longitud equivalente de accesorio para cuáles conexiones?", opts:["Los codos de 90 grados en la base del montante","Conexiones directas al rociador y el accesorio donde una línea de ramal se conecta directamente a un rociador (según las notas de la tabla)","Válvulas de mariposa en el montante","Válvulas de retención de columpio"], re:"Según las notas de la tabla, la pérdida por fricción normalmente no se agrega para el accesorio que conecta directamente a un rociador (la propia pérdida del rociador se maneja por separado); las válvulas y los accesorios de giro siguen contando. Ref: notas de aplicación de la tabla de longitud equivalente de NFPA 13."},
  {id:347, q:"Para el tubo de cobre o la tubería de plástico, NFPA 13 indica al diseñador que:", opts:["Use los valores de longitud equivalente del acero sin cambios","Ignore los accesorios por completo","Use los datos de accesorios listados / longitudes equivalentes apropiadas y aplique el ajuste de valor C adecuado","Use solo la columna de 6 in."], re:"Como la tabla se basa en acero/C=120, el cobre y el plástico requieren los datos de accesorios del fabricante/listados o el factor de ajuste del valor C (p. ej., C = 150). Ref: disposiciones de ajuste de valor C de la tabla de longitud equivalente de NFPA 13."},
  {id:348, q:"La longitud equivalente total de tubería usada para calcular la pérdida por fricción en un segmento es igual a:", opts:["Solo los accesorios","Solo la tubería recta","El valor de un solo accesorio mayor","La longitud real de tubería recta MÁS la suma de todas las longitudes equivalentes de accesorios/válvulas en ese segmento"], re:"La pérdida por fricción se basa en la longitud real medida de la tubería sumada a la suma de las longitudes equivalentes de todos los accesorios y válvulas en la trayectoria del flujo de ese segmento. Ref: procedimiento de cálculo hidráulico de NFPA 13 (longitud equivalente)."},
  {id:349, q:"Los dispositivos especialmente listados (p. ej., bajantes flexibles de rociadores listados, preventores de retroflujo, coladores) deben tener su pérdida por fricción determinada por:", opts:["Los datos de pérdida por fricción listados del fabricante para el dispositivo específico","Solo la tabla estándar de accesorios","Suponiendo pérdida cero","Usando el valor de la válvula de compuerta"], re:"Los dispositivos especiales listados llevan sus propios datos de pérdida por fricción publicados (listados), que deben usarse en lugar de la tabla genérica de accesorios. Ref: disposiciones de NFPA 13 para la pérdida por fricción de dispositivos listados."},
  {id:350, q:"Un accesorio reductor o reductor en los cálculos hidráulicos de NFPA 13 se maneja típicamente:", opts:["Cargándolo como un codo completo de 90 grados","Usando la longitud equivalente del tamaño de tubería menor (salida) para el accesorio, según las notas de la tabla","Ignorándolo siempre","Duplicando el valor de la tubería mayor"], re:"Las notas de la tabla de NFPA 13 indican que la longitud equivalente del accesorio se base en la abertura menor (aguas abajo) del accesorio cuando los tamaños difieren. Ref: notas de la tabla de longitud equivalente de NFPA 13 sobre accesorios reductores."},
  {id:351, q:"Para tubería de acero Schedule 40 de 1 in. y tamaño nominal menor, la distancia máxima entre soportes/colgantes permitida por NFPA 13 es:", opts:["8 ft","10 ft","12 ft","15 ft"], re:"La tabla de NFPA 13 para la distancia máxima entre soportes da 12 ft para tubería de acero de 3/4 in. y 1 in.; el acero de 1-1/4 in. y mayor es 15 ft. Ref: tabla de distancia máxima entre soportes/colgantes de NFPA 13."},
  {id:352, q:"Para tubería de acero Schedule 40 de 1-1/4 in. y mayor, la distancia máxima entre soportes/colgantes permitida por NFPA 13 es:", opts:["12 ft","18 ft","20 ft","15 ft"], re:"NFPA 13 permite 15 ft de separación máxima de soportes para tubería de acero de 1-1/4 in. y mayor (12 ft para 3/4 in. y 1 in.). Ref: tabla de distancia máxima entre soportes/colgantes de NFPA 13."},
  {id:353, q:"NFPA 13 exige que los componentes de soporte/colgante en contacto con la tubería y la fijación estructural sean:", opts:["Listados (los componentes del conjunto de soporte deben estar listados) excepto ciertas fijaciones estándar permitidas","Soldados en campo","Hechos de plástico","Pintados de rojo"], re:"Los soportes/colgantes y sus componentes deben estar listados, con excepciones limitadas para ciertas fijaciones estructurales estándar (p. ej., sujetadores comunes al edificio). Ref: requisitos de listado de soportes/colgantes de NFPA 13."},
  {id:354, q:"El diámetro mínimo de la varilla de soporte para tubería de rociadores de 4 in. y menor, según NFPA 13, es:", opts:["1/4 in.","3/8 in.","1/2 in.","5/8 in."], re:"La tabla de tamaño de varilla de soporte de NFPA 13 requiere una varilla mínima de 3/8 in. para tubería hasta 4 in. inclusive. Ref: tabla de tamaño de varilla de soporte de NFPA 13."},
  {id:355, q:"Para tubería de rociadores de 5 in. y 6 in., el diámetro mínimo de la varilla de soporte requerido por NFPA 13 es:", opts:["3/8 in.","5/8 in.","1/2 in.","3/4 in."], re:"NFPA 13 requiere una varilla de soporte mínima de 1/2 in. para tubería de 5 in. y 6 in. (3/8 in. para 4 in. y menor). Ref: tabla de tamaño de varilla de soporte de NFPA 13."},
  {id:356, q:"Para tubería de rociadores de 8 in., el diámetro mínimo de la varilla de soporte requerido por NFPA 13 es:", opts:["3/8 in.","1/2 in.","1 in.","5/8 in."], re:"NFPA 13 requiere una varilla de soporte mínima de 5/8 in. para tubería de 8 in. (y similar de gran tamaño). Ref: tabla de tamaño de varilla de soporte de NFPA 13."},
  {id:357, q:"En una línea de ramal, NFPA 13 exige al menos un soporte/colgante entre rociadores cuando la distancia entre ellos excede:", opts:["6 ft","3 ft","10 ft","12 ft"], re:"NFPA 13 exige un soporte/colgante entre rociadores donde la separación excede 6 ft en la línea de ramal. Ref: ubicación de soportes/colgantes en líneas de ramal de NFPA 13."},
  {id:358, q:"Para tubería de acero de línea de ramal, la longitud máxima sin soporte entre el rociador extremo y el último soporte/colgante de la línea está generalmente limitada (según el tamaño de tubería) a aproximadamente:", opts:["6 in. sin importar el tamaño","36 in. para 1 in. hasta 48 in. para tamaños de acero mayores","10 ft para todos los tamaños","Sin límite"], re:"NFPA 13 limita la longitud del brazo sin soporte desde el último soporte hasta el rociador extremo según el tamaño de tubería para acero (del orden de 36 in. para 1 in., aumentando para tubería mayor). Ref: disposiciones de longitud sin soporte/extremo de línea para acero de NFPA 13."},
  {id:359, q:"Para TUBO de COBRE de 1 in. de tamaño nominal, NFPA 13 limita la longitud horizontal sin soporte desde el último soporte/colgante hasta el rociador extremo a:", opts:["12 in.","24 in.","18 in.","30 in."], re:"NFPA 13 limita la longitud extrema sin soporte del cobre a 18 in. (1 in.), 24 in. (1-1/4 in.) y 30 in. (1-1/2 in. y mayor). Ref: longitud sin soporte para tubo de cobre de NFPA 13."},
  {id:360, q:"Debido a que el tubo de cobre es menos rígido que el acero, NFPA 13 generalmente exige una separación de soportes/colgantes para el cobre que sea:", opts:["Mayor que para el acero","Exactamente igual que el acero siempre","Ilimitada","Más cercana (separación máxima más corta) que para el acero del mismo tamaño en los tamaños menores"], re:"La menor rigidez del cobre requiere un soporte más cercano que el acero en los tamaños pequeños (p. ej., la separación del cobre varía aproximadamente de 8-15 ft según el tamaño vs. 12-15 ft para el acero). Ref: distancia máxima entre soportes/colgantes (tubo de cobre) de NFPA 13."},
  {id:361, q:"La tubería de rociadores de CPVC listada de 1 in. típicamente tiene una separación máxima de soporte del orden de:", opts:["Alrededor de 5.5 a 6 ft según su listado","15 ft","12 ft","30 ft"], re:"El CPVC requiere un soporte mucho más cercano que el metal (aproximadamente 5.5-6 ft para tamaños pequeños, hasta ~10 ft para mayores), según lo establecido por su listado y reflejado en NFPA 13. Ref: separación de soportes del listado de NFPA 13 / CPVC."},
  {id:362, q:"Un soporte/colgante tipo trapecio se usa cuando:", opts:["La tubería es solo de plástico","No hay un miembro estructural directamente encima de la tubería y la carga debe transferirse a dos miembros adyacentes","La tubería es subterránea","No hay soportes disponibles"], re:"Un soporte tipo trapecio se extiende entre dos miembros estructurales para soportar la tubería donde ningún miembro queda directamente encima de ella; NFPA 13 exige que se dimensione para la carga usando las tablas de módulo de sección. Ref: disposiciones de soporte tipo trapecio de NFPA 13."},
  {id:363, q:"Al dimensionar un miembro de trapecio (soporte), NFPA 13 exige que el diseñador verifique su:", opts:["Color","Paso de rosca","Módulo de sección (para asegurar resistencia adecuada para la tubería soportada y el claro)","Listado como rociador"], re:"El miembro de trapecio debe tener un módulo de sección al menos igual al valor requerido por las tablas de trapecio de NFPA 13 para el tamaño de tubería soportada y el claro. Ref: tablas de módulo de sección de soporte tipo trapecio de NFPA 13."},
  {id:364, q:"NFPA 13 exige que cada soporte/colgante (y su estructura de soporte) sea capaz de soportar:", opts:["Solo el peso de la tubería vacía","El doble del peso de la tubería vacía","Solo el peso del rociador","Cinco veces el peso de la tubería llena de agua más 250 lb en cada punto de soporte de la tubería"], re:"NFPA 13 exige que los soportes/colgantes y sus sujetadores soporten cinco veces el peso de la tubería llena de agua más 250 lb en cada punto de soporte. Ref: requisito de carga de soporte (factor de seguridad) de NFPA 13."},
  {id:365, q:"El primer soporte/colgante en una línea de ramal, medido desde la conexión de la tubería principal transversal, debe ubicarse generalmente dentro de:", opts:["No más que la distancia de separación máxima para esa tubería (según las reglas de soportes de línea de ramal)","Exactamente 6 in.","30 ft","Sin límite"], re:"NFPA 13 vincula la ubicación del primer/cada soporte en una línea de ramal con la separación máxima para el tamaño de tubería, con límites específicos al inicio de la línea cerca de la tubería principal transversal. Ref: ubicación de soportes/colgantes en líneas de ramal de NFPA 13."},
  {id:366, q:"Donde un rociador se instala en un niple montante (sprig-up) más largo que una longitud especificada, NFPA 13 exige:", opts:["Ningún soporte en absoluto","Que el sprig/niple montante esté restringido o soportado (p. ej., cuando excede la altura sin soporte listada, comúnmente 30 in.)","Solo un soporte tipo trapecio","Soldarlo cerrado"], re:"Un sprig-up que excede la longitud permitida sin soporte (comúnmente 30 in.) debe restringirse contra el movimiento lateral/latigazo. Ref: soporte de niples montantes / sprigs de NFPA 13."},
  {id:367, q:"Los pernos accionados por pólvora y los pernos soldados usados para fijar soportes a la estructura del edificio deben ser:", opts:["Cualquier sujetador de ferretería","Anclajes de plástico","Listados para el servicio o instalados según un método aprobado y no usados para soportar tubería en tensión más allá de su clasificación","Evitarse por completo"], re:"NFPA 13 limita los pernos accionados por pólvora/soldados y otros sujetadores a tipos listados/aprobados y clasificaciones de carga, con restricciones de uso en ciertos materiales. Ref: disposiciones de sujetadores en concreto/acero de NFPA 13."},
  {id:368, q:"El propósito del arriostramiento sísmico LATERAL es resistir el movimiento horizontal de la tubería:", opts:["Paralelo al tramo de tubería","Solo verticalmente","Solo torsionalmente","Perpendicular (en ángulo recto) al tramo de tubería"], re:"Los arriostramientos laterales resisten cargas sísmicas horizontales que actúan perpendiculares al eje de la tubería arriostrada. Ref: definiciones de arriostramiento sísmico de NFPA 13 (arriostramiento lateral)."},
  {id:369, q:"El propósito del arriostramiento sísmico LONGITUDINAL es resistir el movimiento horizontal de la tubería:", opts:["Paralelo a (a lo largo del eje de) el tramo de tubería","Perpendicular al tramo de tubería","Solo verticalmente hacia abajo","Solo en el rociador"], re:"Los arriostramientos longitudinales resisten cargas sísmicas horizontales que actúan paralelas a (a lo largo de) el eje de la tubería arriostrada. Ref: definiciones de arriostramiento sísmico de NFPA 13 (arriostramiento longitudinal)."},
  {id:370, q:"La separación máxima entre arriostramientos sísmicos LATERALES en tuberías principales de alimentación y transversales es:", opts:["20 ft","40 ft","80 ft","100 ft"], re:"NFPA 13 limita la separación de arriostramientos laterales a un máximo de 40 ft entre centros. Ref: separación máxima de arriostramiento sísmico lateral de NFPA 13."},
  {id:371, q:"La separación máxima entre arriostramientos sísmicos LONGITUDINALES es:", opts:["40 ft","60 ft","80 ft","120 ft"], re:"NFPA 13 limita la separación de arriostramientos longitudinales a un máximo de 80 ft entre centros. Ref: separación máxima de arriostramiento sísmico longitudinal de NFPA 13."},
  {id:372, q:"El último arriostramiento sísmico lateral en un tramo de tubería debe ubicarse dentro de qué distancia del extremo de la tubería?", opts:["12 ft","24 ft","40 ft","6 ft"], re:"NFPA 13 exige que el último arriostramiento lateral esté dentro de 6 ft del extremo de la tubería. Ref: requisito de distancia al extremo del arriostramiento lateral de NFPA 13."},
  {id:373, q:"El último arriostramiento sísmico longitudinal debe ubicarse dentro de qué distancia del extremo de la tubería?", opts:["40 ft","6 ft","12 ft","24 ft"], re:"NFPA 13 exige que el último arriostramiento longitudinal esté dentro de 40 ft del extremo de la tubería. Ref: requisito de distancia al extremo del arriostramiento longitudinal de NFPA 13."},
  {id:374, q:"El arriostramiento sísmico lateral se requiere en las líneas de ramal (y tuberías principales) cuando la tubería es de al menos qué tamaño nominal?", opts:["1 in.","2-1/2 in.","1-1/2 in.","6 in."], re:"NFPA 13 exige arriostramiento de las tuberías principales de alimentación/transversales y de las líneas de ramal de 2-1/2 in. y mayores; las líneas de ramal más pequeñas se restringen pero no necesariamente se arriostran. Ref: alcance del arriostramiento de NFPA 13 (2-1/2 in. y mayores)."},
  {id:375, q:"La 'zona de influencia' de un arriostramiento sísmico se describe mejor como:", opts:["El área del piso del edificio que ocupa","La clasificación de presión de la tubería","La longitud/peso de tubería de la que el arriostramiento es responsable de restringir hasta que el siguiente arriostramiento se haga cargo","El orificio de holgura alrededor de una penetración"], re:"La zona de influencia es la porción de tubería (y agua contenida) tributaria de un arriostramiento dado, usada con el coeficiente sísmico para calcular la carga del arriostramiento. Ref: determinación de carga sísmica de NFPA 13 (zona de influencia)."},
  {id:376, q:"La carga sísmica horizontal (Fpw) usada para dimensionar un arriostramiento sísmico se calcula como:", opts:["Fpw = diámetro de tubería / 2","Fpw = longitud x valor C","Fpw = 250 lb fijo","Fpw = Cp x Wp (coeficiente sísmico por el peso tributario de tubería y agua)"], re:"NFPA 13 calcula la carga del arriostramiento como Fpw = Cp x Wp, donde Cp es el coeficiente sísmico y Wp es el peso de la tubería llena de agua en la zona de influencia. Ref: fórmula de carga de arriostramiento sísmico de NFPA 13."},
  {id:377, q:"En el procedimiento sísmico de NFPA 13, el coeficiente Cp se determina principalmente a partir de:", opts:["La respuesta espectral de período corto mapeada (Ss) en el sitio","El color de la tubería","El número de rociadores","El valor C de la tubería"], re:"Cp se toma de la tabla de NFPA 13 como una función de la aceleración de respuesta espectral de período corto Ss del sitio (con frecuencia con valor predeterminado cerca de 0.5 en ausencia de datos específicos del sitio). Ref: tabla del coeficiente sísmico (Cp) y Ss de NFPA 13."},
  {id:378, q:"Un arriostramiento sísmico debe instalarse en un ángulo desde la vertical (o medido según NFPA 13) de al menos:", opts:["10 grados","30 grados","60 grados","75 grados"], re:"NFPA 13 exige que los arriostramientos sísmicos formen un ángulo de al menos 30 grados desde la vertical (preferiblemente 45-90 grados) para ser efectivos; los ángulos por debajo de 30 grados no se acreditan. Ref: requisitos de ángulo de arriostramiento sísmico de NFPA 13."},
  {id:379, q:"En la parte superior de un montante de rociadores, NFPA 13 exige:", opts:["Ningún arriostramiento","Solo un soporte/colgante","Arriostramiento de cuatro vías (restricción tanto lateral como longitudinal)","Solo un acoplamiento flexible"], re:"Los montantes deben proveerse con arriostramiento de cuatro vías (que resista el movimiento en ambas direcciones horizontales) ubicado cerca de la parte superior del montante dentro de la distancia requerida. Ref: arriostramiento de cuatro vías de montantes de NFPA 13."},
  {id:380, q:"Un solo arriostramiento lateral también puede servir como arriostramiento longitudinal para un tramo adyacente cuando:", opts:["Nunca; siempre deben estar separados","La tubería es de plástico","El ángulo del arriostramiento está por debajo de 30 grados","El arriostramiento está dentro del desfase permitido (p. ej., dentro de 24 in. del eje de la tubería) y la tubería conectante es de tamaño igual o mayor"], re:"NFPA 13 permite que un arriostramiento lateral actúe longitudinalmente para una línea conectada cuando se ubica dentro de la distancia permitida (aproximadamente 24 in.) del eje y la tubería conectante es al menos de igual tamaño. Ref: disposiciones de uso compartido de arriostramientos de NFPA 13."},
  {id:381, q:"Los conjuntos de arriostramiento sísmico y sus sujetadores deben dimensionarse de modo que no fallen antes de que se impongan las cargas del edificio; por lo tanto NFPA 13 exige que los componentes del arriostramiento sean:", opts:["Listados y seleccionados de las tablas de carga de arriostramiento para la carga calculada y el ángulo del arriostramiento","Sin listar y construidos en campo","Mayores que tubería de 4 in.","Soldados al rociador"], re:"NFPA 13 exige componentes de arriostramiento sísmico listados seleccionados de las tablas de carga según el Fpw calculado y el ángulo y longitud instalados del arriostramiento. Ref: listado de componentes de arriostramiento sísmico y tablas de carga de NFPA 13."},
  {id:382, q:"La relación de esbeltez (l/r) de un miembro de arriostramiento sísmico importa porque:", opts:["Establece el valor C de la tubería","Limita la capacidad de compresión (pandeo) de los arriostramientos que resisten carga en compresión","Determina el factor k del rociador","No tiene efecto"], re:"Para los arriostramientos que resisten compresión, NFPA 13 limita la relación de esbeltez (longitud/radio de giro) para prevenir el pandeo; los arriostramientos de cable resisten solo tensión. Ref: límites de esbeltez de miembros de arriostramiento sísmico de NFPA 13."},
  {id:383, q:"Los arriostramientos sísmicos de cable (cable de acero) difieren de los arriostramientos rígidos en que los arriostramientos de cable:", opts:["Resisten tanto tensión como compresión","Se usan solo bajo tierra","Resisten solo tensión, por lo que deben instalarse en pares opuestos para cada dirección","No requieren listado"], re:"Los arriostramientos de cable soportan solo tensión; para arriostrar una dirección se disponen de modo que un cable resista cada sentido de movimiento (pares opuestos), a diferencia de los arriostramientos rígidos que toman tensión o compresión. Ref: disposiciones de arriostramiento sísmico de cable de NFPA 13."},
  {id:384, q:"Se requiere un conjunto de separación sísmica dondequiera que la tubería de rociadores:", opts:["Cambie de acero a cobre","Se conecte a un rociador","Pase debajo de una puerta","Cruce una junta de separación sísmica (expansión) del edificio"], re:"NFPA 13 exige un conjunto de separación sísmica con accesorios flexibles, sin importar el tamaño de la tubería, donde la tubería cruza una junta de separación sísmica del edificio sobre el suelo. Ref: requisito de conjunto de separación sísmica de NFPA 13."},
  {id:385, q:"La función de un conjunto de separación sísmica es:", opts:["Permitir el movimiento en todas las direcciones de modo que el movimiento diferencial de las dos secciones del edificio no rompa la tubería","Aumentar la presión del agua","Reducir la pérdida por fricción","Actuar como una válvula de retención"], re:"El conjunto usa acoplamientos/accesorios flexibles para acomodar el movimiento diferencial multidireccional a través de la junta, previniendo la rotura de la tubería. Ref: propósito del conjunto de separación sísmica de NFPA 13."},
  {id:386, q:"Se requiere que los acoplamientos flexibles se instalen dentro de qué distancia de la parte superior e inferior de cada montante de rociadores?", opts:["6 in.","24 in.","12 in.","48 in."], re:"NFPA 13 exige un acoplamiento flexible listado dentro de 24 in. de la parte superior e inferior de cada montante (con excepciones para montantes cortos). Ref: ubicación de acoplamientos flexibles en montantes de NFPA 13."},
  {id:387, q:"En un edificio de varios pisos, NFPA 13 exige acoplamientos flexibles en los montantes en cada piso, generalmente ubicados dentro de:", opts:["Ninguna distancia específica","10 ft del piso","12 in. arriba y 24 in. abajo del piso/techo según la regla","Solo el medio del piso"], re:"NFPA 13 exige acoplamientos flexibles cerca de cada piso (comúnmente dentro de 12 in. arriba y 24 in. abajo del piso) para acomodar la deriva entre pisos. Ref: requisitos de acoplamientos flexibles en pisos en edificios de varios pisos de NFPA 13."},
  {id:388, q:"Donde la tubería de rociadores de 1 in. a 3-1/2 in. nominal pasa a través de muros o pisos, NFPA 13 exige una holgura nominal (espacio) alrededor de la tubería de modo que el diámetro del orificio sea mayor que la tubería por:", opts:["No se necesita holgura","6 in. en total","12 in. en total","2 in. en total (aproximadamente 1 in. en todo el contorno)"], re:"Para tubería de 1 in. a 3-1/2 in. nominal, el orificio se dimensiona aproximadamente 2 in. mayor que la tubería (aproximadamente 1 in. de holgura por lado) para permitir el movimiento. Ref: holgura alrededor de la tubería en penetraciones de NFPA 13."},
  {id:389, q:"Para tubería de rociadores de 4 in. nominal y mayor que pasa a través de muros/pisos, el orificio requerido es mayor que la tubería por aproximadamente:", opts:["4 in. en total (aproximadamente 2 in. en todo el contorno)","2 in. en total","Sin holgura","12 in. en total"], re:"Para tubería de 4 in. y mayor, el orificio se dimensiona aproximadamente 4 in. mayor que la tubería (aproximadamente 2 in. de holgura por lado). Ref: holgura alrededor de la tubería en penetraciones de NFPA 13."},
  {id:390, q:"El espacio de holgura alrededor de una penetración de tubería en un conjunto con clasificación de resistencia al fuego debe aún:", opts:["Dejarse completamente abierto","Llenarse con un cortafuego flexible/deformable listado (material resiliente) que mantenga la clasificación pero permita el movimiento","Soldarse cerrado","Rellenarse sólido con concreto"], re:"Donde la holgura requerida penetra una barrera con clasificación, se usa un sistema de cortafuego flexible listado para que la tubería pueda moverse mientras se preserva la clasificación de resistencia al fuego. Ref: disposiciones de holgura usadas con cortafuego flexible listado de NFPA 13."},
  {id:391, q:"NFPA 13 permite omitir la holgura alrededor de una penetración (no se requiere espacio) cuando:", opts:["La tubería es de 8 in. o mayor","El muro está pintado","Se provee un acoplamiento flexible listado dentro de una distancia especificada a cada lado de la penetración","La tubería es de cobre"], re:"La holgura puede omitirse donde se instala un acoplamiento flexible dentro de la distancia especificada a ambos lados de la penetración, ya que esa junta acomoda el movimiento. Ref: excepción de holgura con acoplamientos flexibles adyacentes de NFPA 13."},
  {id:392, q:"La tubería pequeña de línea de ramal (menor de 2-1/2 in.) que no está arriostrada debe aún:", opts:["Dejarse libre para oscilar","Soldarse al techo","Dimensionarse como 4 in.","Restringirse contra el movimiento lateral excesivo cerca del extremo de la línea (p. ej., mediante restricciones listadas o ganchos en U)"], re:"NFPA 13 exige restricción de extremo de línea para las líneas de ramal sin arriostrar (usando ganchos en U envolventes o dispositivos de restricción listados) para limitar el movimiento, aunque no se requiera arriostramiento completo. Ref: restricción de líneas de ramal de NFPA 13."},
  {id:393, q:"Un acoplamiento flexible listado usado para fines sísmicos proporciona protección al permitir:", opts:["Una pequeña cantidad de movimiento angular/axial en la junta de modo que el esfuerzo no se transmita como un momento rígido","Solo mayor flujo","Conexión eléctrica a tierra","Reducción de presión"], re:"Los acoplamientos flexibles acomodan un movimiento angular y axial limitado, aliviando el esfuerzo sísmico que de otro modo una junta rígida transmitiría a la tubería y los accesorios. Ref: función del acoplamiento flexible en el diseño sísmico de NFPA 13."},
  {id:394, q:"NFPA 13 generalmente permite OMITIR el arriostramiento sísmico (y las disposiciones relacionadas) donde:", opts:["La tubería es de plástico","El edificio está en una región/zona exenta por la norma o la AHJ no requiere protección sísmica","El sistema es seco","El techo es alto"], re:"La protección sísmica según NFPA 13 aplica donde la requiere la AHJ o en regiones sísmicas definidas; puede omitirse donde el diseño sísmico no es requerido para el sitio. Ref: aplicabilidad de la protección sísmica (donde se requiere) de NFPA 13."},
  {id:395, q:"Los bajantes a líneas de mangueras, rociadores de estanterías y mezzanines, y otras porciones sujetas a movimiento diferencial, deben protegerse mediante:", opts:["Solo soldadura rígida","Eliminación del bajante","Flexibilidad (p. ej., acoplamientos flexibles o conexiones flexibles listadas) para absorber el movimiento relativo","Valores C mayores"], re:"Donde se espera movimiento relativo (entre estanterías/estructura y el sistema), se usan acoplamientos flexibles o conexiones flexibles listadas para que los bajantes no se cizallen. Ref: disposiciones de flexibilidad para bajantes sujetos a movimiento diferencial de NFPA 13."},
  {id:396, q:"Una razón principal por la que los acoplamientos flexibles de montante se colocan cerca de las penetraciones de piso en edificios altos es para acomodar:", opts:["Solo la expansión térmica","Sobrepresiones de presión","Golpe de ariete de los rociadores","La deriva entre pisos (desplazamiento horizontal relativo entre pisos adyacentes durante un sismo)"], re:"Los acoplamientos flexibles cerca de los pisos absorben la deriva entre pisos de modo que el desplazamiento sísmico relativo entre pisos no fracture el montante. Ref: justificación de los acoplamientos flexibles en los pisos de NFPA 13."},
  {id:397, q:"Cuando la tubería está rígidamente fijada a dos estructuras separadas (o una estructura y un equipo) que pueden moverse independientemente, NFPA 13 exige:", opts:["Flexibilidad entre los dos puntos de fijación de modo que el movimiento diferencial no se resista rígidamente","Un tamaño de tubería mayor","Una válvula de retención de columpio","Una válvula reductora de presión"], re:"Debe proveerse flexibilidad (acoplamientos flexibles/conjunto de separación) entre soportes que se mueven independientemente para prevenir que la tubería se desgarre por el movimiento diferencial. Ref: flexibilidad entre estructuras independientes de NFPA 13."},
  {id:398, q:"Para la protección sísmica de NFPA 13 (a diferencia de FM Global), se requiere que los componentes de arriostramiento y restricción sean:", opts:["Solo Aprobados por FM","Listados (p. ej., listados UL) para el servicio","Fabricaciones de taller sin listar","Hechos de hierro fundido"], re:"NFPA 13 exige componentes listados para el arriostramiento sísmico y la restricción; las normas de FM Global en cambio exigen componentes Aprobados por FM. Ref: requisito de listado para componentes de arriostramiento de NFPA 13."},
  {id:399, q:"El objetivo general de las disposiciones sísmicas de NFPA 13 (arriostramiento, acoplamientos flexibles, holguras, conjuntos de separación) es:", opts:["Aumentar el caudal del sistema","Reducir la presión del agua","Mantener el sistema de rociadores intacto y operativo después de un sismo limitando el movimiento dañino mientras permite el movimiento necesario","Reducir el número de rociadores"], re:"El paquete sísmico limita el movimiento diferencial dañino (arriostramiento) mientras permite el movimiento necesario (acoplamientos, holguras, conjuntos de separación) para que el sistema sobreviva y opere después del evento. Ref: propósito de la protección sísmica de la tubería de NFPA 13."},
  {id:400, q:"Un montante corto está exento de uno o ambos acoplamientos flexibles requeridos cuando su longitud está por debajo de un umbral; NFPA 13 comúnmente permite omitir los acoplamientos en un montante que mide menos de:", opts:["1 ft de largo","12 ft de largo","20 ft de largo","3 ft de largo (con un solo acoplamiento permitido para montantes de 3 ft a 7 ft)"], re:"NFPA 13 permite omitir los acoplamientos flexibles en montantes de menos de 3 ft, y un solo acoplamiento flexible en montantes de 3 ft a 7 ft de largo. Ref: excepciones de acoplamientos flexibles para montantes cortos de NFPA 13."},
  {id:401, q:"En una prueba de flujo de hidrante, ¿qué tres valores de presión/flujo se registran para definir el suministro de agua disponible para un sistema?", opts:["Presión estática, presión residual y descarga fluyente (pitot)","Presión de churn, presión nominal y presión de sobrecarga","Presión de trabajo, presión hidrostática y presión de sobrepresión transitoria","Presión neta, presión de succión y presión de descarga"], re:"Una prueba de flujo de hidrante registra la presión estática (sin flujo), la presión residual en el hidrante de prueba mientras fluye el agua y la descarga fluyente (calculada a partir de la presión pitot en el hidrante fluido). Referencia: NFPA 291, Práctica Recomendada para Pruebas de Caudal de Incendio y Marcado de Hidrantes."},
  {id:402, q:"En un gráfico de suministro de agua usado para diseño hidráulico, la curva de suministro se traza usando qué exponente en papel gráfico log-log (N^1.85)?", opts:["1.50","1.85","2.00","2.63"], re:"Las curvas de suministro de agua se trazan en papel gráfico N^1.85, coincidiendo con el exponente de fricción de Hazen-Williams (Q^1.85), de modo que la línea de suministro se traza como una línea recta. Referencia: NFPA 291; procedimientos de cálculo hidráulico de NFPA 13."},
  {id:403, q:"La descarga fluyente (Q, gpm) de una salida de hidrante durante una prueba de flujo se calcula a partir de qué cantidad medida?", opts:["La presión residual en un hidrante adyacente","La presión estática antes de que comience el flujo","La presión pitot (de velocidad) en la salida fluyente","La diferencia de elevación hasta el rociador más alto"], re:"La descarga se calcula como Q = 29.83 x c x d^2 x sqrt(p), donde p es la presión pitot (de velocidad) leída en la salida fluyente, d es el diámetro de la salida y c es el coeficiente de descarga. Referencia: cálculo de caudal de NFPA 291."},
  {id:404, q:"Una prueba de flujo da una estática de 70 psi y una residual de 50 psi mientras fluye 1,000 gpm. Comparado con una prueba que cae a 30 psi a 1,000 gpm, el primer suministro de agua es:", opts:["Más débil, porque la residual cayó menos","Idéntico, porque ambas fluyeron 1,000 gpm","Indeterminado sin la lectura pitot","Más fuerte, porque la residual cayó menos para el mismo flujo"], re:"Una caída de presión menor (70 a 50 psi vs 70 a 30 psi) para el mismo flujo indica un suministro más fuerte y rígido con más presión disponible a flujos más altos. Referencia: interpretación de la curva de suministro de NFPA 291."},
  {id:405, q:"Para el diseño de un sistema de rociadores, la demanda del sistema (flujo y presión) debe compararse con el suministro de agua disponible en qué punto?", opts:["En un punto de referencia común donde ambos se conocen, como la fuente de suministro","Solo en la base del montante","En el rociador más remoto","En la conexión del cuerpo de bomberos"], re:"La demanda y el suministro se trazan/comparan en un punto de referencia común (a menudo la fuente o un nodo definido) donde se conocen las características de ambos. NFPA 13 requiere que los cálculos se extiendan hasta el punto efectivo del suministro de agua. Referencia: NFPA 13, Planos y Cálculos."},
  {id:406, q:"Cuando una demanda de rociadores calculada hidráulicamente se traza en el gráfico de suministro de agua y cae POR DEBAJO de la curva de suministro disponible, el resultado indica:", opts:["El suministro es inadecuado y se requiere una bomba contra incendios","El suministro es adecuado para satisfacer la demanda","Todos los tamaños de tubería deben aumentarse","Los datos de la prueba no son válidos"], re:"Si el punto de demanda queda por debajo (y a la izquierda de) la curva de suministro disponible, el suministro puede entregar el flujo requerido a la presión requerida o por encima de ella, por lo que el suministro es adecuado. Referencia: análisis del gráfico hidráulico de NFPA 13; NFPA 291."},
  {id:407, q:"La pérdida por fricción en la tubería de protección contra incendios se calcula más comúnmente usando qué fórmula?", opts:["Ecuación de Bernoulli","Ecuación de Darcy-Weisbach","Fórmula de Hazen-Williams","Fórmula de Manning"], re:"NFPA 13 especifica que la pérdida por fricción en la tubería se determine usando la fórmula de Hazen-Williams, con un factor C apropiado para el material de la tubería. Referencia: procedimientos de cálculo hidráulico de NFPA 13."},
  {id:408, q:"En la fórmula de Hazen-Williams, un valor de factor C MÁS BAJO representa:", opts:["Tubería más lisa con menor pérdida por fricción","Diámetro de tubería mayor","Temperatura del agua más alta","Tubería más rugosa con mayor pérdida por fricción"], re:"El factor C de Hazen-Williams describe la rugosidad interior de la tubería; un C más bajo significa un interior más rugoso y por tanto mayor pérdida por fricción para un flujo dado. Referencia: tablas de factor C de NFPA 13 (p. ej., C=120 para hierro fundido/dúctil sin revestir, C=140 para revestido de cemento)."},
  {id:409, q:"La presión de velocidad en un cálculo hidráulico es la porción de presión atribuible a:", opts:["La velocidad (movimiento) del agua fluyente","La elevación del agua por encima del manómetro","La presión atmosférica sobre la superficie","El reflujo de la red pública"], re:"La presión de velocidad (Pv = 0.001123 Q^2 / d^4) es la presión debida a la energía cinética del agua en movimiento; la presión normal es la diferencia entre la presión total y la de velocidad. Referencia: definiciones de cálculo hidráulico de NFPA 13."},
  {id:410, q:"La pérdida de elevación (presión) en un sistema de protección contra incendios se toma como aproximadamente:", opts:["0.500 psi por pie de elevación","0.433 psi por pie de elevación","1.000 psi por pie de elevación","2.310 psi por pie de elevación"], re:"Una columna de agua ejerce 0.433 psi por pie de altura (equivalentemente, 1 psi por 2.31 ft). Las ganancias de elevación se suman a la demanda de presión en los cálculos hidráulicos. Referencia: procedimientos de cálculo hidráulico de NFPA 13."},
  {id:411, q:"Se realiza una prueba de flujo para dimensionar una bomba contra incendios. NFPA 20 requiere que los datos de la prueba de flujo usados para el dimensionamiento se hayan realizado dentro de los anteriores:", opts:["3 meses","6 meses","12 meses","24 meses"], re:"NFPA 20 requiere que la prueba de caudal de agua usada para determinar el suministro de agua para el dimensionamiento de la bomba contra incendios se realice dentro de los 12 meses del diseño (edición actual). Referencia: NFPA 20, Norma para la Instalación de Bombas Estacionarias para Protección contra Incendios."},
  {id:412, q:"Al proyectar una curva de suministro de agua, el caudal de incendio se evalúa comúnmente a una presión residual de:", opts:["40 psi","65 psi","100 psi","20 psi"], re:"El caudal de incendio disponible se reporta típicamente a 20 psi de residual, un umbral común de presión mínima de operación para redes públicas y el punto estándar de proyección en los gráficos de suministro. Referencia: NFPA 291; práctica de caudal de incendio AWWA/ISO."},
  {id:413, q:"Para convertir un flujo Q1 observado a residual P1 a un flujo a un residual diferente, el analista usa la relación Q2 = Q1 x (h2/h1)^0.54, donde h es:", opts:["La caída de presión (estática menos residual)","El diámetro de la tubería","Solo la carga de elevación","La presión pitot"], re:"En NFPA 291, h = caída de presión = estática menos residual; la capacidad nominal a un residual objetivo es QR = QF x (hr/hf)^0.54. Referencia: ecuación de proyección de caudal de NFPA 291."},
  {id:414, q:"Una red de suministro 'en anillo' o enmallada, comparada con una sola red de extremo muerto del mismo tamaño, generalmente proporciona:", opts:["Menor flujo disponible debido a la fricción añadida","Mayor flujo disponible porque el agua llega a un punto desde múltiples trayectorias","Ninguna diferencia en el flujo disponible","Mayor estática pero menor presión residual"], re:"Las redes en anillo/enmalladas alimentan un punto de demanda desde más de una dirección, reduciendo la pérdida efectiva por fricción y aumentando el flujo disponible a una presión residual dada comparado con una red de extremo muerto. Referencia: principios de suministro de NFPA 24/NFPA 291."},
  {id:415, q:"En el análisis del suministro de agua para diseño, la 'presión disponible' en el punto de conexión del suministro se refiere a:", opts:["La presión que el sistema requiere para operar","La presión máxima que la bomba puede producir en churn","La presión que el suministro público/privado puede entregar al flujo de diseño","La presión de prueba hidrostática"], re:"La presión disponible es lo que el suministro puede entregar en el punto de conexión al flujo requerido; debe igualar o exceder la presión de demanda del sistema (más margen de seguridad) para que el diseño funcione. Referencia: NFPA 13/NFPA 291."},
  {id:416, q:"A menudo se aplica un cojín de seguridad de diseño para que el punto de demanda no quede exactamente sobre la curva de suministro. Una práctica común es mantener el suministro disponible al menos:", opts:["Exactamente igual a la demanda","El triple de la presión de demanda","Por debajo de la demanda para permitir sobrepresión transitoria","Aproximadamente 10 psi (o 10%) por encima de la demanda calculada"], re:"Los diseñadores típicamente proporcionan un margen (comúnmente del orden de 10 psi o 10%) entre el suministro disponible y la demanda calculada para tener en cuenta la fluctuación del suministro y su deterioro con el tiempo. Referencia: práctica de diseño común de NFPA 13 / requisitos de la AHJ."},
  {id:417, q:"Si el suministro de agua disponible de un edificio es adecuado en flujo pero deficiente en PRESIÓN para la demanda de rociadores, el remedio más apropiado típicamente es:", opts:["Instalar una bomba contra incendios para aumentar la presión","Reducir el área de diseño","Añadir más hidrantes a la red pública","Reducir el factor C usado en los cálculos"], re:"Cuando el flujo es suficiente pero la presión es inferior a la demanda, se añade una bomba contra incendios para aumentar la presión al nivel requerido. Un tanque (con bomba) aborda los déficits de flujo/volumen. Referencia: NFPA 20; diseño de NFPA 13."},
  {id:418, q:"NFPA 20 limita la presión máxima de churn (sin flujo, cierre) de una bomba contra incendios centrífuga a no más de qué porcentaje de su presión nominal?", opts:["100% de la presión nominal","140% de la presión nominal","120% de la presión nominal","150% de la presión nominal"], re:"NFPA 20 requiere que la presión de churn (sin flujo) no exceda el 140% de la presión nominal de la bomba, limitando la presión máxima del sistema. Referencia: NFPA 20, requisitos de desempeño para bombas contra incendios centrífugas."},
  {id:419, q:"Al 150% de su capacidad nominal (el punto de sobrecarga), una bomba contra incendios debe entregar una presión neta de al menos:", opts:["50% de la presión nominal","85% de la presión nominal","65% de la presión nominal","100% de la presión nominal"], re:"NFPA 20 requiere que la bomba produzca al menos el 65% de la presión nominal al 150% del flujo nominal, definiendo el extremo de sobrecarga de la envolvente de desempeño. Referencia: desempeño de bomba centrífuga de NFPA 20."},
  {id:420, q:"Los tres puntos que definen la curva de desempeño de una bomba contra incendios según NFPA 20 son:", opts:["Succión, descarga y neto","Estática, residual y pitot","Velocidad baja, media y alta","Churn (sin flujo), 100% del flujo nominal y 150% del flujo nominal"], re:"La curva de una bomba contra incendios se define por el churn (0% de flujo, <=140% de presión), el punto del 100% nominal (flujo nominal a presión nominal) y el punto de sobrecarga del 150% (>=65% de presión). Referencia: NFPA 20."},
  {id:421, q:"Una 'clasificación de bomba contra incendios' (p. ej., 750 gpm a 100 psi) se refiere a la presión neta entregada por la bomba al:", opts:["100% de la capacidad nominal","Churn / sin flujo","150% de la capacidad nominal","La menor presión de succión permisible"], re:"La clasificación de la bomba es la presión neta que produce al 100% de su capacidad nominal. El churn y el 150% se evalúan en relación con este punto nominal. Referencia: NFPA 20."},
  {id:422, q:"Cuál de las siguientes es una capacidad nominal ESTÁNDAR para una bomba contra incendios centrífuga según NFPA 20?", opts:["650 gpm","750 gpm","725 gpm","850 gpm"], re:"NFPA 20 enumera capacidades nominales estándar incluyendo 250, 500, 750, 1000, 1250, 1500 gpm (y otras). 750 gpm es estándar; 650, 725 y 850 gpm no son clasificaciones estándar listadas. Referencia: tabla de capacidad nominal de NFPA 20."},
  {id:423, q:"La función principal de una bomba jockey (mantenimiento de presión) es:", opts:["Proporcionar la demanda completa de caudal de incendio","Probar la bomba principal semanalmente","Mantener la presión del sistema y prevenir el arranque innecesario de la bomba contra incendios principal","Aumentar la presión de succión durante un incendio"], re:"Una bomba jockey mantiene la presión dentro de límites preestablecidos para compensar fugas menores, previniendo arranques innecesarios de la bomba principal. No está dimensionada para satisfacer la demanda de incendio. Referencia: NFPA 20, bombas de mantenimiento de presión."},
  {id:424, q:"Una bomba jockey para un sistema de rociadores/tubo vertical generalmente debe dimensionarse para entregar un flujo que sea:", opts:["Igual a la capacidad de la bomba principal","Igual al 50% de la capacidad de la bomba principal","Exactamente 150% de la capacidad de la bomba principal","Menor que el flujo de un solo rociador, de modo que la bomba principal arranque ante cualquier flujo de agua real"], re:"La guía de NFPA 20 dimensiona la bomba jockey para compensar las fugas permisibles y entregar menos que el flujo de un rociador, de modo que cualquier operación real de un rociador reduzca la presión y arranque la bomba principal. Referencia: dimensionamiento de bomba de mantenimiento de presión de NFPA 20."},
  {id:425, q:"La presión neta nominal mínima para una bomba contra incendios centrífuga según NFPA 20 es:", opts:["40 psi","20 psi","65 psi","100 psi"], re:"NFPA 20 requiere que las bombas contra incendios centrífugas se clasifiquen a presiones netas de 40 psi (2.7 bar) o más. Referencia: requisitos de clasificación de bomba centrífuga de NFPA 20."},
  {id:426, q:"Para minimizar la presión desperdiciada/en exceso, NFPA 20 aconseja seleccionar una bomba cuyo punto NOMINAL ubique el flujo de demanda de diseño aproximadamente dentro de:", opts:["10% a 50% del flujo nominal","90% a 140% del flujo nominal","150% a 200% del flujo nominal","Solo 0% (churn)"], re:"Los diseñadores seleccionan una bomba de modo que el flujo requerido del sistema caiga entre aproximadamente el 90% y el 140% de la capacidad nominal (nunca por encima del 150%), manteniendo el punto de operación en la parte útil de la curva. Referencia: práctica de selección de NFPA 20."},
  {id:427, q:"Durante una prueba de aceptación/flujo, la salida de una bomba contra incendios se mide en cuántas condiciones de flujo, como mínimo?", opts:["Una (solo nominal)","Dos (churn y nominal)","Tres (churn, 100% nominal y 150% nominal)","Cinco"], re:"La bomba contra incendios se prueba en un mínimo de tres condiciones: sin flujo (churn), 100% del flujo nominal y 150% del flujo nominal. Referencia: prueba de bomba de NFPA 20 / NFPA 25."},
  {id:428, q:"La 'presión neta de la bomba' para una bomba contra incendios se define como:", opts:["Presión de descarga más presión de succión","Solo presión de succión","Presión de churn menos 140%","Presión de descarga menos presión de succión (con corrección por carga de velocidad)"], re:"La presión neta es la presión manométrica de descarga menos la presión manométrica de succión (ajustada por carga de velocidad y elevación del manómetro). Representa la presión que la bomba misma añade. Referencia: definiciones de NFPA 20."},
  {id:429, q:"Para bombas que toman succión de una red pública, NFPA 20 requiere que la presión manométrica de succión durante la prueba de flujo máximo (150%) generalmente no caiga por debajo de:", opts:["0 psi (manométrica), a menos que la AHJ permita un valor menor","20 psi mínimo en todos los casos","40 psi mínimo en todos los casos","65 psi mínimo en todos los casos"], re:"NFPA 20 limita la presión de succión a no menos de 0 psi manométrica al 150% de flujo para bombas en un suministro (algunas AHJ/proveedores de agua requieren un mínimo más alto como 20 psi). Referencia: requisitos de suministro de succión de NFPA 20."},
  {id:430, q:"Una bomba contra incendios de carcasa partida horizontal, comparada con una bomba contra incendios de turbina vertical, típicamente NO es adecuada cuando:", opts:["El suministro es una red pública presurizada por encima de la bomba","La fuente de agua está por debajo de la línea central de la bomba (p. ej., un tanque o pozo bajo el nivel del suelo, que requiere elevación de succión)","Se requiere alto flujo","Se usa un motor diésel"], re:"Las bombas de carcasa partida horizontal requieren una succión positiva (inundada) y no pueden elevar el agua; se usa una bomba de turbina vertical cuando el nivel de la fuente está por debajo de la bomba, como un pozo o tanque bajo el nivel del suelo. Referencia: tipos de bombas de NFPA 20."},
  {id:431, q:"El ajuste de presión al cual se configura el ARRANQUE de la bomba contra incendios principal normalmente es:", opts:["Por encima de las presiones de arranque y paro de la bomba jockey","Igual a la presión de paro de la bomba jockey","Por debajo de la presión de arranque de la bomba jockey","En la presión de churn de la bomba principal"], re:"La secuencia de control ajusta el paro/arranque de modo que la bomba jockey cicle primero; la presión de arranque de la bomba contra incendios principal se ajusta por debajo de la presión de arranque de la bomba jockey, de modo que la bomba principal arranque solo cuando la jockey no pueda mantener la presión. Referencia: guía de ajuste de presión de NFPA 20."},
  {id:432, q:"Una bomba contra incendios accionada por un motor diésel (en lugar de un motor eléctrico) comúnmente se selecciona principalmente para:", opts:["Reducir la presión nominal requerida","Eliminar la necesidad de un controlador","Permitir una presión de churn superior al 140%","Proporcionar una fuente de energía independiente de la red eléctrica normal"], re:"Un motor diésel proporciona una fuente de energía confiable e independiente donde la confiabilidad de la energía de la red está en cuestión o se requiere una segunda fuente. Los criterios de desempeño de la bomba (churn, 100%, 150%) no cambian. Referencia: motores de NFPA 20."},
  {id:433, q:"Cuando el suministro de succión disponible ya proporciona parte de la presión requerida, la bomba contra incendios solo necesita estar clasificada para:", opts:["Compensar la DIFERENCIA entre la demanda del sistema y la presión de succión disponible (al flujo de diseño)","Producir la presión completa de demanda del sistema sin importar la succión","Producir el 150% de la demanda del sistema","Igualar la presión de churn de la red pública"], re:"La bomba se dimensiona para aumentar la presión en la diferencia faltante: la presión neta requerida es igual a la presión de demanda del sistema menos la presión de succión disponible al flujo de diseño. Referencia: práctica de dimensionamiento de bomba de NFPA 20."},
  {id:434, q:"El propósito de un controlador de bomba contra incendios es:", opts:["Estrangular el flujo de la bomba exactamente a la demanda","Arrancar automáticamente la bomba ante una caída de presión y proporcionar monitoreo/control del motor de la bomba","Reemplazar la bomba jockey","Establecer la presión de prueba hidrostática"], re:"El controlador de bomba contra incendios listado arranca la bomba (típicamente ante una señal de caída de presión), supervisa el motor y proporciona las alarmas/monitoreo requeridos. Referencia: controladores de NFPA 20."},
  {id:435, q:"Para un sistema de tubo vertical Clase I diseñado hidráulicamente, NFPA 14 requiere una presión residual mínima en la conexión de manguera de 2 1/2 pulg. hidráulicamente más remota de:", opts:["65 psi","125 psi","100 psi","175 psi"], re:"NFPA 14 requiere 100 psi de presión residual mínima en la salida de 2 1/2 pulg. (Clase I/III) hidráulicamente más remota mientras fluye la demanda requerida. Referencia: NFPA 14, Norma para la Instalación de Sistemas de Tubos Verticales y Mangueras."},
  {id:436, q:"Para un sistema de tubo vertical Clase II, NFPA 14 requiere una presión residual mínima en la estación de manguera de 1 1/2 pulg. hidráulicamente más remota de:", opts:["50 psi","100 psi","150 psi","65 psi"], re:"NFPA 14 requiere 65 psi de presión residual mínima en la estación de manguera de 1 1/2 pulg. (Clase II) hidráulicamente más remota. Referencia: presiones mínimas de diseño de NFPA 14."},
  {id:437, q:"Un sistema de tubo vertical Clase I proporciona qué tamaño de conexión de manguera, destinado al uso del cuerpo de bomberos o personal capacitado?", opts:["Conexiones de 2 1/2 pulg.","Conexiones de 1 pulg.","Conexiones de 1 1/2 pulg.","Conexiones de 4 pulg."], re:"Los sistemas Clase I proporcionan conexiones de manguera de 2 1/2 pulg. para uso del cuerpo de bomberos/personal capacitado. La Clase II proporciona 1 1/2 pulg. para uso de los ocupantes; la Clase III proporciona ambas. Referencia: clases de sistemas de NFPA 14."},
  {id:438, q:"Un sistema de tubo vertical Clase III proporciona:", opts:["Solo conexiones de manguera de 1 1/2 pulg.","Conexiones de manguera tanto de 1 1/2 pulg. como de 2 1/2 pulg.","Solo conexiones de manguera de 2 1/2 pulg.","Solo una conexión del cuerpo de bomberos, sin válvulas de manguera"], re:"La Clase III combina ambas: 1 1/2 pulg. para uso de los ocupantes/primeros auxilios y 2 1/2 pulg. para uso del cuerpo de bomberos. Sus salidas de 2 1/2 pulg. tienen el mismo requisito de residual de 100 psi que la Clase I. Referencia: clases de sistemas de NFPA 14."},
  {id:439, q:"Para un sistema Clase I, el caudal mínimo para el tubo vertical hidráulicamente más remoto es:", opts:["250 gpm","750 gpm","500 gpm","1,000 gpm"], re:"NFPA 14 requiere 500 gpm para el tubo vertical hidráulicamente más remoto (las dos salidas de 2 1/2 pulg. más remotas a 250 gpm cada una). Referencia: requisitos de caudal Clase I de NFPA 14."},
  {id:440, q:"Después del primer tubo vertical (el más remoto), cada tubo vertical adicional en un sistema Clase I añade cuánto al caudal requerido?", opts:["100 gpm cada uno","500 gpm cada uno","Ningún caudal adicional","250 gpm cada uno"], re:"NFPA 14 añade 250 gpm por cada tubo vertical adicional más allá del más remoto, hasta el máximo del sistema. Referencia: requisitos de caudal Clase I de NFPA 14."},
  {id:441, q:"El caudal total máximo requerido para un sistema de tubo vertical Clase I en un edificio totalmente protegido por un sistema de rociadores NFPA 13 se limita a:", opts:["1,000 gpm","500 gpm","750 gpm","1,250 gpm"], re:"NFPA 14 limita la demanda Clase I a 1,000 gpm para edificios rociados en su totalidad según NFPA 13, y 1,250 gpm donde no están totalmente rociados. Referencia: demanda máxima de caudal de NFPA 14."},
  {id:442, q:"El caudal total máximo requerido para un sistema de tubo vertical Clase I en un edificio que NO está totalmente rociado es:", opts:["750 gpm","1,250 gpm","1,000 gpm","1,500 gpm"], re:"Para edificios no protegidos en su totalidad por rociadores NFPA 13, NFPA 14 limita la demanda Clase I a 1,250 gpm. Referencia: demanda máxima de caudal de NFPA 14."},
  {id:443, q:"NFPA 14 limita la presión estática o residual máxima en una conexión de manguera a 175 psi (para salidas de 2 1/2 pulg.); por encima de este valor el diseño debe proporcionar:", opts:["Un diámetro de tubo vertical mayor","Una segunda conexión del cuerpo de bomberos","Un dispositivo reductor o restrictor de presión en la válvula de manguera","Una bomba jockey adicional"], re:"Donde la presión en una conexión de manguera de 2 1/2 pulg. excede 175 psi, NFPA 14 requiere un dispositivo regulador de presión (reductor/restrictor) aprobado para proteger a los bomberos y la manguera. Referencia: regulación de presión de NFPA 14."},
  {id:444, q:"En un sistema Clase I, las conexiones de manguera en las escaleras de salida se ubican:", opts:["Solo en la parte superior del edificio","Solo en el vestíbulo","Solo en la conexión del cuerpo de bomberos","En el descanso del piso principal de cada escalera de salida"], re:"NFPA 14 requiere conexiones Clase I de 2 1/2 pulg. en el descanso del piso principal en las escaleras de salida (con ubicaciones adicionales como salidas horizontales y pasajes de salida). Referencia: ubicación de conexiones de manguera de NFPA 14."},
  {id:445, q:"Un sistema de tubo vertical 'automático' difiere de un sistema de tubo vertical 'manual' en que un sistema automático:", opts:["Está conectado a un suministro de agua capaz de satisfacer la demanda sin bombeo del cuerpo de bomberos","No tiene conexión del cuerpo de bomberos","Usa solo manguera de 1 1/2 pulg.","No puede calcularse hidráulicamente"], re:"Un tubo vertical automático está conectado a un suministro de agua (p. ej., red de la ciudad o bomba contra incendios) que satisface la demanda del sistema en todo momento; un sistema manual depende de que el cuerpo de bomberos bombee en la FDC para suministrar presión/flujo. Referencia: tipos de sistemas de NFPA 14."},
  {id:446, q:"Un sistema combinado (combinación) de rociadores/tubo vertical es uno en el cual:", opts:["Dos montantes separados sirven a los rociadores y tubos verticales de forma independiente","Un solo montante suministra tanto al sistema de rociadores como a las conexiones de manguera de 2 1/2 pulg.","Solo se proporciona manguera Clase II","No se instalan rociadores"], re:"Un sistema combinado usa un solo montante para servir tanto a los rociadores automáticos como a las conexiones de manguera del tubo vertical; el diseño debe satisfacer ambas demandas. Referencia: sistemas combinados de NFPA 14."},
  {id:447, q:"La conexión del cuerpo de bomberos (FDC) para un sistema de tubo vertical debe dimensionarse con al menos cuántas entradas de 2 1/2 pulg. por cada 250 gpm de demanda del tubo vertical?", opts:["Dos entradas por 250 gpm","Una entrada por 1,000 gpm","Una entrada por 250 gpm","Ninguna relación con la demanda"], re:"NFPA 14 requiere que la FDC proporcione una entrada de 2 1/2 pulg. por cada 250 gpm de la demanda requerida del sistema de tubo vertical. Referencia: conexiones del cuerpo de bomberos de NFPA 14."},
  {id:448, q:"En un edificio alto, cuando la presión hidrostática en las conexiones de manguera inferiores excedería los límites permisibles, el sistema de tubo vertical comúnmente se:", opts:["Reduce solo a Clase II","Convierte a un sistema seco manual","Limita a 50 gpm por salida","Divide en zonas de presión separadas (con montantes separados y/o PRV)"], re:"El exceso de presión en edificios altos se controla dividiendo el tubo vertical en zonas de presión servidas por montantes separados, o aplicando válvulas reguladoras de presión, manteniendo las presiones de salida dentro de los límites. Referencia: práctica de gran altura/zonificación de NFPA 14."},
  {id:449, q:"Para dimensionar tubos verticales (montantes), NFPA 14 históricamente requería un diámetro nominal mínimo de tubo vertical (montante) de:", opts:["4 pulg.","2 pulg.","3 pulg.","6 pulg."], re:"Los montantes de tubo vertical Clase I y Clase III tienen un tamaño nominal mínimo; para sistemas Clase I/III diseñados hidráulicamente NFPA 14 establece un tamaño mínimo de montante (4 pulg. mínimo fue la base establecida desde hace mucho tiempo para estos sistemas). Referencia: dimensionamiento de montante de NFPA 14."},
  {id:450, q:"Un tubo vertical 'húmedo' versus un tubo vertical 'seco' difiere en que un tubo vertical húmedo:", opts:["Se llena solo cuando el cuerpo de bomberos bombea en él","Contiene agua en la tubería en todo momento","No tiene válvulas de manguera","Se limita al servicio Clase II"], re:"Un tubo vertical húmedo contiene agua en todo momento (típicamente automático), dando disponibilidad inmediata; un tubo vertical seco no contiene agua hasta que se suministra, común en configuraciones sin calefacción o manuales. Referencia: definiciones de tubo vertical húmedo/seco de NFPA 14."},
  {id:451, q:"Las válvulas de manguera en sistemas de tubo vertical Clase I deben ser:", opts:["De acoplamiento rápido de 1 pulg.","Solo de 4 pulg.","De 2 1/2 pulg. (con reductor permitido en algunas ocupaciones)","De tipo manguera de jardín roscada"], re:"Las válvulas de manguera Clase I son conexiones de 2 1/2 pulg.; un reductor de 2 1/2 pulg. por 1 1/2 pulg. con tapa puede permitirse en ciertas ocupaciones totalmente rociadas. Referencia: dimensionamiento de conexión de manguera de NFPA 14."},
  {id:452, q:"Los planos de trabajo de NFPA 13 (planos de taller) deben dibujarse a una escala indicada y, entre otros elementos, mostrar:", opts:["Solo la dirección del edificio","Solo el diseño eléctrico","Solo la ubicación del panel de alarma contra incendios","El punto de la brújula (flecha norte), las ubicaciones de los rociadores y los tamaños de tubería"], re:"NFPA 13 requiere que los planos de trabajo a escala muestren el punto norte, la sección transversal de altura completa, los tipos/ubicaciones de rociadores, los tamaños/longitudes de tubería y detalles similares. Referencia: NFPA 13, Planos y Cálculos (planos de trabajo)."},
  {id:453, q:"El paquete de cálculo hidráulico requerido por NFPA 13 debe incluir cuál de los siguientes?", opts:["Una hoja de resumen, hojas de trabajo detalladas y una hoja de gráfico","Solo un único valor de flujo total","Solo el catálogo del fabricante","Solo el permiso de construcción"], re:"NFPA 13 requiere que los cálculos hidráulicos consten de una hoja de resumen, hojas de trabajo detalladas (nodo por nodo) y una hoja de gráfico que trace el suministro versus la demanda. Referencia: formularios de cálculo hidráulico de NFPA 13."},
  {id:454, q:"El 'área de diseño' en un diseño de rociadores por densidad/área representa:", opts:["Toda el área de piso del edificio","El área hidráulicamente más exigente que se supone opera en un incendio","Solo el área directamente bajo el montante","El área cubierta por la conexión del cuerpo de bomberos"], re:"El área de diseño es el área de piso sobre la cual se supone que los rociadores operan simultáneamente (el área hidráulicamente más exigente), usada para calcular la demanda del sistema. Referencia: diseño por densidad/área de NFPA 13."},
  {id:455, q:"Para una ocupación de Riesgo Ligero usando el método de densidad/área, un punto de diseño base comúnmente citado es:", opts:["0.05 gpm/ft^2 sobre 1,000 ft^2","0.20 gpm/ft^2 sobre 1,500 ft^2","0.10 gpm/ft^2 sobre 1,500 ft^2","0.30 gpm/ft^2 sobre 2,500 ft^2"], re:"La base de Riesgo Ligero es aproximadamente 0.10 gpm/ft^2 sobre un área de diseño de 1,500 ft^2 (según las curvas de densidad/área usadas en NFPA 13). Referencia: curvas de densidad/área de NFPA 13 para Riesgo Ligero."},
  {id:456, q:"Para Riesgo Ordinario Grupo 2, un punto de diseño base de densidad/área comúnmente citado es:", opts:["0.10 gpm/ft^2 sobre 1,500 ft^2","0.15 gpm/ft^2 sobre 1,500 ft^2","0.40 gpm/ft^2 sobre 3,000 ft^2","0.20 gpm/ft^2 sobre 1,500 ft^2"], re:"La base de Riesgo Ordinario Grupo 2 es aproximadamente 0.20 gpm/ft^2 sobre 1,500 ft^2; el Grupo 1 es aproximadamente 0.15 gpm/ft^2 sobre 1,500 ft^2. Referencia: curvas de densidad/área de NFPA 13."},
  {id:457, q:"En las curvas de densidad/área, aumentar el ÁREA de diseño asumida generalmente permite que la DENSIDAD requerida:", opts:["Disminuya","Aumente","Permanezca exactamente igual","Se vuelva cero"], re:"Las curvas de densidad/área tienen una pendiente tal que elegir un área de diseño mayor permite una densidad menor (y viceversa); el diseñador selecciona un punto en la curva. Referencia: curvas de diseño por densidad/área de NFPA 13."},
  {id:458, q:"El letrero (placa) de información de diseño hidráulico requerido por NFPA 13 en el montante debe indicar:", opts:["El número de teléfono del propietario del edificio","La densidad de diseño, el área de diseño y el flujo/presión requeridos en la base del montante","La garantía del fabricante de rociadores","La lista de zonas de alarma contra incendios"], re:"NFPA 13 requiere un letrero de información de diseño hidráulico marcado permanentemente que enumere la ubicación del área de diseño, la densidad, la clasificación de ocupación y el flujo y presión requeridos (demanda) en la base del montante, más la asignación de manguera. Referencia: requisitos de identificación/placa de NFPA 13."},
  {id:459, q:"Al dimensionar la tubería por el método de programa de tuberías (donde se permite), el diseñador determina los tamaños de tubería con base en:", opts:["Un cálculo hidráulico en cada nodo","La clasificación de la bomba contra incendios","El número de rociadores servidos por cada tubería y la tabla de clasificación de riesgo","La demanda del tubo vertical"], re:"El método de programa de tuberías asigna tamaños de tubería a partir de tablas basadas en el número de rociadores suministrados y la clase de riesgo; solo se permite para situaciones limitadas de riesgo ligero y ordinario existentes según NFPA 13. Referencia: método de programa de tuberías de NFPA 13."},
  {id:460, q:"NFPA 13 requiere que los cálculos hidráulicos se extiendan hasta:", opts:["Solo el rociador más remoto","Solo la base del montante","La unidad de control de alarma contra incendios","El punto efectivo del suministro de agua donde se conocen las características"], re:"Los cálculos deben extenderse desde el área de diseño hasta el punto efectivo del suministro donde se conocen las características del suministro, de modo que la demanda pueda compararse con el suministro. Referencia: procedimientos de cálculo hidráulico de NFPA 13."},
  {id:461, q:"En una unión hidráulica (donde los flujos se combinan), NFPA 13 requiere que las presiones de las trayectorias convergentes se equilibren dentro de:", opts:["0.5 psi","2 psi","5 psi","10 psi"], re:"En los puntos de unión, las presiones calculadas de las ramas que se fusionan deben equilibrarse dentro de 0.5 psi; la presión más alta gobierna y los flujos se ajustan en consecuencia. Referencia: regla de equilibrio de cálculo hidráulico de NFPA 13."},
  {id:462, q:"Una 'asignación de chorro de manguera' se añade a la demanda de rociadores en los cálculos hidráulicos para tener en cuenta:", opts:["Fugas en la red subterránea","El agua usada por las mangueras del cuerpo de bomberos durante un incendio","El flujo de la bomba jockey","La fricción del preventor de reflujo"], re:"La asignación de chorro de manguera (manguera interior/exterior) se añade en el punto apropiado para reservar flujo para las mangueras de combate manual de incendios que operan simultáneamente con los rociadores. Referencia: asignación de chorro de manguera y tablas de duración del suministro de agua de NFPA 13."},
  {id:463, q:"La duración total del suministro de agua y la asignación de manguera requeridas para una ocupación dada se toman de:", opts:["La placa de identificación de la bomba contra incendios","El letrero de la FDC del tubo vertical","Las tablas de NFPA 13 basadas en la clasificación de riesgo","El programa de cargas del electricista"], re:"NFPA 13 proporciona tablas de la duración mínima de operación (suministro) requerida y la asignación de manguera interior/exterior vinculadas a la clasificación de riesgo usada en el método de densidad/área. Referencia: tablas de requisitos de suministro de agua de NFPA 13."},
  {id:464, q:"En los planos de trabajo, las ELEVACIONES relativas de los rociadores, puntos de unión y puntos de suministro/referencia deben mostrarse porque:", opts:["Afectan solo el diseño estético","Determinan el color de la pintura","Se requieren solo para sistemas secos","Se necesitan para calcular la presión de elevación en los cálculos hidráulicos"], re:"Los datos de elevación se requieren para que el cálculo pueda sumar/restar la presión de elevación (0.433 psi/ft) en cada punto; NFPA 13 requiere las elevaciones relativas en los planos. Referencia: contenido del plano de trabajo de NFPA 13."},
  {id:465, q:"Cuál elemento NO se requiere típicamente como contenido en los planos de trabajo de NFPA 13?", opts:["La nómina detallada del contratista instalador","Las clasificaciones de temperatura y ubicaciones de los rociadores","Los tamaños, longitudes y tipos de accesorios de la tubería","El punto de conexión al suministro de agua"], re:"Los planos de trabajo deben mostrar los tipos/clasificaciones de rociadores, el dimensionamiento de tubería y accesorios, y la conexión de suministro; la nómina del contratista no es un requisito del plano. Referencia: lista de contenido del plano de trabajo de NFPA 13."},
  {id:466, q:"El 'punto de diseño' (rociador más exigente) seleccionado dentro del área de diseño es generalmente el rociador que está:", opts:["Más cerca del montante","Hidráulicamente más remoto (que requiere la mayor presión)","De mayor orificio sin importar la ubicación","En la elevación más baja"], re:"El diseño comienza en el rociador hidráulicamente más remoto/más exigente en el área de diseño y trabaja de vuelta hacia el suministro, asegurando que cada rociador en el área cumpla con la densidad mínima. Referencia: procedimiento de diseño hidráulico de NFPA 13."},
  {id:467, q:"El factor K de un rociador se usa en los cálculos para relacionar:", opts:["El diámetro de la tubería con la longitud","La clasificación de temperatura con el color","El flujo de descarga (Q) con la presión (P) mediante Q = K x sqrt(P)","La elevación con la pérdida por fricción"], re:"La descarga de un rociador es Q = K x sqrt(P), donde K es el coeficiente de descarga listado; convierte la presión calculada en el rociador en un flujo. Referencia: NFPA 13 / características de descarga del rociador."},
  {id:468, q:"La presión mínima de operación para un rociador de aspersión estándar según NFPA 13 generalmente no es menor de:", opts:["3 psi","15 psi","30 psi","7 psi"], re:"NFPA 13 requiere una presión mínima de operación de 7 psi para rociadores de aspersión estándar (algunos rociadores especiales/listados tienen mínimos más altos según su listado). Referencia: presión mínima de operación de NFPA 13."},
  {id:469, q:"En los códigos de protección contra incendios, 'AHJ' significa:", opts:["Autoridad Competente (Authority Having Jurisdiction)","Unión Hidráulica Aprobada (Approved Hydraulic Junction)","Juicio Anual de Riesgo (Annual Hazard Judgment)","Unión Automática de Manguera (Automatic Hose Junction)"], re:"AHJ significa Authority Having Jurisdiction (Autoridad Competente): la organización, oficina o individuo responsable de hacer cumplir los requisitos del código y aprobar equipos, instalaciones y procedimientos. Referencia: definiciones de NFPA (p. ej., NFPA 13/14/20)."},
  {id:470, q:"Antes de comenzar la instalación, NFPA 13 requiere que los planos de trabajo sean:", opts:["Archivados solo después de que el sistema esté instalado","Presentados a la AHJ para revisión y aprobación","Mantenidos confidenciales respecto de la AHJ","Presentados solo al fabricante de rociadores"], re:"NFPA 13 requiere que los planos de trabajo (y cálculos) se presenten a la AHJ y sean aprobados por ella antes de la instalación. Referencia: requisitos de presentación de planos de NFPA 13."},
  {id:471, q:"Si un diseñador desea usar un método o disposición no abordado específicamente por el código, la vía típica es:", opts:["Proceder sin aviso","Ignorar el código por completo","Presentarlo a la AHJ para revisión/aprobación como una equivalencia o medio alternativo","Usarlo solo los fines de semana"], re:"Los códigos permiten materiales/métodos alternativos que la AHJ puede aprobar cuando se demuestra que son equivalentes en calidad, resistencia, seguridad y desempeño. La propuesta se presenta a la AHJ. Referencia: disposiciones de equivalencia de NFPA; códigos modelo de incendio/construcción."},
  {id:472, q:"El término 'listado' en las normas NFPA significa que el equipo o material está:", opts:["Meramente publicitado por un fabricante","Pintado de rojo","Disponible en cualquier ferretería","Incluido en una lista publicada por una organización aceptable para la AHJ que realiza evaluaciones"], re:"'Listado' significa publicado en una lista por una organización (aceptable para la AHJ) dedicada a la evaluación de productos, indicando que el equipo cumple con las normas apropiadas o ha sido probado para un uso especificado. Referencia: definiciones de NFPA."},
  {id:473, q:"El término 'aprobado' tal como se usa en todos los códigos NFPA significa específicamente:", opts:["Aceptable para la Autoridad Competente (Authority Having Jurisdiction)","Aprobado por el fabricante del equipo","Listado solo por Underwriters Laboratories","Permitido por el propietario del edificio"], re:"'Aprobado' se define en los códigos NFPA como aceptable para la Autoridad Competente (Authority Having Jurisdiction). Referencia: definiciones de NFPA (NFPA 13/14/20)."},
  {id:474, q:"Los cálculos hidráulicos presentados con los planos típicamente se requieren que sean:", opts:["Solo manuscritos","Firmados/sellados o preparados por un diseñador calificado y consistentes con los planos de trabajo","Presentados sin los datos de la prueba de suministro","Limitados a una página sin importar el tamaño del sistema"], re:"Los cálculos deben ser preparados por personal calificado, concordar con los planos de trabajo e incluir la información de soporte del suministro de agua; muchas AHJ requieren una certificación del diseñador o sello de PE. Referencia: planos/cálculos de NFPA 13; reglas de presentación de la AHJ."},
  {id:475, q:"Una razón principal por la que la AHJ revisa y aprueba los planos de rociadores contra incendios antes de la construcción es:", opts:["Establecer el precio del contratista","Elegir el color de pintura de la tubería","Verificar que el diseño cumpla con los requisitos aplicables del código antes de que avance el trabajo","Seleccionar el mobiliario del edificio"], re:"La revisión de planos confirma que el diseño propuesto cumple con los códigos/normas adoptados (NFPA 13/14/etc.) antes de la instalación, detectando deficiencias temprano. Referencia: disposiciones de revisión de planos del código modelo de incendio; NFPA 13."},
  {id:476, q:"La 'clasificación de ocupación/riesgo' establecida en los planos es importante para la revisión de la AHJ porque determina:", opts:["La especificación de la pintura","El número de espacios de estacionamiento","La capacidad del ascensor","La densidad de diseño, el área de diseño y la duración del suministro de agua requeridos"], re:"La clasificación de riesgo (Ligero, Ordinario, Extra o almacenamiento) impulsa el punto de diseño por densidad/área y la duración del suministro de agua/asignación de manguera, por lo que la AHJ la verifica cuidadosamente. Referencia: clasificación de ocupación de NFPA 13."},
  {id:477, q:"Qué conjunto de documentos se presenta normalmente para la revisión de planos de rociadores contra incendios?", opts:["Planos de trabajo (de taller), cálculos hidráulicos e información del suministro de agua (prueba de flujo)","Solo un plano de planta","Solo la lista de precios del fabricante","Solo el certificado de ocupación"], re:"Una presentación completa incluye los planos de trabajo/de taller, los cálculos hidráulicos de soporte y los datos del suministro de agua/prueba de flujo usados en el diseño. Referencia: presentación de planos y cálculos de NFPA 13."},
  {id:478, q:"Cuando la edición adoptada de una norma NFPA entra en conflicto con la edición más reciente preferida por un diseñador, el diseño debe cumplir con:", opts:["La edición que prefiera el diseñador","La edición adoptada/aplicada por la AHJ (la jurisdicción)","La edición más antigua jamás publicada","Ninguna edición en absoluto"], re:"La edición legalmente adoptada referenciada por el código de la jurisdicción gobierna; la AHJ aplica esa edición a menos que permita formalmente otra. Referencia: práctica de adopción de código modelo; alcance/AHJ de NFPA."},
  {id:479, q:"Si una condición de campo requiere desviarse de los planos aprobados durante la instalación, la acción correcta es:", opts:["Hacer el cambio en silencio y no documentarlo","Detener todo el trabajo permanentemente","Obtener la aprobación de la revisión (planos revisados) de la AHJ antes o según se requiera","Retirar el sistema de rociadores"], re:"Los cambios respecto de los planos aprobados generalmente requieren planos/aprobación revisados para que el sistema instalado aún cumpla y el registro refleje las condiciones tal como se construyeron. Referencia: práctica de revisión de planos de NFPA 13/AHJ."},
  {id:480, q:"'Deberá' (shall) versus 'debería' (should) en las normas NFPA: la palabra 'deberá' indica un requisito que es:", opts:["Opcional/de asesoramiento","Solo una recomendación","Aplicable solo a sistemas existentes","Obligatorio"], re:"En los documentos NFPA, 'deberá' (shall) indica un requisito obligatorio; 'debería' (should) indica una recomendación o disposición de asesoramiento. Referencia: Manual de Estilo de NFPA; uso de las normas NFPA."},
  {id:481, q:"Una 'prueba de flujo' del suministro de agua presentada con los planos típicamente no debe tener una antigüedad mayor de:", opts:["12 meses (según la práctica común de la AHJ/NFPA 20)","1 mes","5 años","No hay límite de tiempo"], re:"Los datos de la prueba de flujo usados para el diseño comúnmente se requieren que estén dentro de los 12 meses (NFPA 20 requiere dentro de los 12 meses para el dimensionamiento de la bomba); muchas AHJ aplican límites similares a las presentaciones de rociadores para reflejar el suministro actual. Referencia: NFPA 20; práctica de presentación de la AHJ."},
  {id:482, q:"La parte responsable de asegurar que el sistema instalado coincida con los planos APROBADOS es principalmente el:", opts:["Los inquilinos del edificio","El contratista instalador (con verificación de la AHJ en la inspección)","La empresa de agua","El proveedor de mobiliario"], re:"El contratista instalador instala según los planos aprobados y certifica el trabajo; la AHJ verifica el cumplimiento en la inspección/aceptación. Referencia: responsabilidades de instalación/aceptación de NFPA 13."},
  {id:483, q:"Donde un funcionario de construcción adopta el Código Internacional de Incendios o NFPA 1/101, la norma de instalación de rociadores referenciada es generalmente:", opts:["NFPA 70 (Código Eléctrico Nacional)","NFPA 72 (alarma contra incendios)","NFPA 13 (y NFPA 13R/13D para residencial)","NFPA 25 (inspección/prueba)"], re:"La instalación de rociadores se rige por NFPA 13 (con NFPA 13R para residencial de baja altura y 13D para viviendas unifamiliares y bifamiliares); NFPA 25 cubre la ITM y NFPA 72 cubre la alarma contra incendios. Referencia: referencias del código modelo a NFPA 13."},
  {id:484, q:"Una cláusula de 'equivalencia' en una norma NFPA permite que la AHJ acepte una alternativa siempre que ofrezca:", opts:["Un nivel de seguridad menor para ahorrar costos","Instalación más rápida sin importar el desempeño","Solo mejora estética","Calidad, resistencia, resistencia al fuego, eficacia, durabilidad y seguridad equivalentes"], re:"Las disposiciones de equivalencia permiten que la AHJ apruebe materiales/métodos/dispositivos alternativos que demuestren equivalencia en calidad, resistencia, resistencia al fuego, eficacia, durabilidad y seguridad. Referencia: cláusulas de equivalencia de NFPA (p. ej., NFPA 13)."},
  {id:485, q:"La nueva tubería de rociadores sobre el nivel del suelo debe probarse hidrostáticamente a no menos de:", opts:["200 psi durante 2 horas (o 50 psi por encima de la presión de trabajo si esta excede 150 psi)","100 psi durante 1 hora","150 psi durante 30 minutos","300 psi durante 24 horas"], re:"NFPA 13 requiere una prueba hidrostática a 200 psi durante 2 horas, o 50 psi por encima de la presión máxima de trabajo del sistema cuando esa presión excede 150 psi, mantenida durante 2 horas. Referencia: aceptación/prueba hidrostática de NFPA 13."},
  {id:486, q:"Durante la prueba hidrostática de 2 horas de la tubería de rociadores sobre el nivel del suelo, el criterio de aceptación es esencialmente:", opts:["Una caída de 20 psi es aceptable","Sin fugas / sin caída de presión manométrica (sin fugas visibles) durante las 2 horas","Una caída de presión del 50% es aceptable","Cualquier lectura de presión es aceptable"], re:"La prueba pasa solo si no hay fugas visibles ni caída de presión manométrica durante el período de 2 horas (esencialmente pérdida cero). Referencia: criterios de aceptación de prueba hidrostática de NFPA 13."},
  {id:487, q:"El formulario que documenta que un nuevo sistema de rociadores/tubo vertical fue instalado y probado según la norma es el:", opts:["Divulgación de Energía del Edificio","Tarjeta de Garantía del Fabricante","Certificado de Materiales y Pruebas del Contratista","Etiqueta de Inspección del Ascensor"], re:"El Certificado de Materiales y Pruebas del Contratista (para tubería sobre el nivel del suelo y para tubería subterránea) registra los materiales instalados y las pruebas realizadas y se requiere que se complete y firme en la aceptación. Referencia: formularios de certificado de NFPA 13/NFPA 24."},
  {id:488, q:"El Certificado de Materiales y Pruebas del Contratista es completado y firmado por el:", opts:["El corredor de seguros del edificio","El departamento de facturación de la empresa de agua","Solo el arquitecto de registro","El contratista instalador (y firmado para el propietario/AHJ según corresponda)"], re:"El contratista instalador completa y firma el certificado, documentando que el sistema fue instalado y probado de acuerdo con la norma; se entrega al propietario y a la AHJ. Referencia: documentación de aceptación de NFPA 13."},
  {id:489, q:"La tubería de suministro subterránea (NFPA 24) debe LAVARSE antes de la conexión a la tubería sobre el nivel del suelo principalmente para:", opts:["Eliminar escombros, rocas y material extraño que podría obstruir los rociadores","Enfriar la tubería","Añadir cloro para el sabor","Aumentar el factor C permanentemente"], re:"El lavado elimina los escombros de construcción y el material extraño de la red subterránea para que no puedan entrar y obstruir los rociadores o válvulas; los caudales de lavado se especifican por tamaño de tubería. Referencia: requisitos de lavado de NFPA 24; registrado en el certificado subterráneo."},
  {id:490, q:"Las redes subterráneas de servicio contra incendios (NFPA 24) se prueban hidrostáticamente a:", opts:["100 psi o 25 psi por encima de la presión de trabajo","200 psi o 50 psi por encima de la presión máxima de trabajo del sistema (lo que sea mayor), durante 2 horas","300 psi durante 8 horas","No se requiere prueba hidrostática"], re:"NFPA 24 requiere que las redes subterráneas se prueben a 200 psi, o 50 psi por encima de la presión máxima de trabajo del sistema cuando sea mayor, durante 2 horas, con la fuga limitada a la cantidad permisible. Referencia: prueba hidrostática de NFPA 24."},
  {id:491, q:"A diferencia de la tubería de rociadores sobre el nivel del suelo (que esencialmente no permite fugas), la tubería enterrada/subterránea tiene permitida una pequeña cantidad de fuga durante su prueba hidrostática porque:", opts:["La tubería es más débil","La tubería subterránea nunca se prueba","Se hace una concesión para la filtración menor en las juntas de la tubería enterrada, dentro de un límite calculado","La fuga mejora el flujo"], re:"NFPA 24 permite una concesión de fuga limitada y calculada para las juntas subterráneas durante la prueba de 2 horas, mientras que la tubería de rociadores sobre el nivel del suelo no debe mostrar fugas/caída de presión. Referencia: fórmula de fuga permisible de NFPA 24."},
  {id:492, q:"Una 'prueba del drenaje principal' realizada en la aceptación se usa para verificar:", opts:["El nivel de sonido de la alarma contra incendios","El espesor de la pintura","La velocidad del ascensor","Que el suministro de agua no esté obstruido comparando las presiones estática y residual (fluyente)"], re:"Abrir el drenaje principal y comparar la presión estática con la fluyente verifica que las válvulas de control del suministro estén abiertas y que el suministro no esté obstruido; las lecturas se registran y se usan como línea base. Referencia: prueba del drenaje principal de NFPA 13/NFPA 25."},
  {id:493, q:"En la aceptación de una alarma de flujo de agua, el sistema se prueba con flujo para confirmar que la alarma se activa dentro de:", opts:["90 segundos del flujo a la tasa de iniciación de la alarma","10 minutos de flujo","1 hora de flujo","Ningún requisito de tiempo"], re:"Los dispositivos de alarma de flujo de agua deben iniciar una alarma dentro de los 90 segundos del flujo igual o mayor que el flujo del rociador más pequeño; verificado en la aceptación. Referencia: prueba de alarma de flujo de agua de NFPA 13."},
  {id:494, q:"El Certificado de Materiales y Pruebas del Contratista registra cuál de los siguientes?", opts:["Solo los pies cuadrados del edificio","El tipo de sistema, los materiales usados, las presiones/duraciones de prueba, el lavado y los resultados de la prueba de alarma","Solo la dirección de correo electrónico del propietario","Solo el color de la pintura"], re:"El certificado documenta el tipo de sistema, los materiales de tubería/componentes, la presión y duración de la prueba hidrostática, el lavado, las pruebas de alarma/operación y las firmas. Referencia: contenido del certificado de NFPA 13/24."},
  {id:495, q:"Un sistema de rociadores de tubería seca, además de la prueba hidrostática, también requiere una prueba de aceptación para:", opts:["Uniformidad del color","Interfaz del ascensor","Una prueba de fuga de presión de aire (p. ej., no más de una pérdida de presión especificada en 24 horas)","Inflamabilidad de la alfombra"], re:"Los sistemas secos reciben una prueba de aire de baja presión; NFPA 13 limita la pérdida de presión durante 24 horas (comúnmente no más de 1.5 psi de pérdida en 24 horas a una presión de prueba especificada) y verifica el disparo/operación. Referencia: prueba de aire de sistema seco de NFPA 13."},
  {id:496, q:"Los ensambles preventores de reflujo instalados en la línea de servicio contra incendios deben, después de la instalación, ser:", opts:["Pintados de negro","Retirados antes de la aceptación","Dejados sin probar","Probados con flujo directo al flujo de demanda del sistema y el ensamble probado para su correcta operación"], re:"NFPA 13/24 requieren una prueba de flujo directo a través del ensamble preventor de reflujo al flujo de demanda del sistema (para confirmar que no restringe indebidamente el flujo) más la prueba operacional propia del ensamble. Referencia: prueba de flujo directo del preventor de reflujo de NFPA 13/24."},
  {id:497, q:"Para una bomba contra incendios, la prueba de ACEPTACIÓN de campo demuestra que la bomba instalada cumple con su clasificación probando en:", opts:["Churn, 100% del flujo nominal y 150% del flujo nominal, comparado con la curva certificada","Solo churn","Solo flujo nominal","200% del flujo nominal"], re:"La prueba de aceptación de la bomba ejecuta los puntos de churn, 100% y 150% y compara los resultados con la curva certificada de prueba de taller del fabricante para confirmar el desempeño. Referencia: prueba de aceptación de campo de NFPA 20."},
  {id:498, q:"En la aceptación de la bomba contra incendios, el desempeño en cada punto de prueba generalmente debe ser de al menos qué porcentaje de la curva certificada (de taller) / valores de placa?", opts:["50%","95%","75%","140%"], re:"El desempeño de la prueba de campo en cada punto debe ser no menor del 95% de los valores de la curva nominal/certificada (de taller) de la bomba para la aceptación. Referencia: criterios de aceptación de NFPA 20/NFPA 25."},
  {id:499, q:"Qué prueba confirma que un sistema de tubo vertical automático entrega la presión y el flujo requeridos en la salida más remota?", opts:["Una prueba de adherencia de pintura","Una prueba de retorno del ascensor","Una prueba de flujo en la conexión de manguera hidráulicamente más remota","Una prueba de sensibilidad del detector de humo"], re:"Una prueba de flujo del tubo vertical en la salida de 2 1/2 pulg. hidráulicamente más remota verifica que se logre la presión residual requerida (100 psi para Clase I/III) al flujo requerido (500 gpm). Referencia: prueba de flujo de aceptación de NFPA 14."},
  {id:500, q:"El Certificado de Materiales y Pruebas del Contratista completado se entrega finalmente al propietario y se pone a disposición de la AHJ para que pueda servir como:", opts:["Un folleto de marketing","Un sustituto de los planos de trabajo","Un reemplazo de las inspecciones periódicas de NFPA 25","El registro permanente de que el sistema fue instalado y probado de acuerdo con la norma"], re:"El certificado es el registro permanente de aceptación que verifica la instalación conforme y las pruebas exitosas; lo conserva el propietario y se entrega a la AHJ, pero no reemplaza la inspección, prueba y mantenimiento continuos de NFPA 25. Referencia: documentación de aceptación de NFPA 13/24; ITM de NFPA 25."}
];
